-- Poems batch 363
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('d1bb5a89-244c-4263-a589-878c9681b9fe','次閑叟見寄之韻','李彭','宋','宋诗','song-poetry','','[]','王侯氣邁往，青春頗干祿。',156,'全唐诗/poet.song.79000.json','["王侯氣邁往，青春頗干祿。", "任俠似朱家，竄身脱冤獄。", "甘隨支遁遊，不作子公牘。", "着鞭投前地，嗜山性尤酷。", "遺民卧江漢，無心謀半菽。", "數面遂成親，開懷注醽醁。", "新聞倒青箱，讜論尊黄屋。", "禪參靈運前，庭列山陰竹。", "好乖當語離，作惡徒滿腹。", "西風掛席歸，清談渴心足。", "漢庭今側席，公道追黄鵠。", "莫作稻梁謀，營營輩鷄鶩。", "我自宴山川，坐嘯臨長谷。"]'),
('acd381c4-f424-42a0-826a-a095718e995a','次瑛上人韻兼示駒父','李彭','宋','宋诗','song-poetry','','[]','營道烈心期，脱葉危欲霜。',72,'全唐诗/poet.song.79000.json','["營道烈心期，脱葉危欲霜。", "遊子多苦顔，世故定未忘。", "解包祇園下，暎带瑤林旁。", "窈窕寄雲鴈，萬事炊黄粱。", "今君華亭姿，俛啄不得翔。", "相期紬金匱，妙趣詣方將。"]'),
('37a4cc2e-ad30-4b06-9197-7849cec9a8b8','次韻謝吴國器見贈','李彭','宋','宋诗','song-poetry','','[]','眇然詩家流，誰能補其處。',120,'全唐诗/poet.song.79000.json','["眇然詩家流，誰能補其處。", "雋逸追莫還，蕪漫推不去。", "譬彼玉花虬，絕塵須善御。", "越女動鳴機，纖纖工織素。", "吴侯勇於文，鋭氣發眉宇。", "既度驊騮前，邊幅時得覩。", "寧當縛微官，一掾妙三語。", "病夫樗櫟姿，耄及那受斧。", "新詩欲招隱，便自忘勞苦。", "眷言謝心期，願公毋矯舉。"]'),
('7deaee79-1e9e-4239-bf41-b5468817284d','三益齋','李彭','宋','宋诗','song-poetry','','[]','知人實未易，定交良獨難。',216,'全唐诗/poet.song.79000.json','["知人實未易，定交良獨難。", "勝已謝容悦，有來期必端。", "明公邁往姿，勁氣摩諫垣。", "確訒金石貫，博極溟渤寬。", "遺經起凡例，射策凌孔鸞。", "睥睨漢庭右，言激壯士肝。", "恥作子公書，肯彈貢禹冠。", "小試不盡妙，銀章楚江干。", "抱牘鴈鶩行，欲作故時看。", "彈治非柱後，縮手心膽寒。", "何嘗擾獄事，民自以不冤。", "如卿未慚老，此語垂不刊。", "虚懷望三益，閲此賢士關。", "要須得偉人，闊步未登壇。", "拜公丈人行，攝衣許躋攀。", "反蒙補我劓，况復親芝蘭。", "會心在簡要，我言真覺煩。", "章成謝不敏，猥并勞一刪。"]'),
('55d2ba1e-d753-4e24-94b1-57020cfa1326','廬山道中望天池諸寺','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','籃輿造林口，暝色歸暮田。',84,'全唐诗/poet.song.79000.json','["籃輿造林口，暝色歸暮田。", "槁木半搖落，羣峰翠回旋。", "翳翳雲門塔，霏霏祇樹烟。", "夕梵落雲際，微鐘下遙天。", "平時笑傲處，真成觀輞川。", "巖壑事難必，賞心難捨旃。", "還將九節杖，踏月上危顛。"]'),
('e81133c8-b048-4e33-b60c-af5f4238ddb8','遊廬山懷叔粲季敵兼憶小子氓等次謝康樂寄惠連韻','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','諸峰靄遐矚，上與箕斗近。',192,'全唐诗/poet.song.79000.json','["諸峰靄遐矚，上與箕斗近。", "西風吹人衣，蕭然無畦畛。", "煙霞入詩句，欲吐初未忍。", "但恨數往來，幽栖愧真隱。", "真隱如虚舟，渺渺姑乘流。", "何須長卿慢，暮年稱倦游。", "鐘鳴起菌閣，天上隱瓊樓。", "焉能誘松桂，曠懷且少留。", "少留平生歡，看雲復長歎。", "芝蘭念羯末，繭栗惟雍端。", "倚松聊停策，意遠縈層巒。", "風駛烟尚積，雨歇雲猶攅。", "攅雲本無心，孤猿響山陰。", "俯瞰白鹿洞，仰窺紫霄岑。", "何時攜諸少，清盟可重尋。", "仲子日邊去，歸鴉聞暮音。"]'),
('21fbf1ed-a1a7-42ca-bea9-baecb46a99ad','次環中韻兼示蔡安叔','李彭','宋','宋诗','song-poetry','','[]','徵君遂偃蹇，乃復肯見過。',60,'全唐诗/poet.song.79000.json','["徵君遂偃蹇，乃復肯見過。", "清秋雨方闋，斷蜺猶飲河。", "高論到正始，往往操吾戈。", "相期守雌一，功成樂婆娑。", "步出雲雨上，長嘯攜羊何。"]'),
('d84b6612-990f-4811-931c-4cd19d3f21bb','觀諸少移瑞香花詩皆屬意不淺次轉字韻戲之','李彭','宋','宋诗','song-poetry','','[]','託諷本寓辭，語亦要流轉。',48,'全唐诗/poet.song.79000.json','["託諷本寓辭，語亦要流轉。", "歘觀移花作，老眼頓忘倦。", "勿矜風露姿，未入麒麟殿。", "行將顧眄稱，深衷自兹見。"]'),
('0e10063e-6bdd-4872-b819-9448c60e45e8','次韻并示劉四壯輿','李彭','宋','宋诗','song-poetry','','[]','浣衣起筮仕，釣璜辭碧灣。',48,'全唐诗/poet.song.79000.json','["浣衣起筮仕，釣璜辭碧灣。", "朝來玩西峰，聊答馬曹閒。", "寂寥漢庭中，二疏勇自退。", "復有一子雲，茅簷甘炙背。"]'),
('6102c8e5-22a0-4aab-95bf-3f752706038c','絕江遇大風','李彭','宋','宋诗','song-poetry','','[]','江流平兩堤，艇子打雙槳。',48,'全唐诗/poet.song.79000.json','["江流平兩堤，艇子打雙槳。", "西疇閲多稼，北風吹巨浪。", "諸峰忽低昂，飛鳬隨下上。", "欲爲舒嘯期，兹焉廢心賞。"]'),
('20fd0549-312a-4ca7-9de0-c0b6e7d3c455','喜聞繩武元亮有歸期','李彭','宋','宋诗','song-poetry','','[]','行雲無定姿，况復出岫心。',84,'全唐诗/poet.song.79000.json','["行雲無定姿，况復出岫心。", "因風著孤嶼，悵望故山岑。", "遊子在天末，胡爲成滯淫。", "巽坎浩難期，關河阻且深。", "向來一紙書，何啻萬黄金。", "未射漢庭策，不妨梁甫吟。", "孤花春欲盡，裏許要同斟。"]'),
('9306e2e9-b9c6-4066-a9a6-b6d0aa7b83b5','赴鄰舍招','李彭','宋','宋诗','song-poetry','','[]','虚舟縱逸棹，冉冉成老大。',156,'全唐诗/poet.song.79000.json','["虚舟縱逸棹，冉冉成老大。", "隨食蟲寄居，行年螘旋磨。", "來歸修水頭，視地不敢唾。", "俚言亦屢陪，灌畦常往佐。", "毎於休作時，弄筆聊頓挫。", "自謂老於斯，晏然歌楚些。", "年來尤屢空，非關學高卧。", "時節閭里歡，觴豆競繁夥。", "我獨蓬窗底，達曙發清餓。", "賴有竺乾書，開顔真自賀。", "近局可憐人，鷄黍起頹堕。", "整冠禮甚修，坐客仍虚左。", "浩歌爲之傾，樽爲歌長破。"]'),
('12b2d769-a892-4353-a34a-536b042506c6','題蘭亭修禊圖','李彭','宋','宋诗','song-poetry','','[]','商飈吹漢皋，水滿郎官湖。',180,'全唐诗/poet.song.79000.json','["商飈吹漢皋，水滿郎官湖。", "狂策上秋興，拂塵觀畫圖。", "娟然春風面，觴詠聊歡娱。", "中有超絕人，髯髯多髭鬚。", "筆端吐奇胸，紫鳳兼天吴。", "草木方變衰，安得蘭蕙俱。", "生絹如無有，酣放間歌呼。", "可憐謝餘杭，沾醉欹坐隅。", "詩慳遭重劾，罰酒輸行厨。", "遙遙數千里，定交在須臾。", "金谷望塵友，鸞鳥何其愚。", "嗟彼許敬宗，握筆侍玉除。", "將圖來此傳，懸知不相如。", "畫中見勝韻，真欲誅姦諛。", "臨風增想像，候鴈度晴虛。"]'),
('ae343a64-2106-46fc-9f8f-6c4468a5abf8','將遊雲居中途得佛鑑師到日涉簡徑歸','李彭','宋','宋诗','song-poetry','','[]','呼船凌曙江，江空渺黄霧。',72,'全唐诗/poet.song.79000.json','["呼船凌曙江，江空渺黄霧。", "冥冥蜀魄啼，嘖嘖寒雀哺。", "道人大梁來，折簡須晤語。", "爲迴緣雲策，小緩攀天路。", "元因會心期，非關排俗馭。", "青燈耿夜窗，高談雜疏雨。"]'),
('1fe72bb0-f875-4109-b851-7528bc7c2a5e','東湖夜歸賦詩二章呈駒甫師川  其一','李彭','宋','宋诗','song-poetry','','[]','春歸土膏動，草際來和風。',84,'全唐诗/poet.song.79000.json','["春歸土膏動，草際來和風。", "厲厲氣又嚴，晏陰似窮冬。", "崇蘭未含薰，蔽芾蕭艾中。", "仲長久埋照，幽期得無功。", "湖光起遙裔，淑景復冲融。", "連山倒垂碧，落日半規紅。", "不須勞意匠，物色自無窮。"]'),
('00ffa236-0b54-4d4f-8789-8b6b2d1a4550','東湖夜歸賦詩二章呈駒甫師川  其二','李彭','宋','宋诗','song-poetry','','[]','弱齡百不堪，寄傲及壯節。',72,'全唐诗/poet.song.79000.json','["弱齡百不堪，寄傲及壯節。", "從人笑數奇，丘壑藏我拙。", "客夢漳水頭，鄰鷄鳴枯楬。", "荷鉏挾新詩，懷哉清夜月。", "野桃欲着花，幾見堪黍雪。", "當還灌我園，終歲飽葵蕨。"]'),
('d91a1172-8ead-4f55-8d4a-c133b671b3aa','讀西京雜記十三首次淵明讀山海經韻  其一','李彭','宋','宋诗','song-poetry','','[]','南風吹新竹，密密復疏疏。',96,'全唐诗/poet.song.79000.json','["南風吹新竹，密密復疏疏。", "脱冠眠北窗，興不減精廬。", "緬思西京事，聊開稚川書。", "千古納眼界，恍若巾柴車。", "頓忘在墐墉，灌畦蒔佳蔬。", "筆端真有口，妙處天壤俱。", "明如丹青手，百幅生綃圖。", "舉似兒子曹，矜誇還久如。"]'),
('bf890984-6ddf-4a86-9b53-84ac9e5b1081','讀西京雜記十三首次淵明讀山海經韻  其二','李彭','宋','宋诗','song-poetry','','[]','恢恢樂遊苑，遊樂蠲苦顔。',48,'全唐诗/poet.song.79000.json','["恢恢樂遊苑，遊樂蠲苦顔。", "懷風森苯尊，吐花耀流年。", "秣驥無萬里，鋭氣陵天山。", "妙哉苜蓿盤，信矣非虛言。"]'),
('3572346a-7f46-41c9-952e-e3222d42a5fa','讀西京雜記十三首次淵明讀山海經韻  其三','李彭','宋','宋诗','song-poetry','','[]','湛湛太液池，氣接崑崙丘。',48,'全唐诗/poet.song.79000.json','["湛湛太液池，氣接崑崙丘。", "雕葫紫籜輩，茂密誰能儔。", "鳬雛與鴈子，遡波還復流。", "偓佺倚黄鵠，往往乘風游。"]'),
('f5ea1836-9c26-447e-a061-d285b3b8a24e','讀西京雜記十三首次淵明讀山海經韻  其四','李彭','宋','宋诗','song-poetry','','[]','飛燕傾人國，専夜居昭陽。',48,'全唐诗/poet.song.79000.json','["飛燕傾人國，専夜居昭陽。", "當時姊弟貴，坐閲歲月長。", "琉璃作窗扉，金翠粲以光。", "無復聞勤儉，敦朴追文皇。"]'),
('04bb30d1-b045-4f91-8bb7-dcdce0dca6aa','讀西京雜記十三首次淵明讀山海經韻  其五','李彭','宋','宋诗','song-poetry','','[]','彼姝掖庭子，王嬙端可憐。',48,'全唐诗/poet.song.79000.json','["彼姝掖庭子，王嬙端可憐。", "咄嗟毛延壽，媚嫵移遠山。", "一朝聘絕域，艷麗復何言。", "畫工戮幾盡，遺恨抱當年。"]'),
('3e717537-07de-41f5-a19b-ac2931c692dc','讀西京雜記十三首次淵明讀山海經韻  其六','李彭','宋','宋诗','song-poetry','','[]','公孫發蒙耳，猥作支厦木。',48,'全唐诗/poet.song.79000.json','["公孫發蒙耳，猥作支厦木。", "仲舒棄膠西，白駒在空谷。", "脱粟飯故人，安敢望薰沐。", "齊人固多詐，何由調玉燭。"]'),
('2113af6b-5b52-4e31-8c6e-a145fbca2fd6','讀西京雜記十三首次淵明讀山海經韻  其七','李彭','宋','宋诗','song-poetry','','[]','長卿還成都，埋玉崑山陰。',48,'全唐诗/poet.song.79000.json','["長卿還成都，埋玉崑山陰。", "謀醉鷫鸘裘，跫然遯丘林。", "賣醪著犢鼻，滌器揚巴音。", "誰知子虚賦，遽愜武皇心。"]'),
('22aee582-e458-4376-97e7-1a0a864ef240','讀西京雜記十三首次淵明讀山海經韻  其八','李彭','宋','宋诗','song-poetry','','[]','子雲識奇字，辨舌非所長。',48,'全唐诗/poet.song.79000.json','["子雲識奇字，辨舌非所長。", "有宅纔一區，安貧固其常。", "深沉草玄腹，如裹萬里糧。", "苦心夢吐鳳，流傳今未央。"]'),
('def00eda-f774-42ba-a7ec-368b954b2564','讀西京雜記十三首次淵明讀山海經韻  其九','李彭','宋','宋诗','song-poetry','','[]','惠莊長安儒，馳騁盤珠走。',48,'全唐诗/poet.song.79000.json','["惠莊長安儒，馳騁盤珠走。", "廉藺蠒栗犢，五鹿不當負。", "拊心困劇談，此中固多有。", "口舌何足争，虚名千載後。"]'),
('9f6f179d-b021-461c-9a60-b6712f568d8e','讀西京雜記十三首次淵明讀山海經韻  其一○','李彭','宋','宋诗','song-poetry','','[]','淮南學神仙，逸跡窮山海。',48,'全唐诗/poet.song.79000.json','["淮南學神仙，逸跡窮山海。", "著書名鴻烈，精爽凜然在。", "字中挾風霜，反躬忘寡悔。", "空餘褭蹏金，萬世將誰待。"]'),
('d0afd4f8-7b43-4b91-ab92-c870c6183e9a','讀西京雜記十三首次淵明讀山海經韻  其一一','李彭','宋','宋诗','song-poetry','','[]','韓嫣佞幸徒，骩曲承密旨。',48,'全唐诗/poet.song.79000.json','["韓嫣佞幸徒，骩曲承密旨。", "長安有成言，金丸不餓死。", "平生鵔鸃冠，於兹見操履。", "安陵泣前魚，炙手何可恃。"]'),
('46b17a48-4e6e-4f67-97a0-38f58fd92f9d','讀西京雜記十三首次淵明讀山海經韻  其一二','李彭','宋','宋诗','song-poetry','','[]','侍中着貂璫，非無事君志。',48,'全唐诗/poet.song.79000.json','["侍中着貂璫，非無事君志。", "雜用儒家流，仕宦譏不止。", "漢代從行幸，親近固其理。", "何嘗裨衮職，所執玉虎子。"]'),
('cb8a2a87-6549-49ec-825d-ddc7a05ba811','讀西京雜記十三首次淵明讀山海經韻  其一三','李彭','宋','宋诗','song-poetry','','[]','馬遷下蠶室，發憤見良才。',48,'全唐诗/poet.song.79000.json','["馬遷下蠶室，發憤見良才。", "伯夷觀列傳，冥報嗟從來。", "含悲復不遜，安能避嫌猜。", "高文垂箕斗，斯士今悠哉。"]'),
('a8d1763e-4e24-4f23-be48-6713107daba8','讀廬山記懷文若弟','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','茂樹遶茅棟，鳴泉響屋除。',108,'全唐诗/poet.song.79000.json','["茂樹遶茅棟，鳴泉響屋除。", "胸中了無累，泛覽匡山書。", "巖谷在眼界，風烟來座隅。", "時逢幽人語，似與仙者俱。", "昔在宗少文，壁間留畫圖。", "澄神可觀道，卧遊良不疏。", "嗟予何徒役，山腰轉籃輿。", "瞻焉懷靡及，登臨將不殊。", "聊憑西去鳥，殷勤問何如。"]'),
('ed61b04f-a95a-4250-b02a-139f0e133083','陪趙傳道都護飲擬峴臺詩','李彭','宋','宋诗','song-poetry','','[]','平生羊荆州，雅意垂不朽。',132,'全唐诗/poet.song.79000.json','["平生羊荆州，雅意垂不朽。", "登臨發浩歎，望秋怯蒲柳。", "誰知如湛者，自可弊宇宙。", "鄒郎不領略，甘言發諛口。", "奈何千載餘，卜築擬峴首。", "我來勝氣生，排霄峙山斗。", "何暇知許事，谿山攬明秀。", "都護賢王孫，爲具掃愁箒。", "晴嵐變晚靄，霞綺粲高牖。", "如開摩詰畫，妙處落杯酒。", "長嘯徙倚餘，孤鴻沒南岫。"]'),
('ee12c1b5-c075-4ae3-84ce-c63d6d386c35','遂初堂爲伸仲題','李彭','宋','宋诗','song-poetry','','[]','長卿四壁立，寥廓無贏餘。',276,'全唐诗/poet.song.79000.json','["長卿四壁立，寥廓無贏餘。", "子雲英妙姿，有宅纔一區。", "東山文靖公，盛德壓海隅。", "五畝幾不保，翁仲泣遺墟。", "張融貧寄傲，非水船安居。", "是皆知名士，慷慨振古無。", "隻椽與寸梠，乃爾未昜圖。", "頃年黄篾舫，赤壁藏菰蒲。", "尉曹得錢侯，孤柁吞平湖。", "自言家吴會，寧高結精廬。", "挾權彼何人，連茵列鼎徒。", "出奇斯無窮，怡顔享渠渠。", "理世無冤民，屢上黄屋書。", "竟爾完趙璧，幸免攘公羭。", "赤手縛於菟，幾發壯士疽。", "草木初無情，和氣勻噓枯。", "尋盟賀燕雀，聲樂聞鳥烏。", "獲鼎名其年，作亭題遂初。", "如公已克家，得雄必充閭。", "我居日涉園，養疴聊自娱。", "卜築頗清曠，風烟在衣裾。", "問舍經始難，覺公言不誣。", "詩成增想似，疏鐘暝虚徐。"]'),
('309691cd-3869-4d24-a838-8a564a791db9','晨起  其一','李彭','宋','宋诗','song-poetry','','[]','晨起眄庭柯，冲襟澹無營。',48,'全唐诗/poet.song.79000.json','["晨起眄庭柯，冲襟澹無營。", "猶疑夜來暑，幻作秋氣清。", "蒨籬鳥雀語，各自謀其生。", "安能從物役，月落修渚横。"]'),
('c46191bc-50ec-418c-bf67-3ee864311105','晨起  其二','李彭','宋','宋诗','song-poetry','','[]','澹澹故園月，暉暉垂屋星。',48,'全唐诗/poet.song.79000.json','["澹澹故園月，暉暉垂屋星。", "闌夕伴客語，已復過我庭。", "誰爲旋其樞，未覺顧兔靈。", "要知本不動，莫作流轉驚。"]'),
('0d8c104e-d944-479f-9ff9-23ff90591403','宿康王觀','李彭','宋','宋诗','song-poetry','','[]','流水赴大壑，孤雲耿松門。',60,'全唐诗/poet.song.79000.json','["流水赴大壑，孤雲耿松門。", "風幡動林杪，步屧烟景昏。", "矯掌俟幽討，高懷定誰論。", "濁醪有佳趣，溪魚供晚飱。", "無名窗外鳥，催曙武陵原。"]'),
('59804738-080d-4fb4-a67f-a8a3fc1bb1f5','重過康王觀','李彭','宋','宋诗','song-poetry','','[]','憶昔尋遠山，停策康王谷。',84,'全唐诗/poet.song.79000.json','["憶昔尋遠山，停策康王谷。", "烟昏鐘韻微，林茂鳥歸速。", "羽人雖稀少，落日見樵牧。", "徘徊臨清溪，溪魚白於玉。", "並遊幾何人，槁葉下喬木。", "回首十年夢，前塵那可復。", "欲去且少留，殘霞带孤鶩。"]'),
('89521dde-e108-49d8-8456-91332e441fac','醉起','李彭','宋','宋诗','song-poetry','','[]','戀花歇晝眠，汲泉醒午醉。',72,'全唐诗/poet.song.79000.json','["戀花歇晝眠，汲泉醒午醉。", "潛筠雅相攜，侵堦那復避。", "微風過方塘，鬱鬱送荷氣。", "丘園羣卉木，詮品識根柢。", "譬之足穀翁，贏縮在心計。", "借問有何好，是中固多味。"]'),
('c544d684-577a-49aa-8914-4650a14e45fc','豫章通守李侯苦癰痬卧舟中約予相見','李彭','宋','宋诗','song-poetry','','[]','雲斷夜來雨，傍舟渡前溪。',48,'全唐诗/poet.song.79000.json','["雲斷夜來雨，傍舟渡前溪。", "波漲回汀沒，林端遠岫微。", "故人方抱瘵，有約吾忍違。", "夷猶理歸棹，天末放朝暉。"]'),
('e8d1eb11-a00b-4a61-90ea-87e49d814c14','劉越石','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','蒼岑玉峥嶸，寒林深窈窕。',84,'全唐诗/poet.song.79000.json','["蒼岑玉峥嶸，寒林深窈窕。", "石如馬鬛封，其中藏二島。", "匡山嘗款門，煙扉耿相照。", "瑤堦既肪截，侍女亦雲緲。", "兹焉諧所求，蟬蜕出塵表。", "自爾絕問津，日月數過鳥。", "摩挲坐久如，藤蘿歘猿歗。"]'),
('e914c40c-363d-47fc-a125-ce8e0a66032e','寄劉壯輿','李彭','宋','宋诗','song-poetry','','[]','曩者劉中允，懸車未華顛。',264,'全唐诗/poet.song.79000.json','["曩者劉中允，懸車未華顛。", "騎牛澗谷底，終歲飽風烟。", "至今草木間，餘光發幽姸。", "秘書百鍊剛，凜凜森戈鋋。", "勁氣睨汲黯，高文儕史遷。", "當時補衮流，氣燄摩蒼天。", "一語不合意，歸來枕書眠。", "急流勇自退，已度二疏前。", "檢討少壯時，嗜學勘丹鉛。", "微官裹黄綬，雄名敵青錢。", "聊爲三徑資，未减五柳賢。", "薦書到禁闥，信史多官聮。", "仙署得董狐，筆端直如絃。", "季札嬴博垠，歸興何翩翩。", "掉頭不肯住，引帆黄篾船。", "昨來離山東，嗤點羣兒喧。", "一朝掛其冠，謗語無由宣。", "顧我牛馬走，定交良有年。", "相期實高蹈，飲潔鳴風蟬。", "雖無元龍豪，問舍仍求田。", "同採陽崗薇，共酌陰崖泉。", "來往成二老，庶使萬世傳。"]'),
('d601e485-9cd7-4afc-b2f1-718aa9985d70','宿慧日','李彭','宋','宋诗','song-poetry','','[]','幽窗著曙色，匆匆鳥烏啼。',84,'全唐诗/poet.song.79000.json','["幽窗著曙色，匆匆鳥烏啼。", "軫念在遠壑，發軔離苔谿。", "泉聲作好語，挽客來招提。", "老衲道機熟，空洞了無疑。", "霜鐘耿晴空，上有垂露姿。", "暝隨噌吰聲，直與雲漢齊。", "摩挲不及去，行雲會東歸。"]'),
('b000b7c5-3ded-4ca3-b07f-ee753141d148','喜元亮歸','李彭','宋','宋诗','song-poetry','','[]','念君赴修畛，值此春事晏。',84,'全唐诗/poet.song.79000.json','["念君赴修畛，值此春事晏。", "坐窗居人愁，木末遊子遠。", "平時樂羣心，亦起隔津歎。", "南風不解愠，執熱要排遣。", "好鳥噪簷際，冰玉來照眼。", "歲華幾何時，莫遣費牽挽。", "茂椒儻可人，勤來或忘返。"]'),
('dca15af7-3b82-4dc1-8541-92bc86e580e5','修源','李彭','宋','宋诗','song-poetry','','[]','修源寒皎鏡，湛湛有餘地。',108,'全唐诗/poet.song.79000.json','["修源寒皎鏡，湛湛有餘地。", "居然起灘瀨，無復保夷粹。", "人實不易知，出處非細事。", "懸知成小草，何苦辭遠志。", "饑求仁者粟，不用濫乞米。", "清言豈置患，高誼世所韙。", "君看陸平原，華亭思鶴唳。", "季野雖不言，四時氣亦備。", "一飽會有時，幽園動春意。"]'),
('34c3f8de-0960-4c71-a0a9-fb1abada20f1','宿翠巖','李彭','宋','宋诗','song-poetry','','[]','開門望西山，歲月已云積。',48,'全唐诗/poet.song.79000.json','["開門望西山，歲月已云積。", "及兹一登眺，風雨送行役。", "緣雲路崎嶔，憩澗鐘寂歷。", "幽討良獨難，微吟夜寥閴。"]'),
('7078f805-910c-4405-a91e-502503e94587','呼酒告竭不果飲徒飲漿因次淵明述酒韻','李彭','宋','宋诗','song-poetry','','[]','貧賤俯中歲，沒齒甘無聞。',168,'全唐诗/poet.song.79000.json','["貧賤俯中歲，沒齒甘無聞。", "藿食屢清餓，勢與膏粱分。", "斯濫非我事，濁醪餞歸雲。", "槖饘從告竭，不廢抱皇墳。", "嘯歌夜漫漫，曜靈未能晨。", "豈非杜康絕，督郵那復馴。", "壺漿當觥飲，舉白澆余唇。", "飛霜凝暑路，調齊何殷勤。", "不堪餉親串，一笑貽文君。", "悠悠缺陷界，本無蕕與薰。", "亡于天地間，而生經緯文。", "東丘終反魯，仲淹世居汾。", "懷寶何必售，千載猶心親。", "伊優與骯髒，榮衰本同倫。"]'),
('e401116a-f16f-4e99-9ba6-a94af77cc206','小軒前菊花玉雪可念今年忽變鵝黄作詩小話','李彭','宋','宋诗','song-poetry','','[]','幽軒種佳菊，得秋耀素華。',84,'全唐诗/poet.song.79000.json','["幽軒種佳菊，得秋耀素華。", "頗與塵外客，特來當煮茶。", "賞爾貞潔姿，珂雪凈莫加。", "今年日在房，暉暉弄新葩。", "誰令色無主，稍稍作此花。", "長吟復三嗅，亦復長嘆嗟。", "汲泉蒔根本，藍田待瓊芽。"]'),
('d3abed09-e347-4736-bee1-146b91705e59','觀訪戴圖','李彭','宋','宋诗','song-poetry','','[]','閒庭秋草積，滿砌蒼苔深。',84,'全唐诗/poet.song.79000.json','["閒庭秋草積，滿砌蒼苔深。", "忽向冰紈上，聊窺訪戴心。", "雪月俱皎皎，風林互森森。", "縱觀停艫處，猶聞擊汰音。", "終身剡溪曲，何嘗返山陰。", "徒言興已盡，真妄誰能尋。", "浮生同盡爾，慷慨爲長吟。"]'),
('38390f11-47d2-429c-91df-3bd43eddcceb','别何肅之','李彭','宋','宋诗','song-poetry','','[]','吾黨何水曹，明窗飽書傳。',156,'全唐诗/poet.song.79000.json','["吾黨何水曹，明窗飽書傳。", "筆頭夢緗桃，秀句出黄絹。", "胸中萬壑冰，璧月共凝遠。", "未受沈范知，苦乏崔魏見。", "效官三徑資，立節九秋幹。", "隨牒修水濆，未減潘懷縣。", "誰知舞文吏，抱牘進鳬鴈。", "煩苛困疲民，欲作摶沙散。", "談笑罷追胥，老稚無遺患。", "春風吹城隅，花柳俱紛衍。", "胡爲動歸艎，徑去不受挽。", "病夫卧幽園，念離情莫遣。", "營詩持送君，愁雲横絕巘。"]'),
('0f6f832b-7692-470e-9ec8-62cd2cecee7a','遊資聖菴遇明光明祖首座','李彭','宋','宋诗','song-poetry','','[]','久從招提遊，妙趣崖谷逈。',120,'全唐诗/poet.song.79000.json','["久從招提遊，妙趣崖谷逈。", "自謂頗造微，何由昧斯境。", "絳氣靄秋空，白雪屯夜永。", "華屋蔭修椽，皎月浮藻并。", "壞衲逢阿師，苯尊髪垂頂。", "簡默近道要，虚夷發幽省。", "念昨分手初，霜飈虎溪冷。", "及兹再會面，老色藏秀整。", "屬予妄緣息，值子塵事屏。", "循澗意無窮，捫蘿度前嶺。"]'),
('68fb74e5-6766-486e-9f8d-a9c1888a295e','寄雲居微首座','李彭','宋','宋诗','song-poetry','','[]','天星粲以繁，斗杓横復直。',96,'全唐诗/poet.song.79000.json','["天星粲以繁，斗杓横復直。", "其誰移人間，羅列遍阡陌。", "綺紈沸笙竽，觴酌事几席。", "遥憐山阿人，聽鐘夜寥閴。", "孤峰最高寒，陰崖四時雪。", "許分一沠風，濯我朱夏熱。", "江臯春事歸，峰頭猶凛冽。", "報子以迴飈，草木亦欣悅。"]'),
('58d0ae52-6675-4be0-8328-9c8b0a635d91','客有以贋銅香爐見貺者感而賦詩','李彭','宋','宋诗','song-poetry','','[]','巧匠資妙手，斵泥冶金爐。',108,'全唐诗/poet.song.79000.json','["巧匠資妙手，斵泥冶金爐。", "雲雷載皤腹，金石礱慢膚。", "外質荷潤色，中扄嗟厚誣。", "巖巖金博山，水沉與之俱。", "青煙耿朱火，鬱窈凝空虚。", "香色映華觴，噴薄滿座隅。", "謬當二器間，顔泚意不舒。", "如聞厭浮僞，此物無贏餘。", "勿云識真少，爲謀良自疏。"]'),
('321af935-84cc-4cee-a0dd-5b1ed482f9bf','次徐十題承天壁韻','李彭','宋','宋诗','song-poetry','','[]','權門嗟來食，諸郎願操瓢。',84,'全唐诗/poet.song.79000.json','["權門嗟來食，諸郎願操瓢。", "獨有聘君孫，詩裁九牛腰。", "南州翁仲泣，祖風端未遥。", "漢庭給扶人，進隨退晚朝。", "凌煙在何許，潘鏡二毛彫。", "抱瑟懶來齊，啜羮常見堯。", "與子同臭味，何時共儀韶。"]'),
('cfe10e7b-7f72-44f5-b97d-0cf67927871a','雲薌閣爲簡寂賦','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','匡山苦霧裏，衝曉度前溪。',72,'全唐诗/poet.song.79000.json','["匡山苦霧裏，衝曉度前溪。", "定是柴桑老，來尋陸鍊師。", "誰復餐霞客，天籟吹參差。", "泉妥巖崖白，雲生梁棟遲。", "若憶遼東鶴，似聽淮南雞。", "西鄰約惠遠，同採此中薇。"]'),
('eb901073-1df5-406b-be61-4437df1da3fe','雨過清曉登鄰宫鐘閣','李彭','宋','宋诗','song-poetry','','[]','倦夜思重閣，曙登興悠哉。',60,'全唐诗/poet.song.79000.json','["倦夜思重閣，曙登興悠哉。", "殿古木亦老，江闊眼逾開。", "宿雨風前落，幽雲鏡裏來。", "高懷無一欠，客底悲徘徊。", "書空復長嘯，烏雀莫相猜。"]'),
('63147f14-173f-4051-9743-c2562fbe6489','泛舟','李彭','宋','宋诗','song-poetry','','[]','暄風吹天墟，淑景來日涉。',132,'全唐诗/poet.song.79000.json','["暄風吹天墟，淑景來日涉。", "繁花已舒顔，晴哢復緩頰。", "平生萬斛愁，賴此短兵接。", "俯攜諸少年，清江玩舟楫。", "波平罷牽挽，論高闢嚅囁。", "緬懷荀慈明，冰霜胸中挾。", "食貧傍人門，官學居建業。", "向來疥遂痁，性命危脫葉。", "勝遊夙昔共，大句常岌嶪。", "回頭見小雁，頗恨暮山疊。", "何當奮飛去，碧雲端可躡。"]'),
('cc532e2d-17c8-4bfe-9629-a9ac939b15ab','過淵明祠次還舊居韻','李彭','宋','宋诗','song-poetry','','[]','往者金華公，賜環僰道歸。',96,'全唐诗/poet.song.79000.json','["往者金華公，賜環僰道歸。", "筍輿過柴桑，彷徨有餘悲。", "荒庭尚如舊，物色人事非。", "寒風起虚林，木葉無復遺。", "榛叢傲霜菊，詎肯相因依。", "二事墮渺茫，兹理未易推。", "適堪作廢朝，總芳俱不衰。", "當有曠達人，槖金煩一揮。"]'),
('09b8c49e-a859-45d7-b6f1-aa5292f2da2f','北齊校書圖','李彭','宋','宋诗','song-poetry','','[]','嫣然粉面郎，上馬能據鞍。',48,'全唐诗/poet.song.79000.json','["嫣然粉面郎，上馬能據鞍。", "身非行秘書，亦復磨鉛丹。", "六籍火攻餘，渡河惑亥豕。", "毫端雖有神，頗能正朋字。"]'),
('ebbc43a6-556c-4332-8849-62fdd2745191','自寰通巽橋尋幽','李彭','宋','宋诗','song-poetry','','[]','谷鳥唤暝姿，孤鐘生晚聽。',48,'全唐诗/poet.song.79000.json','["谷鳥唤暝姿，孤鐘生晚聽。", "危橋澹忘歸，巖壑耿相映。", "潺湲見機泉，窈窕入雲磴。", "遐矚野寺門，忽盡山陰興。"]'),
('b077b141-7e88-4d75-80d0-dd8529ae1c59','醉中戲贈淳上人','李彭','宋','宋诗','song-poetry','','[]','上人湯休徒，肯顧亦云屢。',48,'全唐诗/poet.song.79000.json','["上人湯休徒，肯顧亦云屢。", "衣上鳯栖雲，辨我林壑雨。", "殊方怨别餘，苦乏碧雲句。", "禪間儻能來，聊用慰衰暮。"]'),
('48cf7a01-708b-4110-9b88-af8ec75ca1a8','到家用環中韻呈玉侯','李彭','宋','宋诗','song-poetry','','[]','客子倦行役，失席高軒過。',60,'全唐诗/poet.song.79000.json','["客子倦行役，失席高軒過。", "胡床語清夜，皎皎天無河。", "勃窣自理窟，何勞觸干戈。", "蘭摧玉久折，蕭艾空婆娑。", "強進忘憂物，無如作病何。"]'),
('154f8551-31de-428c-80ac-b89afa446800','遊仙二首  其一','李彭','宋','宋诗','song-poetry','','[]','昔日漢公昉，畦瓜真人旁。',72,'全唐诗/poet.song.79000.json','["昔日漢公昉，畦瓜真人旁。", "試此塵外姿，持獻分甘芳。", "神丹爲之壽，千里還故鄉。", "劾鼠得被具，妙處固難忘。", "雲生五畝宅，雞犬亦得將。", "應持八瓊文，往醻九霞觴。"]'),
('42168940-4c63-45a8-b2c8-44162bf0caf2','遊仙二首  其二','李彭','宋','宋诗','song-poetry','','[]','江叟冥寂士，邈非芻豢流。',60,'全唐诗/poet.song.79000.json','["江叟冥寂士，邈非芻豢流。", "悠然揚舲去，路窮仍曲謳。", "野笛三美罷，變徵荆卿愁。", "我懷乃昭曠，興寄真滄洲。", "只應清夜鶴，時過緱山頭。"]'),
('b4eeecf3-313b-4828-99b8-1db78a05a31f','夜飲','李彭','宋','宋诗','song-poetry','','[]','公子敬愛客，高會不知疲。',60,'全唐诗/poet.song.79000.json','["公子敬愛客，高會不知疲。", "樽下殷勤勸，只以慰數奇。", "樂憐張女彈，舞倦秦王衣。", "持觴不作難，霑醉倒接䍦。", "客子歌言歸，主稱露未晞。"]'),
('911a70ae-dd63-43d7-b28e-80da0aeb5601','七夕','李彭','宋','宋诗','song-poetry','','[]','兒時聞天孫，今夕聘河鼓。',144,'全唐诗/poet.song.79000.json','["兒時聞天孫，今夕聘河鼓。", "鳴機應暫停，飛鵲橋邊渡。", "藁砧倦服箱，捨策息怨語。", "常時别經年，雪涕作零雨。", "念各非妙齡，無復啼着曙。", "癡兒去蹇拙，芳樽肴核具。", "頗憐柳柳州，文字稍誇詡。", "昔在台省時，模畫秘莫覩。", "奈何吐憤辭，投荒猶未悟。", "性與是身俱，巧拙有常度。", "何能謁以獲，詎有期而去。", "悠悠區中緣，當今愛體素。"]'),
('19de6859-d814-443b-862e-28e630a56142','得六弟書有歸期','李彭','宋','宋诗','song-poetry','','[]','茶鼎起松風，明窗共昏旭。',84,'全唐诗/poet.song.79000.json','["茶鼎起松風，明窗共昏旭。", "孰令著征衣，貧病爲推轂。", "畏途阻且長，况兹加煩促。", "忽傳尺素書，歡喜三過讀。", "蔽芾惡木蔭，前修慎其獨。", "缺月耿孤桐，歸雲赴深谷。", "吾擬誦招隱，殘章留子讀。"]'),
('4169a462-fa0c-4ae2-a240-457bd1516b92','晚登鐘樓即事','李彭','宋','宋诗','song-poetry','','[]','幽棲無熱客，地僻自鳴蛙。',120,'全唐诗/poet.song.79000.json','["幽棲無熱客，地僻自鳴蛙。", "危樓一登眺，晚涼清興賖。", "疏林方寂歷，惡木半槎牙。", "五峰在北户，慰眼落玄花。", "危檣渡洲渚，暮帆收日斜。", "巒崗念徐稚，去及東吳瓜。", "雪山輕幾許，高士正浮楂。", "南州苦牢落，秋鱸寒可义。", "願懷張校尉，莫作賈長沙。", "何繇致叩叩，翠柏故啼鴉。"]'),
('4bf45d3f-ffef-46ca-8811-ca4aa962a10c','夜聽從弟榮緒琴','李彭','宋','宋诗','song-poetry','','[]','凉月耿茂樹，微風薄疏林。',168,'全唐诗/poet.song.79000.json','["凉月耿茂樹，微風薄疏林。", "令弟肯過我，清夜撫鳴琴。", "妙生徽軫外，虚夷有遠心。", "哀猿山暝嘯，凝笳霜霽吟。", "胡馬驚朔吹，楚囚操南音。", "王嬙穹廬泣，校尉漢恩深。", "翻令曠士懷，數行下沾襟。", "曲中頗清壯，攫醳蠲煩淫。", "亞夫軍細柳，令嚴夜沉沉。", "我友擅丘壑，頗遭雞須侵。", "營詩貎烟靄，辭慳負幽尋。", "畫師雖無如，滄浪一蹄涔。", "藉爾山水曲，軒豁窮上岑。", "勤來商略此，勝處要同斟。"]'),
('27ef1106-6e9c-40bb-9ca2-e8c5d97fc0f9','掃除尚書公冡下','李彭','宋','宋诗','song-poetry','','[]','平原令僕射，精銳暢人謀。',96,'全唐诗/poet.song.79000.json','["平原令僕射，精銳暢人謀。", "當時焚諫草，安知即山丘。", "零落三十年，誰其追遠猷。", "只今忠義風，夜夜鳴松楸。", "啼鳥勸行沽，催花生道周。", "遺墟泣翁仲，荒蹊風馬牛。", "非無玉樹郎，抱官在中州。", "悠悠生存子，那得不沉憂。"]'),
('554c3941-fdc7-4c57-b67c-19b3316344b5','讀揚雄法言','李彭','宋','宋诗','song-poetry','','[]','子雲老暗事，晚乃著一書。',96,'全唐诗/poet.song.79000.json','["子雲老暗事，晚乃著一書。", "經營極淺易，艱深聊塈塗。", "終身作雕蟲，出語嗟壯夫。", "苦笑屈原智，頗憐晁錯愚。", "丹青果變玉，美新孰非諛。", "我麟不可覊，投閣將焉如。", "侯芭痛領略，見謂老易徒。", "小兒楊德祖，鑒裁自不虚。"]'),
('46b53113-7118-4f7e-bcdb-5c11a1320d7e','擬古','李彭','宋','宋诗','song-poetry','','[]','彼美如花人，如花復如玉。',156,'全唐诗/poet.song.79000.json','["彼美如花人，如花復如玉。", "嫁作征人妻，别長歡日促。", "拂掠可憐粧，翠袖抱幽獨。", "飛狐驛使斷，交河無寸牘。", "春著鞏梅繁，風吹秦樹綠。", "草生森苯尊，誰能辨薋菉。", "啼裏花成子，愁間笋爲竹。", "雨滴翡翠帷，月上寒蛩褥。", "稍知狹邪遊，能忘窈窕淑。", "新人工參差，故人勤杼軸。", "慆堙爲病媒，經緯有邊幅。", "苦言餉夫君，夫君當熟復。", "告君君不知，我自蓺蘭菊。"]'),
('1d85c36a-3a43-4b30-b74e-b259f6e87fe3','題洪駒父徐師川詩後','李彭','宋','宋诗','song-poetry','','[]','籍甚洪崖孫，高寒欲無敵。',144,'全唐诗/poet.song.79000.json','["籍甚洪崖孫，高寒欲無敵。", "徐郎聘君後，挺挺百夫特。", "堂堂無雙公，户外滿屨迹。", "虎豹雄牙須，儕流甘辟易。", "徐詩到平澹，反自窮艱極。", "周鼎無款識，賞音略岑寂。", "陰何不支梧，少陵頗前席。", "洪語自奇嶮，餘子傷剽賊。", "大似樊紹述，文字各識職。", "二子辨飣餖，鄙夫與下客。", "粢食薦鉶羮，熊蹯雜象白。", "殿最付公議，吾言可以默。"]'),
('57f7ebff-956d-401a-adea-89eb0973b708','醉書','李彭','宋','宋诗','song-poetry','','[]','春風吹草木，苯尊换衰朽。',48,'全唐诗/poet.song.79000.json','["春風吹草木，苯尊换衰朽。", "亦復吹我顔，祇覺成老醜。", "速呼醒酒水，來袪掃愁帚。", "遣客我欲眠，深憐柴桑叟。"]'),
('34150385-a636-4da4-85d0-09f48462d563','以形模婦女笑度量兒童輕爲韻賦十詩  其一','李彭','宋','宋诗','song-poetry','','[]','孟夏樹扶疏，繞屋鬱青青。',48,'全唐诗/poet.song.79000.json','["孟夏樹扶疏，繞屋鬱青青。", "了無俗士駕，嘯歌頗忘形。", "洩雲閟前峰，瀉雨自神屏。", "蔬盂有妙理，未减五侯鯖。"]'),
('509a8963-31c9-46bc-b951-65ad05c11910','以形模婦女笑度量兒童輕爲韻賦十詩  其二','李彭','宋','宋诗','song-poetry','','[]','清晨澹無營，按行瓜芋區。',48,'全唐诗/poet.song.79000.json','["清晨澹無營，按行瓜芋區。", "二雛能拜起，嬰兒千里駒。", "抗顔捋髭鬚，酤酒提胡盧。", "幸非李元禮，何勞爲楷模。"]'),
('669f6a74-dec3-4424-b2ef-997606217b98','以形模婦女笑度量兒童輕爲韻賦十詩  其三','李彭','宋','宋诗','song-poetry','','[]','潛筠穿屋頭，幽草圍舍後。',48,'全唐诗/poet.song.79000.json','["潛筠穿屋頭，幽草圍舍後。", "手攜東臯書，竟熟俱上口。", "詩無擬澄江，文不誇幼婦。", "婆娑丘壑底，藏此牛馬走。"]'),
('e92a7355-8968-471b-86c3-92af34268121','以形模婦女笑度量兒童輕爲韻賦十詩  其四','李彭','宋','宋诗','song-poetry','','[]','丈夫志四海，摶風類鵬舉。',48,'全唐诗/poet.song.79000.json','["丈夫志四海，摶風類鵬舉。", "方其未遇時，潔身閨中女。", "晝伏夜動者，貪冒如倉鼠。", "炯炯抱名誼，所慎在出處。"]'),
('abaca80b-6780-4403-adea-739edea80d67','以形模婦女笑度量兒童輕爲韻賦十詩  其五','李彭','宋','宋诗','song-poetry','','[]','我有百衲琴，巴渝不同調。',48,'全唐诗/poet.song.79000.json','["我有百衲琴，巴渝不同調。", "三疊太古音，那免世驚笑。", "彼哉遇嗾徒，睥睨追風驃。", "幼輿雖折齒，初不妨吟歗。"]'),
('596f8a76-64fd-4750-8314-e73d02b6e440','以形模婦女笑度量兒童輕爲韻賦十詩  其六','李彭','宋','宋诗','song-poetry','','[]','謝公東山時，徹侯等塵霧。',48,'全唐诗/poet.song.79000.json','["謝公東山時，徹侯等塵霧。", "一朝畏桓温，攝衣忘雅素。", "忽著進賢冠，頓失滄州趣。", "勇退真難忘，天末横雲度。"]'),
('3a173f73-f0f6-4a1d-867d-03ea0446e7cf','以形模婦女笑度量兒童輕爲韻賦十詩  其七','李彭','宋','宋诗','song-poetry','','[]','昔者温簡輿，王屋頗清曠。',48,'全唐诗/poet.song.79000.json','["昔者温簡輿，王屋頗清曠。", "建封禮爲羅，非復無度量。", "落膽劾權臣，籠街速官謗。", "輿棧胡不歸，猿鶴儼惆悵。"]'),
('a8058253-103f-46c9-989d-4ef625aed14e','以形模婦女笑度量兒童輕爲韻賦十詩  其八','李彭','宋','宋诗','song-poetry','','[]','少室拾遺公，許身潁與箕。',48,'全唐诗/poet.song.79000.json','["少室拾遺公，許身潁與箕。", "韓侯爲作牙，俯交軒冕兒。", "獻策盪淮寇，犯顔立丹墀。", "未免誘松桂，應遭北山移。"]'),
('1a358b44-2a53-475e-b8f6-047cd427b72f','以形模婦女笑度量兒童輕爲韻賦十詩  其九','李彭','宋','宋诗','song-poetry','','[]','尋壑逐飛鳥，持觴送歸鴻。',48,'全唐诗/poet.song.79000.json','["尋壑逐飛鳥，持觴送歸鴻。", "不解世俗書，稽古何所蒙。", "久矣川效珍，矧兹山不童。", "應容陶隱居，佳眠聽松風。"]'),
('58198a4f-4b74-43a6-9cb7-e3624f55a613','以形模婦女笑度量兒童輕爲韻賦十詩  其一○','李彭','宋','宋诗','song-poetry','','[]','舉世市道交，誰能保榮名。',48,'全唐诗/poet.song.79000.json','["舉世市道交，誰能保榮名。", "譬之多財賈，惡囂安得贏。", "一身拱璧重，萬事秋毫輕。", "向來冥寂士，飄然逐遐征。"]'),
('de5a4eef-6b1d-4ae6-8ea3-d331445aa2b1','七月十九夜有大星殞于西北','李彭','宋','宋诗','song-poetry','','[]','迢迢天漢星，寂寂夜未艾。',84,'全唐诗/poet.song.79000.json','["迢迢天漢星，寂寂夜未艾。", "孰居無事中，差次若璣貝。", "向來西北隅，煒然獨顛沛。", "彼蒼既悠遠，神理滋茫昧。", "豈君坐逐客，無乃勇自退。", "嘒彼亦何爲，竟夕屹相對。", "絡緯啼井欄，和我微吟內。"]'),
('a1aa30b3-1990-4ed9-971f-aa7b706f7399','五月二十四日晨起隔壁聞季敵營詩戲作此嘲之','李彭','宋','宋诗','song-poetry','','[]','阿敵覓新詩，蹤迹真詭秘。',96,'全唐诗/poet.song.79000.json','["阿敵覓新詩，蹤迹真詭秘。", "如偷發關鍵，大懼驚鄰里。", "微吟蟲得秋，幽討蟲搜耳。", "排句歸陣鴻，細字列行蟻。", "詩成膽力壯，巨軸書側釐。", "遠寄賞音人，稍欲見名字。", "但求皇甫序，何暇公榮醴。", "吾言可并案，嘲竟聊自洗。"]'),
('3bd31aee-901f-4bbe-8518-3f0a1f15f981','巢雲亭','李彭','宋','宋诗','song-poetry','','[]','山柳排晴空，羣峰助高寒。',96,'全唐诗/poet.song.79000.json','["山柳排晴空，羣峰助高寒。", "危亭踞上遊，不在世網間。", "曉窗飛鳥度，暮簷餘雨還。", "興多仲宣樓，勢肩天姥山。", "落筆睨前輩，血指空汗顔。", "金華牧羊客，句回造物慳。", "眼界無一欠，辭源溟渤寬。", "會當踐不朽，夜郎今賜環。"]'),
('0bb18061-18af-4673-8a50-6614a4d551c8','芰香亭','李彭','宋','宋诗','song-poetry','','[]','束髪事明主，遇合誠獨難。',144,'全唐诗/poet.song.79000.json','["束髪事明主，遇合誠獨難。", "譬彼佩犢翁，穮蓘功貴完。", "明府真權奇，汗溝沫流丹。", "雅意獨當御，未享苜蓿盤。", "詔許上紫殿，占對隨孔鸞。", "底事寢不報，鼓船下風湍。", "顧兹未逢年，于我頗復安。", "治道貴清凈，稚耋家相歡。", "桁楊生木鷄，榛蕪薙西園。", "方塘毎製芰，澤畔思紉蘭。", "靈修方布席，下詔應賜環。", "勿墮逐臣淚，去躡青雲端。"]'),
('da2fd64a-b85d-4525-b2a1-f2fad75b50d9','凈薌亭','李彭','宋','宋诗','song-poetry','','[]','校讐淇園姿，勁特傲霜雹。',72,'全唐诗/poet.song.79000.json','["校讐淇園姿，勁特傲霜雹。", "論交不滿眼，入社難湊泊。", "賴有此檀欒，嫣然時解籜。", "風枝兼雨葉，調度固不惡。", "結實何離離，開花紛莫莫。", "鳯鳥當來過，歲華今異昨。"]'),
('dd8aa5d3-97d6-4747-8c0d-5da43ecebde9','夜坐食蛤蜊','李彭','宋','宋诗','song-poetry','','[]','紞紞寒鼓鳴，稍稍華月上。',120,'全唐诗/poet.song.79000.json','["紞紞寒鼓鳴，稍稍華月上。", "蒲蓐蔽幽齋，夜鼎驚暗浪。", "但見炰蛤蜊，許事付塵坱。", "獷殻雖外緘，甘腴實天相。", "霜臍貴抱黄，雀醢誇挾纊。", "江瑶初脫柱，蠔山憐疊嶂。", "盤飱得此生，風期特高亮。", "如跨大宛兒，凡馬羞駿駔。", "嗟予鬢成絲，山林真獨往。", "會心不在遠，坐有濠濮想。"]'),
('ad1de6f8-f5e3-4940-a605-b274db8b0d90','敦好軒','李彭','宋','宋诗','song-poetry','','[]','會心誠獨難，托契復何有。',108,'全唐诗/poet.song.79000.json','["會心誠獨難，托契復何有。", "曩哲有遺言，定交于杵臼。", "此風頗淪胥，射利一相就。", "口血寧未乾，轉眄忽賣友。", "夙心何由敦，聊與眷眷偶。", "是中白頭新，嘉德真耐久。", "恍如對華觴，心醉不在酒。", "誓言山若礪，此好那容朽。", "商颷振庭梧，明河掛箕斗。"]'),
('902c9dd4-00f2-4350-a4a6-682913c7c30c','題范贊府覓先春亭','李彭','宋','宋诗','song-poetry','','[]','范叔老不衰，周禮素獨秉。',96,'全唐诗/poet.song.79000.json','["范叔老不衰，周禮素獨秉。", "素標垂青衫，不厭官踪冷。", "抱牘鴈鳬行，色笑辨俄頃。", "園涉寒未餞，和氣君先領。", "霜花吐幽香，煙柳發新穎。", "大鈞無私酬，播物厚兹境。", "仁人所遊居，寒威甘遠屏。", "要當均此施，草木清晝永。"]'),
('8a648b27-ee9e-400e-a2db-ac3bdc5040e4','錢伸仲乞静照軒詩取逸少所謂靜照在忘求云','李彭','宋','宋诗','song-poetry','','[]','往者多逸想，山陰時見之。',192,'全唐诗/poet.song.79000.json','["往者多逸想，山陰時見之。", "肯持圭組面，自塵丘壑姿。", "奇偉不少貸，確訒無纖遺。", "保全勝東山，出語曾未思。", "巢許逢稷契，何由致于斯。", "乃比石衛尉，此老端不爲。", "觀其誓墓作，豈復隨家雞。", "忘求在静照，定體發光輝。", "誰料百代下，領此無言師。", "元非折腰具，聊復尉河西。", "開軒延勝氣，不許賸客隨。", "凛然廉藺風，坐用談笑追。", "懸知杜武庫，時與河陽期。", "持觴望天末，雲樹相參差。", "直恐永和日，未能相盛衰。", "徑煩畫幽處，公莫惜鵝溪。"]'),
('fc6a6693-8f4c-4386-aba7-7c930c59350e','阻風濤湓浦捨舟由山北以歸','李彭','宋','宋诗','song-poetry','','[]','自發郎官湖，掛席如江練。',48,'全唐诗/poet.song.79000.json','["自發郎官湖，掛席如江練。", "繫舟潯陽郭，風濤中夜變。", "攜孥坐菰蒲，驚歎雜鳬鴈。", "明當度山椒，聊寬故園眼。"]'),
('217cf3fd-b8af-474d-8c2d-346e525f1c3b','諸人絕江遊同安大風濤作予適病眩不能渡','李彭','宋','宋诗','song-poetry','','[]','平生湖海心，舟檝雅所便。',96,'全唐诗/poet.song.79000.json','["平生湖海心，舟檝雅所便。", "揚舲欲尋山，風濤怒掀掀。", "中途得眩疾，跨馬如乘船。", "誰能于此時，絕江歌叩舷。", "寧費賞心晤，歸作甕牖眠。", "壯哉二三子，嗤點懦不前。", "顧慚謝公嘯，幸免季野憐。", "延目望斜照，歸路山蒼然。"]'),
('2666020f-82b2-45a7-bfb4-635933f248bd','用陳觀韻寄廣心敦詩兼示陳  其一','李彭','宋','宋诗','song-poetry','','[]','卧疴春带賖，抱獨眉宇皺。',60,'全唐诗/poet.song.79000.json','["卧疴春带賖，抱獨眉宇皺。", "歘懷北阮貧，既親亦有舊。", "歸歟渺前期，騎氣勞侍後。", "暄風攬客衣，勝處當宿留。", "遣我次公嘲，知君杜陵瘦。"]'),
('0aa2d0a3-8ca0-475b-b263-d92d340c21bd','用陳觀韻寄廣心敦詩兼示陳  其二','李彭','宋','宋诗','song-poetry','','[]','陳侯探禹穴，辭源何浩浩。',60,'全唐诗/poet.song.79000.json','["陳侯探禹穴，辭源何浩浩。", "佳處似陰鏗，丘里得名早。", "吾家習主簿，筆頭妙揮掃。", "花繁漢署香，春事隨花鳥。", "快裁兩牛腰，何代無賀老。"]'),
('6a4cf3b7-79a9-4b5c-b8fd-6fa1738f1562','四月十八日過師賢留飲歸用前韻寄師賢','李彭','宋','宋诗','song-poetry','','[]','避俗非避世，擇交欣擇鄉。',108,'全唐诗/poet.song.79000.json','["避俗非避世，擇交欣擇鄉。", "共泛忘憂物，聽雨對胡床。", "江湖繫舴艋，夜窗燈火涼。", "論詩中鳴鏑，辭源注方塘。", "韋杜骨已朽，誰焚更生香。", "我纔肩培塿，君自粲氐房。", "玉人能曉此，藻繪已埋藏。", "破涕欲爲笑，横膺復怏怏。", "行矣勿復道，孽孤政爲祥。"]'),
('ae43018e-28eb-4c49-a142-c8b56446071c','離雲居道中偶成寄微先馳恭首座','李彭','宋','宋诗','song-poetry','','[]','久樂巖中趣，未覺身世拙。',108,'全唐诗/poet.song.79000.json','["久樂巖中趣，未覺身世拙。", "冬暖愁雲開，歲晏塵事歇。", "山靈招我遊，草木亦欣悅。", "黄松少穉羔，蒼崖對宿雪。", "山川誰斷取，擎在仇池穴。", "恭公雨花手，微公傲霜節。", "唤起隨粥魚，談餘餞山月。", "兩禪過虎溪，一笑頗清絕。", "歸來武陵春，欲向幽人說。"]'),
('979c1353-b43e-44ec-bdef-ce3fd8ffda3b','寄微先馳','李彭','宋','宋诗','song-poetry','','[]','雲横暮鐘微，窗含遠山曙。',48,'全唐诗/poet.song.79000.json','["雲横暮鐘微，窗含遠山曙。", "卷祴正佳眠，候鴈送寒暑。", "觀君弄泉手，豈是縫裳具。", "獨鳥不西南，長懷天際樹。"]'),
('f153e824-cb57-4a76-bcf3-d6358a5b528c','寄徐聖功','李彭','宋','宋诗','song-poetry','','[]','暄風緣隙來，窈窕過我廬。',72,'全唐诗/poet.song.79000.json','["暄風緣隙來，窈窕過我廬。", "新花已集目，弱柳復藏烏。", "故人怪音素，定知中密疏。", "客從西縣來，問訊聊可娛。", "幽窗含暝色，亮月麗高隅。", "意逐前雲去，微鐘尚虚徐。"]'),
('b6d2d117-0083-4b11-a807-900cec9d0438','以酒渴愛江清爲韻寄秦廿四  其一','李彭','宋','宋诗','song-poetry','','[]','春風草際歸，爾客向杯酒。',48,'全唐诗/poet.song.79000.json','["春風草際歸，爾客向杯酒。", "觀化發珍藏，俱爲鄙夫有。", "雖無雅頌姿，櫜之維楊柳。", "賞春良獨難，深憐魯中叟。"]'),
('8058ad12-6d6e-4296-959d-1d1281b5fc84','以酒渴愛江清爲韻寄秦廿四  其二','李彭','宋','宋诗','song-poetry','','[]','倦遊文園令，病肺塵消渴。',48,'全唐诗/poet.song.79000.json','["倦遊文園令，病肺塵消渴。", "句斡造化機，雲霞互轇轕。", "慢世誰與儔，嗤議從夸奪。", "誠哉死諸葛，能走生仲達。"]'),
('247276e4-8054-4a1c-aa6b-8c88367fbd74','以酒渴愛江清爲韻寄秦廿四  其三','李彭','宋','宋诗','song-poetry','','[]','通籍金閨人，物望侔鼎鼐。',48,'全唐诗/poet.song.79000.json','["通籍金閨人，物望侔鼎鼐。", "醉卧古藤陰，一往無復再。", "卒業有劉歆，學富仍多愛。", "定持柯亭竹，遡日吹丹塞。"]'),
('38f9c0d9-f08c-4c83-a64d-2c209d0e6cd0','以酒渴愛江清爲韻寄秦廿四  其四','李彭','宋','宋诗','song-poetry','','[]','玄暉擅江左，遠岫列雲窗。',48,'全唐诗/poet.song.79000.json','["玄暉擅江左，遠岫列雲窗。", "佳句神其吐，律身未敦龐。", "胡爲犯奇禍，雙流带二江。", "將智嗟耄及，懷寶聽迷邦。"]'),
('8fd604ce-f6f4-494d-8469-87a33252c39e','以酒渴愛江清爲韻寄秦廿四  其五','李彭','宋','宋诗','song-poetry','','[]','隋河苦黄濁，不亂長淮清。',48,'全唐诗/poet.song.79000.json','["隋河苦黄濁，不亂長淮清。", "秦郎久埋照，餘子祇平平。", "詞林得此士，隱若楚方城。", "風流不頓盡，驚人聞一鳴。"]'),
('5b54014a-31fe-4964-b225-a105eb0f16b7','用韻寄潘仲達','李彭','宋','宋诗','song-poetry','','[]','淵明解真意，欲辨斯忘言。',96,'全唐诗/poet.song.79000.json','["淵明解真意，欲辨斯忘言。", "我亦厭苦相，頗復參鷄園。", "潘侯隱于酒，早悟逍遥篇。", "兩髯俱似戟，空洞復昭然。", "不作逐貧賦，共結貧中緣。", "臨江弔公瑾，登樓懷仲宣。", "何須畫麟閣，從渠定天山。", "君看持漢節，白首自丁年。"]'),
('638dcb80-c409-4455-a2fa-2ae35814b88c','寄甘露滅','李彭','宋','宋诗','song-poetry','','[]','疵賤楚江濆，真遭女嬃罵。',120,'全唐诗/poet.song.79000.json','["疵賤楚江濆，真遭女嬃罵。", "自無交吕心，從猜追信詐。", "頗耽麯米春，寒柯一壺掛。", "戲逃蘇晉禪，時赴拾遺社。", "念我眼中人，十燭九已灺。", "向來支道林，得禍不能嫁。", "解覊蜑霧中，萬事頓高謝。", "奇胸挾風濤，吐句端可怕。", "何時織錦機，緯經聊一借。", "懷哉付短章，參旗耿寒夜。"]'),
('5196d803-16d3-4436-8f6c-8a61cfc1c863','次韻寄錢伸仲','李彭','宋','宋诗','song-poetry','','[]','簡秀歎真長，韶潤思阮裕。',96,'全唐诗/poet.song.79000.json','["簡秀歎真長，韶潤思阮裕。", "眼中人物衰，政爾用金注。", "吳産尚父孫，思脫塵中屨。", "嗜學頗驚奇，于我實肺腑。", "高材堪遺補，伐冰非所慕。", "時于鼓吹間，自得鳴鵠句。", "妙語隨霜飈，識我丘園路。", "賞音吾敢辭，當傳太冲賦。"]'),
('7b5e7193-027b-437c-a5a2-4b530d043569','次陶淵明贈羊長史韻寄李翹叟','李彭','宋','宋诗','song-poetry','','[]','遺民百念冷，中歲多囏虞。',144,'全唐诗/poet.song.79000.json','["遺民百念冷，中歲多囏虞。", "不希咸陽價，頓有旁行書。", "李侯妙德望，閒雅亦甚都。", "南郡此名流，聞聲十年逾。", "披雲落星灣，情留厭歸輿。", "只今丘園夢，君與川岑俱。", "胸中書零亂，清言不躊躇。", "曩時僰道囚，風神頗相如。", "此翁蟬蛻去，詞林遂榛蕪。", "迺于羣憂中，孤笑成歡娛。", "冷官類逃禪，未减漢庭疏。", "何時招隱巖，追涼遲望舒。"]'),
('bd797a67-6cad-4baa-9041-8cf4587367f2','還日涉寄吳世良','李彭','宋','宋诗','song-poetry','','[]','白珩藍田生，赤驥渥洼種。',168,'全唐诗/poet.song.79000.json','["白珩藍田生，赤驥渥洼種。", "異産非其源，定自難入用。", "吳侯掌武孫，九鼎家世重。", "筮仕如挽强，妙手一一中。", "抱牘鳬鴈行，嚴憚安得縱。", "捐金購奇書，嗜學有餘勇。", "鄴侯空插架，而子頗成誦。", "昨日章水頭，春風吹客夢。", "開筵置清醴，落月流畫棟。", "念子不負丞，義士色爲動。", "梯山貢楛矢，效珍出銀甕。", "胡爲百僚底，歲月數賓送。", "天邊賞音意，推轂亦云衆。", "他年解組歸，三徑着求仲。"]'),
('6a660068-bda0-405a-9c51-505f76086e84','次九弟遊雲居韻兼簡鄭禹功博士  其一','李彭','宋','宋诗','song-poetry','','[]','幽棲捐衆累，塵事猶抗行。',48,'全唐诗/poet.song.79000.json','["幽棲捐衆累，塵事猶抗行。", "浮湛太古相，却掃何癡生。", "祇園有勝踐，蒼崖無俗情。", "笋輿度絕壑，雷雨下滿盈。"]'),
('d4d1fb9d-7301-4f7b-915e-80f6d83e2d88','次九弟遊雲居韻兼簡鄭禹功博士  其二','李彭','宋','宋诗','song-poetry','','[]','矯首出巖幽，斜日耿煙樹。',48,'全唐诗/poet.song.79000.json','["矯首出巖幽，斜日耿煙樹。", "玄蟬斷續鳴，驚麏縱横去。", "未窮山海迹，兹焉賞心遇。", "絕勝馳康莊，車鮮馬仍怒。"]'),
('bed7e187-f8cc-4f06-86cd-a98063e51904','次九弟遊雲居韻兼簡鄭禹功博士  其三','李彭','宋','宋诗','song-poetry','','[]','博士麟一角，曠世獨秀羣。',48,'全唐诗/poet.song.79000.json','["博士麟一角，曠世獨秀羣。", "胸中藏箕潁，筆端生風雲。", "平視楚倚相，陋矣知三墳。", "佛界飽遊衍，草木俱欣欣。"]'),
('66337d16-a4a4-44f7-b33f-2c5cb441d355','次九弟遊雲居韻兼簡鄭禹功博士  其四','李彭','宋','宋诗','song-poetry','','[]','阿彤荷衣時，迺與此山别。',48,'全唐诗/poet.song.79000.json','["阿彤荷衣時，迺與此山别。", "願言奉巾屨，不復苦炎熱。", "歸來出新詩，老眼聊一閱。", "雖非天姥句，淺凈亦可悅。"]'),
('adb7b66b-0aaa-4e03-af6b-dbc8be491142','次九弟遊雲居韻兼簡鄭禹功博士  其五','李彭','宋','宋诗','song-poetry','','[]','病夫世味薄，野處隨年深。',48,'全唐诗/poet.song.79000.json','["病夫世味薄，野處隨年深。", "以彼有限景，寫我無窮心。", "緬懷太冲語，山水有清音。", "時尋松桂約，勿遣嘲書淫。"]'),
('52ed8c45-bd69-4e06-9224-fe93736a91a7','次韻謝朓直中書省詩寄馮彦爲','李彭','宋','宋诗','song-poetry','','[]','泰階就平夷，風軌肅恢敞。',96,'全唐诗/poet.song.79000.json','["泰階就平夷，風軌肅恢敞。", "內樞方暢謀，吳岫俄矯掌。", "富貴踐危機，紛華嬰世網。", "諸生經濟心，緩带赤霄上。", "黄金買蛾眉，歌臺争暖響。", "未聞舜九官，賣友變俯仰。", "重瞳垂衣裳，閶闔映蕩蕩。", "均勞當賜環，看公被嘉賞。"]'),
('916ee5b3-1b70-4b92-b67f-e4363089944e','次韻謝朓京路夜發寄六弟書因以督其歸','李彭','宋','宋诗','song-poetry','','[]','問津實知津，阮屐穿幾兩。',84,'全唐诗/poet.song.79000.json','["問津實知津，阮屐穿幾兩。", "束裝徑巑岏，呼船凌泱漭。", "老餘風埃顔，枯槁日日上。", "屏居二十載，寡求毎自廣。", "眷言季行役，清音當見賞。", "聲華慎交綏，物色易摇蕩。", "得雋早歸來，毋爲勤掉鞅。"]'),
('bd1ea260-1d2a-4fe9-8de4-4cf1f9514c87','寄郭循正','李彭','宋','宋诗','song-poetry','','[]','粲粲有道孫，丰姿復亂真。',108,'全唐诗/poet.song.79000.json','["粲粲有道孫，丰姿復亂真。", "養氣如晴虹，照映塞外春。", "好大有餘韻，雨墊烏角巾。", "典學萬人敵，談笑五臺賓。", "篆筆壓秦相，翻笑蔡有鄰。", "長袖果善舞，巨價藏百珍。", "豈繄寂寞中，見此妙入神。", "平生樂聞善，况我骨肉親。", "孟堅贊炎漢，揚雄賦逐貧。"]'),
('d256a0a1-2a7a-4c75-8830-71e348ee4aa0','次謝宣城出新林浦向板橋韻寄汪彦章','李彭','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','名郎摩霄翼，徑逐先賢騖。',72,'全唐诗/poet.song.79000.json','["名郎摩霄翼，徑逐先賢騖。", "奇胸如洞庭，中藏萬烟樹。", "憶昨易前期，寒暑亦云屢。", "雖聮臺省班，未减江湖趣。", "老境専一丘，病著隨所遇。", "何時過我來，嘗柑噀香霧。"]'),
('6fb9927c-ea6b-48be-ad1d-6028cf1caaef','寄陳無感','李彭','宋','宋诗','song-poetry','','[]','憶昔悵有違，平湖拍天漲。',156,'全唐诗/poet.song.79000.json','["憶昔悵有違，平湖拍天漲。", "公乘美滿風，乘興破巨浪。", "我歸茅屋底，念切情惝恍。", "中間忽抱瘵，此病最无妄。", "伏枕辭鳴蟬，秋風吹倚杖。", "緬懷醉夷門，歗咏真愜當。", "頗復持漫刺，曳裾謁丞相。", "曩者金石交，爲子傾家醸。", "膚清神更清，年壯思亦壯。", "蘭臺要給札，抒寫不流宕。", "讜言動主意，湛思慰人望。", "歸帆拂五老，停艫當疊嶂。", "不忘茗果期，烟扉聊一訪。"]'),
('f1056ecb-12af-45f1-ba35-67b651c6fc9f','余與劉壯輿先大父屯田父秘丞爲契家壯輿又與予厚不數年皆下世今過其故居','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','劉郎平昔居，門巷草芊芊。',276,'全唐诗/poet.song.79000.json','["劉郎平昔居，門巷草芊芊。", "念我眼中人，骨驚淚潺湲。", "中允實高蹈，倦遊自丁年。", "問舍得匡廬，卜宅如澗瀍。", "懸車著屋山，騎牛弄寒泉。", "秘書極精銳，筆下走百川。", "口戈擊姦佞，直聲寰宇喧。", "諸郎排候鴈，一一落雲天。", "獨餘漫郎叟，高名星斗聮。", "辟書日夜催，援毫錄羣仙。", "幾負喪明責，掛冠遂言旋。", "中河忽墜月，半岳遽摧巔。", "孤嫠俱幽憤，一仆無復痊。", "傳家惟蔡琰，擇壻得鮑宣。", "驅車官殊方，衡宇頽荒阡。", "壞壁蝸篆滿，小窗蛛網懸。", "翠藹遠山暝，蒼苔修竹連。", "往時所憩樹，相與聽鳴蟬。", "忽逢持斧翁，葆鬢青行纒。", "採薪收斜日，伐竹破疏煙。", "沉痛迫中腸，裴回不能前。", "高明鬼得瞰，豈弟神所捐。", "微吟復凄斷，暮角西風傳。"]'),
('6300c1ef-36b1-4593-9453-6e051f948416','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其一','李彭','宋','宋诗','song-poetry','','[]','剩客苦填委，神交多乖離。',48,'全唐诗/poet.song.79000.json','["剩客苦填委，神交多乖離。", "静言數存沒，驚風邈難追。", "水清石自見，山高鳥鳴悲。", "一盃且相屬，何庸記吾誰。"]'),
('be127360-e1fc-42a9-8d4d-d870c4c77741','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其二','李彭','宋','宋诗','song-poetry','','[]','久矣羌山遊，幽討無復遺。',48,'全唐诗/poet.song.79000.json','["久矣羌山遊，幽討無復遺。", "如觀侏儒節，觸類或可推。", "山靈厚相戲，傲以所不知。", "故放出岫雲，變更無定姿。"]'),
('eace5eeb-da47-49c1-aed5-14aac425fd7e','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其三','李彭','宋','宋诗','song-poetry','','[]','憶昨謝幼輿，宜著丘壑中。',48,'全唐诗/poet.song.79000.json','["憶昨謝幼輿，宜著丘壑中。", "論交麯糵底，愁絕連樽空。", "自我失此士，清夢隨歸鴻。", "封胡與羯末，安知無餘風。"]'),
('03f24b1c-3535-49a4-bfac-8db217358f20','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其四','李彭','宋','宋诗','song-poetry','','[]','高臺擬峴首，孤峰陵天姥。',48,'全唐诗/poet.song.79000.json','["高臺擬峴首，孤峰陵天姥。", "與子各壯年，車鮮馬亦怒。", "歲月忽欺人，于邁不可補。", "詎知唤仍回，藜床同夜雨。"]'),
('c07b5755-898d-4dfc-97e0-7e487bb101a2','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其五','李彭','宋','宋诗','song-poetry','','[]','誰其妙丹青，將軍獨曹霸。',48,'全唐诗/poet.song.79000.json','["誰其妙丹青，將軍獨曹霸。", "能開生面姿，拂絹貎照夜。", "偉哉千載後，萬金不當價。", "吾欲評斯文，善學如善畫。"]'),
('0aaa7c35-6b0c-47b1-a6b0-c958e4176733','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其六','李彭','宋','宋诗','song-poetry','','[]','却老煩青精，度歲掘黄獨。',48,'全唐诗/poet.song.79000.json','["却老煩青精，度歲掘黄獨。", "長乘下澤車，何煩挾丹轂。", "求我盛年非，常恐不可復。", "永結交舊歡，阿謨甘碌碌。"]'),
('192df1b5-8300-43a4-b714-e04c3b34cdfd','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其七','李彭','宋','宋诗','song-poetry','','[]','吾憐阮嗣宗，口不掛臧否。',48,'全唐诗/poet.song.79000.json','["吾憐阮嗣宗，口不掛臧否。", "是眼何親疏，青白生譽毁。", "照鄰殆庶者，穎脫當悟此。", "本心如虚空，何嘗受塵滓。"]'),
('f59f0b9d-f9c2-4017-876b-5f90c508012d','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其八','李彭','宋','宋诗','song-poetry','','[]','曩時太傅公，日下欲無對。',48,'全唐诗/poet.song.79000.json','["曩時太傅公，日下欲無對。", "富貴恐不免，大節在顯晦。", "一朝出東山，勲業到鼎鼐。", "眷言固窮士，難進思易退。"]'),
('128a6339-9ae8-4d91-b064-563e2d0cfc56','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其九','李彭','宋','宋诗','song-poetry','','[]','脂車離郊園，潛筠人許長。',48,'全唐诗/poet.song.79000.json','["脂車離郊園，潛筠人許長。", "歸來十畝陰，縹節已儲霜。", "畦畛日將蕪，况復病在床。", "亭亭望五老，煙雲晚蒼茫。"]'),
('025bd2fc-a85b-4e56-a661-37b862a52cd5','予與謝幼槃董瞿老諸人往在臨川甚昵幼槃已在鬼錄後五年復與瞿老會宿于星渚是夕大風雨因誦蘇州誰知風雨夜復此對床眠之句歸賦十章以寄  其一○','李彭','宋','宋诗','song-poetry','','[]','渚蒲方蒨絢，汀草亦芊緜。',48,'全唐诗/poet.song.79000.json','["渚蒲方蒨絢，汀草亦芊緜。", "扶藜數過鳥，蕩槳看歸船。", "董子有來約，要在秋風前。", "已辦河朔飲，更哦陶令篇。"]'),
('e1433282-842b-4bea-afc6-f77f447d69eb','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其一','李彭','宋','宋诗','song-poetry','','[]','萬壑無定姿，勝處加風烟。',48,'全唐诗/poet.song.79000.json','["萬壑無定姿，勝處加風烟。", "愛山亦尤物，常怵他人先。", "凌厲矯雲翮，酬酢含風蟬。", "終日松路永，冲襟頗蕭然。"]'),
('06bb7490-cdfd-4480-9022-01e8cb0e0e45','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其二','李彭','宋','宋诗','song-poetry','','[]','故人隔秋水，夢往寧可到。',48,'全唐诗/poet.song.79000.json','["故人隔秋水，夢往寧可到。", "山南會心處，不負乾鵲噪。", "胸中如陰雨，百穀仰一膏。", "嘉德向來深，此事神所勞。"]'),
('89d1b14f-e357-400d-a356-763cca9f9f2f','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其三','李彭','宋','宋诗','song-poetry','','[]','明月出東壁，歷井復捫參。',48,'全唐诗/poet.song.79000.json','["明月出東壁，歷井復捫參。", "如我飲歡伯，了無經世心。", "土膏富畦壠，濁醪有常斟。", "鳥語復見廣，浩蕩栖雲林。"]'),
('997af659-9b6e-4371-b5cf-a4988f195aa9','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其四','李彭','宋','宋诗','song-poetry','','[]','遊目霄壤間，禀生不可逾。',48,'全唐诗/poet.song.79000.json','["遊目霄壤間，禀生不可逾。", "企躍有定在，嗜好真殊途。", "超詣方獨往，安然鐘鼎娛。", "嗟彼强聒士，營營竟何如。"]'),
('2d8f9534-f4a2-46c6-bb4f-c13d1003422b','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其五','李彭','宋','宋诗','song-poetry','','[]','老圃志沉鬱，久哉宦悰冷。',48,'全唐诗/poet.song.79000.json','["老圃志沉鬱，久哉宦悰冷。", "道廣雖難周，恬愉境元静。", "著書雪明窗，垂老真雋永。", "諸郎汗血姿，一一皆絕影。"]'),
('cd3634c6-d8ea-4d03-9f94-405f22acdc83','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其六','李彭','宋','宋诗','song-poetry','','[]','窗上飛野馬，酒中鳴山鳥。',48,'全唐诗/poet.song.79000.json','["窗上飛野馬，酒中鳴山鳥。", "俯仰幾何時，秋林風嫋嫋。", "高懷凡情盡，虚齊塵事少。", "卧讀若耶詩，意寄在雲表。"]'),
('6eb69e94-0bfa-4226-a1ff-f003bb1f32af','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其七','李彭','宋','宋诗','song-poetry','','[]','綠髪嗜翰墨，頗徂成章程。',48,'全唐诗/poet.song.79000.json','["綠髪嗜翰墨，頗徂成章程。", "耽思且傍訊，僅有能詩聲。", "老語如凍芋，時時强抽萌。", "公等極英妙，毎聞鸞鳯鳴。"]'),
('4917fb15-2826-4778-892b-98c6d6f10695','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其八','李彭','宋','宋诗','song-poetry','','[]','禹金貢九牧，鑄鼎知神姦。',48,'全唐诗/poet.song.79000.json','["禹金貢九牧，鑄鼎知神姦。", "博學如地負，能發鍵與關。", "奇貨只希價，妙語期藏山。", "要當繼三代，何勞追二班。"]'),
('0c67e572-47b1-4afc-8d2d-c54a22260539','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其九','李彭','宋','宋诗','song-poetry','','[]','豺祭秋事歸，蓐收遂爲政。',48,'全唐诗/poet.song.79000.json','["豺祭秋事歸，蓐收遂爲政。", "爽氣挾曙來，風露頗輝映。", "祛我中夜懶，起予維摩病。", "回首問炎蒸，暴謔子難更。"]'),
('4f1a83e2-329d-4bbe-acc4-c65185a57bf4','喜遇洪仲本于山南以蟬噪林逾静鳥鳴山更幽爲韻作十詩寄之兼呈駒父  其一○','李彭','宋','宋诗','song-poetry','','[]','倚杖覽清曠，江臯事事幽。',48,'全唐诗/poet.song.79000.json','["倚杖覽清曠，江臯事事幽。", "戰勝名義府，策勲逾徹侯。", "世故毎情得，塵緣成語偷。", "長吟撫孤松，濯足清江流。"]'),
('9859ab2f-3b38-4086-ba8a-72315fd38faa','蔡州顔魯公祠','李彭','宋','宋诗','song-poetry','','[]','孤雲亦羣遊，勁柏受遠托。',144,'全唐诗/poet.song.79000.json','["孤雲亦羣遊，勁柏受遠托。", "烈士懷貞心，肯勞常情度。", "堂堂顔太師，立朝獨莊諤。", "太宗柱石衰，中夜懸六博。", "朝廷冠劍人，孤君資元惡。", "公當蔡州鋒，活國立然諾。", "頭顱危一葉，舌本未渠弱。", "恥爲蘇屬國，華顛圖麟閣。", "想當凶焰時，直氣森噴薄。", "廟貌存典刑，社鼓追冥漠。", "我生當昭代，何憾涕横落。", "浩歌招遊魂，白眼瞪寥廓。"]'),
('849d0bea-1fbd-4754-8774-bd0c48e6140c','聽了公孫彈琴','李彭','宋','宋诗','song-poetry','','[]','商飈吹菰蒲，船官雙停槳。',144,'全唐诗/poet.song.79000.json','["商飈吹菰蒲，船官雙停槳。", "中有陳太丘，堂堂道彌廣。", "容我拜牀下，凛然增妙想。", "碧洞名家兒，侍立資開爽。", "取琴爲我彈，襟懷自恢朗。", "蘭芽弄徽絃，巖谷發佳響。", "迺翁琮璧姿，風氣日豪上。", "一言犯台鼎，放逐金波漲。", "郎君翠眉低，沉憂雜悲壯。", "滄海連三山，攫醳共消長。", "生雛有如此，十年違色養。", "推手且罷休，夕嵐横莽蒼。"]'),
('25d014b9-5002-4a26-b788-10b53b53fb15','倦夜','李彭','宋','宋诗','song-poetry','','[]','倦夜苦夜短，追涼卧前楹。',72,'全唐诗/poet.song.79000.json','["倦夜苦夜短，追涼卧前楹。", "清飈颯然至，滓穢開天經。", "月在房心間，木末相將明。", "頻年困秔稌，何足糝藜羮。", "一飽吾可必，呼兒斟醁醽。", "酣歌幾達曙，露下濕流螢。"]'),
('412b907c-32f4-4232-b680-cd2ab2b932bc','雨坐遣心','李彭','宋','宋诗','song-poetry','','[]','孟夏始三氣，暑還自何鄉。',108,'全唐诗/poet.song.79000.json','["孟夏始三氣，暑還自何鄉。", "稍稍切肌骨，病著徑卧床。", "雲從甌峰來，將雨送微涼。", "容與過朝市，殷勤洒林塘。", "幽窗多僧氣，頗带山茶香。", "縹思隨歸雲，冉冉列禪房。", "此物方料理，陰崖容伏藏。", "火老恐愈濁，熏煮猶未央。", "會當牋山靈，時來呵不祥。"]'),
('03588ba4-ee5c-4c2e-92ca-b50c34a59b3f','讀左氏','李彭','宋','宋诗','song-poetry','','[]','麟經書王法，聖筆行天誅。',72,'全唐诗/poet.song.79000.json','["麟經書王法，聖筆行天誅。", "丘明發其藴，磊磊照九隅。", "奈何蠒栗犢，命曰相斫書。", "世不足董狐，殺青議其覆。", "無煩家置喙，粲若夜占斗。", "舌本未暇澆，但自飲醇酎。"]'),
('01156f1b-c5c2-44e2-b6ea-5162fbece430','送嗣行叟住雲巖','李彭','宋','宋诗','song-poetry','','[]','昔在馮光禄，精兵伐莎車。',288,'全唐诗/poet.song.79000.json','["昔在馮光禄，精兵伐莎車。", "大宛獻象龍，權奇天馬駒。", "朝趨不動塵，歷塊暮過都。", "銀鞍香羅帕，晞驥行坦途。", "一朝伏轅下，局趣時長吁。", "霜蹄繞羊腸，翻思在坰娛。", "復聞郭槖駝，種蓺絕代無。", "擢秀土膏動，安恬肆紆餘。", "儕流失妙理，静躁由來殊。", "木性不受觸，剥膚驗榮枯。", "柳侯爲作傳，臨民真楷模。", "嗣公武夷秀，淡然雲水徒。", "風期壓支遁，淵源從老盧。", "膏肓在巖壑，浩浩不可汙。", "屢辭公侯聘，煙霞閟團蒲。", "忽著垢墨衣，俯身蛙黽區。", "我本佛國净，示見穢土居。", "譬之噴玉姿，驤首徑崎嶇。", "雖懷萬里氣，詎可輕艱虞。", "亦如蒔卉木，涵養須敷腴。", "根節藏蠹蝎，安忍不剔除。", "名駒即商鑒，種術毋令疏。", "邾蟊或蜂蠆，三言成於菟。", "願公置坐右，愛之良不誣。"]'),
('f11097cf-d0ef-4d2a-91e9-188997bb3197','次九弟阻雪不得遊雲居','李彭','宋','宋诗','song-poetry','','[]','憶女垂九齡，尋幽非舊常。',96,'全唐诗/poet.song.79000.json','["憶女垂九齡，尋幽非舊常。", "兩鬢忽如棘，歌聲類蒙莊。", "山色故無恙，老者鬚眉蒼。", "載之著車後，誰言山路長。", "毎逢勝絕處，賦詩要難忘。", "大雪渺空曠，清境詎可望。", "燭龍何時來，銜曜發暉光。", "長懷亦云極，煙渚聞鶖鶬。"]'),
('87d60cdb-b1e0-4508-9351-ed05af1a401e','雨後望雲居','李彭','宋','宋诗','song-poetry','','[]','愛山勇成癖，巖壑羅心胸。',72,'全唐诗/poet.song.79000.json','["愛山勇成癖，巖壑羅心胸。", "政使詣幽絕，何如天際逢。", "春雨雲斷續，蔽虧歐岌峰。", "如我金石交，渺然曠音容。", "眼邊出突兀，煙霞更葱蘢。", "方營五字賞，鳥下醉吟中。"]'),
('048641ac-dfca-4cd1-9028-d04ea6943c1f','聞蘇大養直同李子充遊雲居作此詩招之','李彭','宋','宋诗','song-poetry','','[]','人心各如面，石交定難逢。',120,'全唐诗/poet.song.79000.json','["人心各如面，石交定難逢。", "吾觀蘇夫子，真有古人風。", "自開蔣生徑，日望求羊蹤。", "乃攜李長吉，上我歐岌峰。", "羌山落君手，稍欲吞附庸。", "練練峰上雲，蕭蕭巖際松。", "想當岸綸巾，嘯傲驚歸鴻。", "我有浣花竹，隔林聞曙鐘。", "幽禽發佳響，亦足披心胸。", "何當小休轡，一尊聊此同。"]'),
('b7f43bb8-39a5-411b-a1c8-7368f9520d52','再次阿敵韻寄舒大士兼簡微首座  其一','李彭','宋','宋诗','song-poetry','','[]','風窗生晚聽，雨砌耀宵行。',48,'全唐诗/poet.song.79000.json','["風窗生晚聽，雨砌耀宵行。", "斜柯横吹度，緣堦細草生。", "片月懸屋角，嬋娟有餘情。", "世味了無取，虚懷浩難盈。"]'),
('b293985b-7bb1-4377-ab64-448f010c67a8','再次阿敵韻寄舒大士兼簡微首座  其二','李彭','宋','宋诗','song-poetry','','[]','欲念山阿人，臨崖九秋樹。',48,'全唐诗/poet.song.79000.json','["欲念山阿人，臨崖九秋樹。", "袖手謝鼎來，屬袂推不去。", "兀爾自忘緣，湛然隨所遇。", "稱譏洶濤波，渤澥恬喜怒。"]'),
('a7b4f4c5-1570-41a2-abab-6a7255e23b0a','再次阿敵韻寄舒大士兼簡微首座  其三','李彭','宋','宋诗','song-poetry','','[]','我亦樂清曠，頗甘去人羣。',48,'全唐诗/poet.song.79000.json','["我亦樂清曠，頗甘去人羣。", "回觀蔭華軒，澹如秋空雲。", "二桃殺三士，纍纍蕩陰墳。", "吾廬蔽床席，有托衆鳥欣。"]'),
('b1f73036-b444-4207-aa8e-8ce6056e103d','再次阿敵韻寄舒大士兼簡微首座  其四','李彭','宋','宋诗','song-poetry','','[]','室邇會面稀，軔發分首别。',48,'全唐诗/poet.song.79000.json','["室邇會面稀，軔發分首别。", "緬思耐久交，不爲翕翕熱。", "祇夜在貝多，有懷時間閱。", "嚬伸三昩起，燕坐真適悅。"]'),
('2186c850-bfe6-4a7f-84b4-2d88557c60b6','再次阿敵韻寄舒大士兼簡微首座  其五','李彭','宋','宋诗','song-poetry','','[]','吳産微開士，膏肓巖穴深。',48,'全唐诗/poet.song.79000.json','["吳産微開士，膏肓巖穴深。", "向來避小草，于今有遠心。", "懸知軒轅律，定非桑濮音。", "寒藤且高閣，川塗多毒淫。"]'),
('fdbffe54-6bdc-4711-b550-bd5612ddd2ef','端午','李彭','宋','宋诗','song-poetry','','[]','鄭袖椒房寵，音容勝莫愁。',84,'全唐诗/poet.song.79000.json','["鄭袖椒房寵，音容勝莫愁。", "多情上官郎，朝夕侍冕旒。", "從來秋水好，見謂繞指柔。", "何堪女嬃罵，竟與馮夷遊。", "至今荆楚兒，奮舟競長流。", "重華改前度，歸翮起南州。", "莫作古時恨，静聽羣謌謳。"]'),
('aa5eddd3-1c8a-4969-b95e-6dd542cca1a3','北窗睡起有懷吳世南','李彭','宋','宋诗','song-poetry','','[]','曩時謝仁祖，蕭散北牗下。',216,'全唐诗/poet.song.79000.json','["曩時謝仁祖，蕭散北牗下。", "捍撥響鵾絃，天際頗閒暇。", "淵明曲肱卧，餘事眼不掛。", "便欲俯羲皇，凉飈助矜詫。", "縱觀兩郎傳，明如丹青畫。", "獨于避俗翁，英姿猶可借。", "此翁多新詩，天成妙風雅。", "不從人間來，句法殆神化。", "伊予綠髪時，奮舌談王覇。", "中歲懶問津，銳意學耕稼。", "一往二十年，了不畏嘲罵。", "性初嗜清醥，病見杯勺怕。", "徑作雲窗眠，端回俗流駕。", "緬懷吳朝歌，南州滿聲價。", "虎脊天廐姿，未覆香羅帕。", "顧我迺神交，素書毎盈把。", "何時逐飛蓋，西園樂清夜。", "微吟望天末，虚懷聊空寫。"]'),
('f798ea64-fc14-46a6-a7f5-c9e502574fbc','病中有懷','李彭','宋','宋诗','song-poetry','','[]','江城春事還，温風攪清晝。',96,'全唐诗/poet.song.79000.json','["江城春事還，温風攪清晝。", "花藥粲以繁，好鳥俱應候。", "客中維摩病，何心折楊柳。", "黄鸝勸窺園，于我意頗厚。", "緬懷趙明府，傾蓋真若舊。", "翩翩佳公子，弈弈名世胄。", "筆可扛龍文，識足辨虀臼。", "何當與若人，長歗向宇宙。"]'),
('8db5f5e5-d94c-4566-b885-134ea0861f74','有懷張掾師言','李彭','宋','宋诗','song-poetry','','[]','户牖煙霞積，池塘蒲稗深。',84,'全唐诗/poet.song.79000.json','["户牖煙霞積，池塘蒲稗深。", "幽鳥如交友，招唤出疏林。", "懷人隔湓浦，終朝梁父吟。", "别鵠太古澹，徽絃寫瑶琴。", "誰能領斯妙，士貴相知心。", "僧彌非謝守，其誰能賞音。", "深衷若爲寄，長歗看遥岑。"]'),
('edbe6aa5-276e-491a-b948-8b3f49ced3f9','有懷鄭禹功','李彭','宋','宋诗','song-poetry','','[]','吏隱専一壑，才名横九州。',60,'全唐诗/poet.song.79000.json','["吏隱専一壑，才名横九州。", "袖手煙雨外，坐看江漢流。", "斯人美無度，孤標可鎮浮。", "窮居白日静，蒼苔門巷周。", "永懷不可見，臺笠向西疇。"]'),
('732f7ee0-ce3d-4cae-b2d1-25f62e2f2b6d','夜坐懷師川戲效南朝沈炯體','李彭','宋','宋诗','song-poetry','','[]','鼠鏖觸蠻兵，客夢寒窗短。',144,'全唐诗/poet.song.79000.json','["鼠鏖觸蠻兵，客夢寒窗短。", "牛斗挂闌干，起視夜參半。", "虎頭丹青手，欲畫澀回腕。", "兔尖渴陶泓，得句亦不漫。", "龍沙懷石友，羽觴舊無算。", "蛇飛梵王壁，絡繹壯神觀。", "醉踏吳沙歸，轉眄歲月換。", "羊腸自詰曲，馳道方晏晏。", "旋攜古菱花，悟罷如冰泮。", "雞園談妙口，當我一笑粲。", "狗監浪延譽，凌雲非吾願。", "猪蹄祝汙邪，舉世良可歎。"]'),
('78f96331-18e7-454d-af1a-1c3caa3a403a','雪晚望懷子充宗弟','李彭','宋','宋诗','song-poetry','','[]','歸雲度山椒，木末留夕照。',132,'全唐诗/poet.song.79000.json','["歸雲度山椒，木末留夕照。", "聮翩銜尾鴉，不復明楚調。", "安知牛尻沒，便出豐年笑。", "南阮有偉人，領略造意表。", "端憂突不煙，岑寂有餘妙。", "簡遠到安豐，邁往同逸少。", "頗教弟子員，鉛槧發清奥。", "誰可相推轂，僅自免鐫譙。", "閱月不傳音，柴門跡如掃。", "藜床還睡債，癭杯敦夙好。", "爲君短長吟，扶笻送飛鳥。"]'),
('eb8e8f1d-7fed-4aa1-8390-632a60353d86','懷子充復次間字韻','李彭','宋','宋诗','song-poetry','','[]','彌年曠不接，耿耿心未闌。',48,'全唐诗/poet.song.79000.json','["彌年曠不接，耿耿心未闌。", "緣何稅君鞅，飽看江西山。", "追涼故園樹，待月房心間。", "君歸有後約，悵望何時還。"]'),
('ba3e1b10-f2fc-47de-a53c-e83f3cad4464','元亮詩次玉局翁過二李故居韻賞僕作草堂于故園同賦一章','李彭','宋','宋诗','song-poetry','','[]','兄家咸陽公，餘澤被巖麓。',120,'全唐诗/poet.song.79000.json','["兄家咸陽公，餘澤被巖麓。", "怪底多珪璋，藍田自生玉。", "我獨出衰緒，嗜酒仍愛竹。", "晝眠殷晴雷，看雲腰不束。", "作堂延野色，風吹草心綠。", "情間飛鳥親，相呼暝投宿。", "往往遼東鶴，來栖手栽木。", "心期得幽子，浩歌去邊幅。", "抱甕同灌畦，牽蘿來補屋。", "修文不無人，付渠調玉燭。"]'),
('07325f01-554d-49ba-93e0-5490f23559ba','董真人煉丹井','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','董子侯官秀，養真匡山陰。',84,'全唐诗/poet.song.79000.json','["董子侯官秀，養真匡山陰。", "瓊田蓺金糓，絳雪飛瑶林。", "種杏令虎守，償稻見本心。", "淮南雞犬仙，舐鼎昇瑶岑。", "寒泉冽舊井，遺風猶至今。", "我來澡鬚眉，憑虚欲駸駸。", "稅駕不忍去，遂歌梁父吟。"]'),
('aafdd7b1-8a8b-449c-b2c9-29d6642c239d','聽侍其雲叟琴','李彭','宋','宋诗','song-poetry','','[]','君家建鄴城東頭，捲簾卧對長淮流。',128,'全唐诗/poet.song.79000.json','["君家建鄴城東頭，捲簾卧對長淮流。", "除書謗書不到耳，空洞腹中無片愁。", "白浪從高瓦棺閣，清夜無人響猿鶴。", "琴聲時復一挑之，北斗横天月將落。", "御風過我故山岑，一寫太古之清音。", "當春風動爲凄緊，波底時聞龍一吟。", "坐觀人琴成二妙，覺來形穢顔枯槁。", "伯牙袖手意有餘，請公臨流一舒嘯。"]'),
('8a7061e4-16be-4f78-ad2f-210707c344e8','聽程道士琴','李彭','宋','宋诗','song-poetry','','[]','鵾絃鐡撥世多有，玉筝銀甲嗟凡陋。',64,'全唐诗/poet.song.79000.json','["鵾絃鐡撥世多有，玉筝銀甲嗟凡陋。", "平生綠綺醒心泉，凈洗耳根端不朽。", "鍊師霜髭已滿頤，履霜坐彈霜葉飛。", "腐儒凍餒非所惜，物物願荷皇天慈。"]'),
('02dde092-b857-4cd0-9cab-1fbe0be70bbc','演上人以權詩示余歸其卷演師系以長句','李彭','宋','宋诗','song-poetry','','[]','花縣潘郎未白頭，下從玉局仙翁遊。',144,'全唐诗/poet.song.79000.json','["花縣潘郎未白頭，下從玉局仙翁遊。", "平生四海饒次守，脫冠壞衲藏深幽。", "死生俱在天一角，句法不復陰梁州。", "眼明得此道人演，更遣權詩遮世眼。", "唤起蘄春十年夢，恍如神明還舊觀。", "黑柏蒼鷹飽欲飛，天馬銜芻方來漢。", "演翁自是塵外客，筆端秀句應無敵。", "禪餘軋軋弄鳴機，紫鳯天吳亂紅碧。", "會當載月漾舟來，盡出公家金粟尺。"]'),
('9bc5bd2b-6abc-4034-ba60-fc661b91c276','觀吕居仁詩','李彭','宋','宋诗','song-poetry','','[]','西風鏖暑功夫深，老火由來欺稚金。',240,'全唐诗/poet.song.79000.json','["西風鏖暑功夫深，老火由來欺稚金。", "蠻花缺月午夢短，伐翳正爾開遙岑。", "忽看僧珍五字句，妙想寔與神明聚。", "清如明月東澗泉，壯如玄豹南山霧。", "抑揚頓挫百態隨，鷙鳥欲舉風迫之。", "莫言持此黄初詩，直恐竟亦不能奇。", "老懷凜凜受霜氣，想見此郎冰雪姿。", "鄙夫好詩如好色，嫣然一笑可傾國。", "擊節歌之侑歡伯，杯中安得着此客。", "此客不肯紲塵羈，况復世網如蛛絲。", "秋空横河鵰鶚上，不許蜂蝶同所歸。", "漢家太尉死宗社，大鳥泣墳天所借。", "謝傅未吐活國謀，賫恨懷奇赴泉下。", "僧珍向來期此人，頽波砥柱妙入神。", "要當疊些湘水濱，唤起猶足張吾軍。"]'),
('ced7baf9-dcc8-42ed-abaf-8366f7fbf2f6','曉發琳山晚會於湖光亭','李彭','宋','宋诗','song-poetry','','[]','琳山寺前雨翻盆，辟邪渡頭争渡喧。',112,'全唐诗/poet.song.79000.json','["琳山寺前雨翻盆，辟邪渡頭争渡喧。", "湖光主人敬愛客，解装咄嗟開酒樽。", "江城花盡柳亦老，薄暮歡娯憐草草。", "殷勤爲唤兩紅顔，始知人好鳥還好。", "斑斑鬢間少黑絲，客中不復憂心擣。", "阻酒中聖少年時，江湖放浪真忘歸。", "老來頗喪丈夫勇，心隨暝鳥投林飛。"]'),
('f57cd8cb-a03a-4225-b5a7-e0393632615b','謝人見過','李彭','宋','宋诗','song-poetry','','[]','門無褦襶軒車過，草廬寂寂南陽卧。',64,'全唐诗/poet.song.79000.json','["門無褦襶軒車過，草廬寂寂南陽卧。", "夫君掀髯來扣關，不减昔日陳驚座。", "肉食者鄙無遠謀，喜君義氣横霜秋。", "已看獻策尊王室，白筆應須上黑頭。"]'),
('20fa7a52-0fbe-4f03-baa6-1f3fbb02055a','遭風禱神林浦','李彭','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','伐鼓放船落星渚，争曙鳬鴻集儔侣。',160,'全唐诗/poet.song.79000.json','["伐鼓放船落星渚，争曙鳬鴻集儔侣。", "乾旋坤轉風掀掀，陽侯就戮波臣怒。", "廬山孤巘政排空，複閣重樓欲無路。", "水蟲瑣細何足云，竊發凴陵敢予侮。", "長年吞聲三老悲，老妻驚呼稚子啼。", "病軀不能自料理，袖手懸知虀粉期。", "謝公吟嘯吾豈敢，興公悲號差勝之。", "寒葅百甕未渠盡，猶得餘生見昏覲。", "歸帆行將拂五老，要及霜風快雁隼。", "徑須作牋寄魴鱮，行路艱難公莫遽。"]'),
('d9c80ba1-328b-43d7-9e25-eea232760f33','南至日離同安舟中寄阿弓','李彭','宋','宋诗','song-poetry','','[]','去年闌冬亦戒塗，北風吹雪邾城隅。',128,'全唐诗/poet.song.79000.json','["去年闌冬亦戒塗，北風吹雪邾城隅。", "八字山頭駕高浪，曙角更聽吹單于。", "今年南至又行役，蕭寺佛香僧飲俱。", "身在瀟湘黄蔑舫，眼看惠崇歸雁圖。", "緬懷吾家之季子，細酌明窗愁欲無。", "詩腸定遭酒媒孽，語作曉霜催槁梧。", "漫將長句代作草，河凍難求雙鯉魚。", "歸期不落蜡賓後，行李困來頻寄書。"]'),
('cbd2aacc-4e51-4500-9539-dcd80723fe9d','夜宿寶巖寄寇李二鍊師兼懷王環中','李彭','宋','宋诗','song-poetry','','[]','北風驅雲度危嶠，日下蒼茫煙靄横。',208,'全唐诗/poet.song.79000.json','["北風驅雲度危嶠，日下蒼茫煙靄横。", "山靈唤客起杖屨，定自不凡爲此行。", "山南冥搜未得妙，山陰問津向猿鳥。", "遙岑疊疊羅峻屏，溪流濺濺鳴楚調。", "眼明全椒道士家，丹砂入頰暾朝霞。", "談間勃窣妙理窟，挽不聽去猶欲遮。", "縹思右轄千丈松，眉宇中藏嵇阮風。", "放船雲夢鬼作祟，磈磊仆卧洪濤中。", "此翁身大不及膽，引帆復逐天邊鴻。", "淵宗堂中柱史裔，黄鵠作雛欺鶴唳。", "衣裾不著京洛塵，潛心涪翁哦五字。", "相逢俄頃復解攜，韻勝遣人增想似。", "僧窗夢短夜復長，句挾寒霜聊可寄。"]'),
('00b886f1-38eb-4fe7-b475-eb3f579ef6b6','寄崇書記','李彭','宋','宋诗','song-poetry','','[]','窮山歲晚滿煙雨，欣逢支公會心侣。',128,'全唐诗/poet.song.79000.json','["窮山歲晚滿煙雨，欣逢支公會心侣。", "斵詩已度曹劉前，談玄復恃殽函固。", "寒廳夜寂斗正横，衰懷徑協滄洲趣。", "新章頓挫兵出奇，遙隨歸雁下煙渚。", "胸中書傳要扶疏，筆端聯翩將脫兔。", "淵淵撾就漁陽摻，遽作回帆聽鳴鼓。", "明窗試翫老髯語，黄鵠看君響長阜。", "山陰傲吏有僧珍，水鏡湛然當見許。"]'),
('ee4ee882-b9c3-4cf7-9e6d-c13dbb587104','寄甘露滅','李彭','宋','宋诗','song-poetry','','[]','道人欲居甘露滅，年來寄食温柔鄉。',96,'全唐诗/poet.song.79000.json','["道人欲居甘露滅，年來寄食温柔鄉。", "開單展鉢底事遠，舉案齊眉風味長。", "我衰日涉甘岑寂，頗遭霜刺頤長出。", "願隨魚鼓供伊蒲，一墮塵網誰能力。", "要知在欲是行禪，久聚荷花顔色鮮。", "秋濤風怒何掀掀，莫倒危檣沈法船。"]'),
('c655d14d-beb3-4eba-b084-5aaa99ae5467','寄何生','李彭','宋','宋诗','song-poetry','','[]','爛羊都尉本不惡，鬬雞開府無處著。',64,'全唐诗/poet.song.79000.json','["爛羊都尉本不惡，鬬雞開府無處著。", "天禄諸君盡貴遊，據鞍上馬能不落。", "何郎未免儒生酸，於此政復不作難。", "但公剩著潛夫論，何須頭上鵕鸃冠。"]'),
('07b5f946-0356-4d74-88ef-53a9c34bb700','懷秦處度復用山谷韻','李彭','宋','宋诗','song-poetry','','[]','秦髯昨首長沙路，捨舟來甘餘霜兔。',96,'全唐诗/poet.song.79000.json','["秦髯昨首長沙路，捨舟來甘餘霜兔。", "翻憶淮山鷄黍秋，二十年來穿幾屨。", "衣如懸鶉氣栩栩，足垢頭脂藏妙處。", "欲買桑柘閭里歡，却乘舴艋江湖去。", "似尋劍客脱塵埃，北走南遊未安堵。", "去年籬菊今又黄，安得同嘗噀香霧。"]'),
('7e8beda2-0ef2-42a7-83fc-b58bbea09bce','遊雲居歌','李彭','宋','宋诗','song-poetry','','[]','岷峨秀氣凌太白，諸峰彈壓流輩百。',256,'全唐诗/poet.song.79000.json','["岷峨秀氣凌太白，諸峰彈壓流輩百。", "右軍昔爲懷祖困，此心勇往曾未識。", "羊家叔子端可人，峴山何爲苦傷神。", "多情賴有鄒從事，與山不磨有遺味。", "平生尋幽幾屐穿，始知歐峰峰外天。", "捫參歷井出鳥道，耳邊河漢聲潺湲。", "千古追懷同一律，神明還觀悲節物。", "兩郎凜凜安能來，定於何處埋爾骨。", "往時宏覺大道場，心净無塵聞妙香。", "幽禪寂寂師粲可，高韻卓卓凌羲黄。", "九原蕪沒那能作，勝日良遊自不惡。", "靈雲野桃初著花，鼻祖柏子僧前落。", "玉函貝葉渡流沙，法筵復雨曼殊花。", "充虛解戰天皇餅，破魔驚睡趙州茶。", "世網嬰人太煩促，桑下安眠戒三宿。", "柴扉草閣空歸來，大梁推枕黄粱熟。"]'),
('657cac9e-8ca5-41d8-bc39-010ffdc8e53a','玉花驄','李彭','宋','宋诗','song-poetry','','[]','杜陵絕唱驄馬行，想見躡雲噴玉聲。',72,'全唐诗/poet.song.79000.json','["杜陵絕唱驄馬行，想見躡雲噴玉聲。", "龍眠貌出姿態横，香羅覆背紅汗透。", "如行沙苑秋風瘦，我羮芋魁乃飯豆。", "不愛金羈如此驄，深雲一塢住山翁，朝霞入頰常暾紅。"]'),
('f0b200e8-d074-48f1-93fc-2beaa0842934','胡少汲名直孺龍舒佳士清修可喜往歲見之金陵聞除侍御史因作此詩以見意','李彭','宋','宋诗','song-poetry','','[]','聞君往年客淮西，及見我公無恙時。',240,'全唐诗/poet.song.79000.json','["聞君往年客淮西，及見我公無恙時。", "潛山皖水德星聚，天下中庸人表儀。", "川行節往萬事盡，我獨流寓東南涯。", "協洽之歲秋九月，買船適詣秦淮湄。", "建康城頭鷄欲曙，白下門前烏未飛。", "有客剥啄復剥啄，出門一見忘塵羈。", "戛然野鶴下孤嶼，意定吾子初無疑。", "高談確訒不跛踦，養此鬱鬱澗底姿。", "發蒙振落笑餘子，招之不來不可麾。", "判司卑官果難屈，脱身遂與箠楚辭。", "行行且止避驄馬，膽落於地非公誰。", "御爐煙動天顔喜，柱下雲開春日遲。", "側席愛民如愛子，願達民病蘇瘡痍。", "要使英風觸白獸，更遣直氣生青規。", "鄙夫養疾江漢間，有如不信吾誰欺。"]'),
('3e84af8a-e3fd-4ddb-9244-173972708f9b','范家所藏孫知微畫彭祖女禮北斗圖','李彭','宋','宋诗','song-poetry','','[]','晴空無塵月在房，松間博山沈水香。',96,'全唐诗/poet.song.79000.json','["晴空無塵月在房，松間博山沈水香。", "翠眉女子約略粧，兩足亭亭如雪霜。", "步虛之聲風度長，紫微北斗忽低昂。", "金釵何勞十二行，不羨盧家丹桂梁。", "凌雲已復飛羅裳，生絹寫照公家藏。", "應憐彩鸞翳鳯凰，未能割愛俱翺翔。"]'),
('11d0bd5b-ebd6-403c-8b57-f68c1bd3c753','戲答椶笋','李彭','宋','宋诗','song-poetry','','[]','髯翁落落緣坡竹，肥如瓠壺書滿腹。',192,'全唐诗/poet.song.79000.json','["髯翁落落緣坡竹，肥如瓠壺書滿腹。", "好客勤炊燭代薪，中厨羮金仍膾玉。", "春風渺渺生微瀾，欲向吳江把釣竿。", "引帆伐鼓閲三歲，候雁不來衣带寬。", "阿蠻虎子能哮吼，千金掃除似無帚。", "却甘杞菊侵我畦，固窮不障談天口。", "剩誇椶笋饞生津，章就旁搜不厭頻。", "錦綳嬌兒直欲避，紫駝危峰何足陳。", "出爲小草居遠志，藜藿盤中長此味。", "客來不廢董嬌嬈，安用凋胡見真意。", "年來我亦食無魚，莫遣此老専懷羭。", "時時酒澆茶苯尊，亂我玄藳俱扶疏。"]'),
('d7ddfbfd-7ee4-4480-bcda-6680182ad914','送所借書還王生','李彭','宋','宋诗','song-poetry','','[]','鄴侯家藏三萬軸，牙籤新若手未觸。',128,'全唐诗/poet.song.79000.json','["鄴侯家藏三萬軸，牙籤新若手未觸。", "此翁眼如九秋鷹，一過成誦不再讀。", "愧非玄晏獨峥嶸，復愧王郎著論衡。", "案頭螢乾太苦相，久假不歸何癡生。", "開州公子好奇古，胸中寶笈森四庫。", "安用鄴候插架書，向來借我紙上語。", "頻年多病百不如，凖擬傳書學截蒲。", "還君一鴟細故爾，莫厭時時開鎖魚。"]'),
('21accf7a-b178-448f-8c05-2dda51338578','題閻立本醉客圖','李彭','宋','宋诗','song-poetry','','[]','酒有何好工作病，頗怪斯人喜中聖。',128,'全唐诗/poet.song.79000.json','["酒有何好工作病，頗怪斯人喜中聖。", "藏身麯糵勝巖幽，寄愁天上呼不醒。", "春風吹開玉東西，月落參横斟酌之。", "吐茵脱帽有妙理，眩朱成碧渾忘歸。", "右相丹青果馳譽，幻藥調成疑笑語。", "便覺微綃古意生，似聞醉眠卿可去。", "半生憂患復蕭條，甕中肥遁何須邀。", "一樽桑落對公等，盡解平時藜莧嘲。"]'),
('31254f6e-e725-46e5-b95f-fabade0de047','包虎行','李彭','宋','宋诗','song-poetry','','[]','畫師老包氣如虹，解衣醉倒塵泥中。',128,'全唐诗/poet.song.79000.json','["畫師老包氣如虹，解衣醉倒塵泥中。", "急呼生綃卧展轉，筆追造化分奇功。", "須臾奮袂於菟出，絕壑陰崖嘯風月。", "懸著高堂煙霧深，觀者膽寒俱辟易。", "誰爲彪子與虥孫，宛陵後葉諸仍昆。", "顧視雄姿亦遒緊，小犢繭栗何勞吞。", "通玄論成馱貝葉，大空小穴隨老衲。", "何暇與汝同條生，玄豹豐狐要彈壓。"]'),
('2baaa892-0378-43bb-98c6-49598ea3ad7e','望吕道士庵居不果往','李彭','宋','宋诗','song-poetry','','[]','鍊師精悍極了了，穹谷營巢若飛鳥。',80,'全唐诗/poet.song.79000.json','["鍊師精悍極了了，穹谷營巢若飛鳥。", "流泉滌盡化淄塵，明窗點存填血腦。", "停策微聞叔夜琴，叩關阻食安期棗。", "我方尋源上河漢，目送落日諸峰小。", "杪秋蠟屐要重來，與子相過拾瑤草。"]'),
('ac45002a-3e77-4efa-8d8a-8ea6076c1e49','食鰒魚戲呈夏侯','李彭','宋','宋诗','song-poetry','','[]','君不見吳良齋郡吏，斂板居高隨掾史。',178,'全唐诗/poet.song.79000.json','["君不見吳良齋郡吏，斂板居高隨掾史。", "諸郎元日壽府君，觴酒諛言敗人意。", "口角擊節五馬賢，鰒魚百輩爲君賜。", "又不見江左之禇淵，此魚一尾售數千。", "丈夫須髪果如戟，但知堪炙寧論錢。", "平生剛直卧江漢，非吳非禇何由羨。", "療饑漸臺亦可悲，味比瘡痂良可賤。", "謂言此物不擬嘗，餉我因君累十觴。", "漢陰槎頭推不御，徐州秃尾甘走藏。", "藜莧觴中初未識，已覺盤餐慘無色。", "憑君遣使更函封，莫令子羽吟頭責。"]'),
('aa8aedde-85d4-4939-b639-5079780e854c','重遊草堂','李彭','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','德人昔遊居寢處，一草一木可敬之。',224,'全唐诗/poet.song.79000.json','["德人昔遊居寢處，一草一木可敬之。", "涪翁初釋僰道縳，枉道過我臨水湄。", "梵宫三託吉祥卧，悠悠東泛長淮涯。", "牽絲姑孰席未暖，鬼瞰高明俄解龜。", "鸚鵡洲前弄晴泚，祠宫寄食長江西。", "黄絹碑中發奇禍，播遷瘴海如湘纍。", "天生斯人意有在，世或不用將何疑。", "巫陽下招化黄鵠，不遣啄腐隨家鷄。", "前年歲晏到蕭寺，開眼適見鄒松滋。", "涪翁故時得此客，今已改色嗟流離。", "大招淚濕緣坡竹，神觀凜凜疑來歸。", "今年森木挂秋暑，鷓鴣鈎輈向我啼。", "重來野僧零落盡，壞帳鼠囓非當時。", "過眉拄杖爲小立，將暝西山含夕霏。"]'),
('f4e7063a-8c7d-4008-97cf-a0b6e3ae3c3a','黄岡尉錢紳種蓮其上開軒榜曰起靈蓋取鮑參軍荷花賦超四照之靈本云','李彭','宋','宋诗','song-poetry','','[]','平吳利在獲二陸，我得斯人一夔足。',128,'全唐诗/poet.song.79000.json','["平吳利在獲二陸，我得斯人一夔足。", "明光射策卷波瀾，灞橋新詩挾冰玉。", "只因心賞鮑參軍，種花欲招千載魂。", "筆端有口不倚辨，盡付此花生氣存。", "一代風流幾頓盡，漢官威儀聊復正。", "覓句何勞夢惠連，解頤未用呼匡鼎。", "秋風蘋末助颼飀，花藥應須讓一頭。", "何必嘉陵種嘉橘，始擬人間千户侯。"]'),
('0f7f5c72-b2c3-4476-8b93-531ae65aeb33','東庵舒老出徐兔圖障求詩章末兼戲行叟','李彭','宋','宋诗','song-poetry','','[]','宛陵包虎天下無，徐生之兔畫作殊。',176,'全唐诗/poet.song.79000.json','["宛陵包虎天下無，徐生之兔畫作殊。", "眼明忽見此粲者，在笥不獨藏於菟。", "平岡雄兔脚撲朔，草樹深煙紛漠漠。", "懸知丹青相拂斫，不怕蒼鷹頭戴角。", "坡陀雌兔眼迷離，拊憐大兒攜小兒。", "銜粟分甘且療饑，學母由來無不爲。", "東庵道人念俱寂，遣予不復嘲熱客。", "生綃新圖聊一出，便覺野風來四壁。", "緬懷中有衣褐徒，不牙不角真趺居。", "莫令舉網拔豪族，湯沐管城還自娯。", "黑頭歸來能自了，巖壑猶堪伴猿鳥。"]'),
('56b0f7e3-ea0d-4c07-845e-622e0d06cbc0','題伯時所畫邵平種瓜圖','李彭','宋','宋诗','song-poetry','','[]','邵平湯沐故千户，解組投林如脱兔。',192,'全唐诗/poet.song.79000.json','["邵平湯沐故千户，解組投林如脱兔。", "勒銘鼎鼐屬伊人，我方荷鋤斸烟雨。", "瓜田鈎带蓋阡陌，大者輪囷細旁午。", "殽函設險吾何補，日日青門自成趣。", "槿籬半破復牽蘿，夕霏晼晚留疏樹。", "娟然翠氣出眉嫵，喜得斯人慰遲暮。", "劇談欲寫塊磊胸，尚恐軒昂作莊語。", "畫師紛紛安足數，對此令人重豪素。", "陽陵公子傲雪林，灑落由來足風露。", "自言購取傾家貲，柴桑要伴歸來賦。", "兩郎後先千載餘，粉墨相追叶風度。", "懸之素壁足丘壑，噭噭猿啼起寒霧。"]'),
('c8e01ba2-c464-4585-93b9-ef22937c6c81','題盧鴻草堂圖','李彭','宋','宋诗','song-poetry','','[]','丈室幽雲織翠微，盧生草堂雲作扉。',160,'全唐诗/poet.song.79000.json','["丈室幽雲織翠微，盧生草堂雲作扉。", "陰崖絕壑鳥跡稀，扶藜縱觀拂雲霓。", "心知丹轂赤吾族，要須愛身如愛玉。", "三十六峰幽意足，何必鑒湖分一曲。", "老仙寧上登封壇，一夜蠒生雙足間。", "不知此圖筆筆妙，巖巒映带冰霜顔。", "集賢學士從省歸，僧床卧觀晝掩扉。", "繡鞍那補塵化緇，不如盧郎駕鴻飛。", "老色蒼顔今採薇，故山風煙常滿衣。", "眼明見此社中客，盡謝東阡與西陌。"]'),
('7c6d2a31-2d32-442d-8cc0-37cbbd371f86','題包虎枕屏','李彭','宋','宋诗','song-poetry','','[]','兩虎肉醉欲醒時，饑腸得飽恣遊嬉。',64,'全唐诗/poet.song.79000.json','["兩虎肉醉欲醒時，饑腸得飽恣遊嬉。", "一虎當巖自哮吼，朝欲食子暮食妃。", "最後一虎絕長者，坐歗眼有百步威。", "豺狼當道正須汝，莫尋兔徑問狐狸。"]'),
('314011cc-3676-4513-a6d4-e21dbbd6c333','列遵道以古銅爵見歸','李彭','宋','宋诗','song-poetry','','[]','何年銅爵姿狀古，如對高人開美度。',128,'全唐诗/poet.song.79000.json','["何年銅爵姿狀古，如對高人開美度。", "重雲結疊虺虺雷，遶腹循環危欲雨。", "廉問御風之子孫，世南秘書藏肺腑。", "縱釴欲炙真垂涎，舉以壽卿吾所許。", "非無玉舟金叵羅，簡素睨之如糞土。", "奈何趙璧復來歸，知我懷茲會心侣。", "拂塵識面如故人，口不能言實莊語。", "細酌明窗舊索郎，伴我微吟度寒暑。"]'),
('a96fc0b8-3251-4ab9-a18a-e75d747c874e','吳熙老家風雲圖','李彭','宋','宋诗','song-poetry','','[]','秦人屈鼎真畫師，胸蟠風雲人得知。',176,'全唐诗/poet.song.79000.json','["秦人屈鼎真畫師，胸蟠風雲人得知。", "獨無佳句自潤色，未忍援毫時吐之。", "酒澆塊磊遂倒槖，素練忽復翻淋漓。", "宛如盛怒生囊口，飈至霆擊何由追。", "墨雲霮䨴摧半岳，飛動殆莫窮端倪。", "征人解装馬伏櫪，居人墐户雞亦棲。", "虚堂高掛髪爲立，三伏凜凜無炎曦。", "吳侯憐我慘不樂，卷去隨手俱清夷。", "乃知非獨畫工妙，妄念起滅分毫釐。", "想當在笥常洶洶，不與關河相蔽虧。", "會當一雨被八表，何用袐藏深密爲。"]'),
('7b2efa60-499c-4a6a-bdc1-721e9484cf5b','題伯時畫蓮社圖','李彭','宋','宋诗','song-poetry','','[]','遠公得名喧宇宙，如意舉墮渠不知。',96,'全唐诗/poet.song.79000.json','["遠公得名喧宇宙，如意舉墮渠不知。", "何爲歗聚野狐羣，依經解義真成癡。", "柴桑老翁挽不留，籃輿醉衝烟靄歸。", "由來却具一隻眼，社中不著謝客兒。", "白業許時露消息，鼻觀參取初自誰。", "飲光微笑總爲此，至今留與後人疑。"]'),
('e020dfcb-55eb-4e7d-9e40-6a89d0d52499','題吳成伯家文與可所畫晚靄横春圖','李彭','宋','宋诗','song-poetry','','[]','湖州手參造化鑪，墨君老稚俱扶疏。',112,'全唐诗/poet.song.79000.json','["湖州手參造化鑪，墨君老稚俱扶疏。", "含毫回作晚靄戲，凴軒丹青渾欲無。", "雨聲忽破鳥行急，木末尚掛窮猿呼。", "衰翁將雛來蕩槳，挽引斜暉到漁網。", "嵐昏那計目力長，厓傾欲陟天梯往。", "湖州雖仆妙相存，此畫他年人更珍。", "但恐君家風雨夜，山川斷取不無神。"]'),
('989cf8dd-af43-44dc-9de3-84ff4875050b','晨起','李彭','宋','宋诗','song-poetry','','[]','晨起按行瓜芋區，園竪畦丁争殿最。',96,'全唐诗/poet.song.79000.json','["晨起按行瓜芋區，園竪畦丁争殿最。", "蹲鴟壠底未輪囷，蒲鴿藤間懸鈎带。", "錦里先生態度同，青門故侯風味在。", "肥家敢望李衡奴，擊彊安用任棠薤。", "累人僅解口腹嘲，貰酒可免尋常債。", "含毫初不爲矜奇，遣興聊須風雨快。"]'),
('c9e568e0-c2bb-41dc-95fa-5d27384a56f8','韓熙載宴客圖','李彭','宋','宋诗','song-poetry','','[]','紫微華屋桂爲梁，中有侍兒宫樣粧。',96,'全唐诗/poet.song.79000.json','["紫微華屋桂爲梁，中有侍兒宫樣粧。", "閉門投轄醉短舞，牛馬因風兩相忘。", "翠翹掛冠真細事，必能作賊無顧忌。", "堂上燭滅何足云，亦期羽林射鵰子。", "當年誰遣轉鴻鈞，終典哀榮厚恩禮。", "西風猶吹建業水，直恐姦魂污清泚。"]'),
('031c321f-0db2-447d-a7b4-4945dd4bf499','次山谷答范信中韻','李彭','宋','宋诗','song-poetry','','[]','范君膽勇如季路，三穴笑談空狡兔。',96,'全唐诗/poet.song.79000.json','["范君膽勇如季路，三穴笑談空狡兔。", "鋭頭初無儒生酸，果呼下邳换雙屨。", "往年風義公獨許，藥裹追攀險艱處。", "公隨瘴葉落瘴鄉，買舟反骨勞君去。", "少陵未築耒陽墳，尚喜宗文有環堵。", "人生萬事何所無，極目澄江鎖寒霧。"]'),
('e3135d79-150a-4213-a897-efe0839f3a90','賦張邈所畫山水圖','李彭','宋','宋诗','song-poetry','','[]','異時頗愛宋元君，踏門畫史如雲屯。',176,'全唐诗/poet.song.79000.json','["異時頗愛宋元君，踏門畫史如雲屯。", "舐筆和墨太早計，解衣槃薄全天真。", "夢澤張侯飽閒暇，直疑胸中有成畫。", "酒酣耳熱呼不醒，澹墨淋漓疾揮灑。", "誰爲右轄賦招魂，遠過酸寒鄭廣文。", "怪底高堂見丘壑，欲攀松蘿尋石門。", "咫尺終南與王屋，翩翩不下如黄鵠。", "水南水北索價高，放浪猶歌紫芝曲。", "張侯愛畫入骨髓，腦脂遮眼良有以。", "筆端刻意寫遺民，要似留侯赤松子。", "如聞可汲用王明，會須添作貢公喜。"]'),
('654112b7-87c4-4743-9d67-b10fd2f05cba','賦米芾所畫金山圖','李彭','宋','宋诗','song-poetry','','[]','憶昔扁舟帆正落，楊子江頭風浪惡。',192,'全唐诗/poet.song.79000.json','["憶昔扁舟帆正落，楊子江頭風浪惡。", "江心樓臺渾欲沈，不獨能高瓦棺閣。", "晚山接天波面平，白鷗去邊鐘磬鳴。", "雲昏上頭不可到，往來余懷今未寧。", "楚狂澹墨掃絹素，澄神卧遊知處所。", "欲披霧牖尋野僧，反向烟汀辨江樹。", "新詩葱蒨工於畫，川岑想像高堂掛。", "驊騮絕塵走千里，何勞遠處幽并夜。", "漸到潯陽不復前，安得仙山來眼邊。", "斷非毗耶掌中取，直疑壺公謫處天。", "新詩妙畫真有益，張衡南都能畢力。", "不如此詩氣崷崒，却使丹青句中識。"]'),
('8efaf72a-eef5-40d1-b113-0ee4142d026f','小憩琵琶亭呈環中養正','李彭','宋','宋诗','song-poetry','','[]','香山居士骨已冷，文采風流今未遙。',64,'全唐诗/poet.song.79000.json','["香山居士骨已冷，文采風流今未遙。", "捍撥何勞作胡語，寒江璧月想前朝。", "濤波竟夕相喧豗，吳檣楚柁争傾欹。", "老夫何暇知許事，但飲松醪炰蛤蜊。"]'),
('1ec7ab51-8250-400c-af6d-3a57ef2b9c18','客有以戲魚竹枕見餉作此謝之','李彭','宋','宋诗','song-poetry','','[]','蘄州笛竹含風漪，縹瓷斵月聊相依。',128,'全唐诗/poet.song.79000.json','["蘄州笛竹含風漪，縹瓷斵月聊相依。", "白頭苦風癡女問，歲晚乃知非所宜。", "公從何處得此枕，勁節儲霜餘凜凜。", "遊戲真同赴壑魚，小窗夕陽助酣寢。", "餌甘釣深安可圖，長網横江嗟已疏。", "我寧低昂弄清泚，絕勝縷切太官厨。", "莫作枯魚過河泣，寄聲魴鱮慎出入。", "長伴幽人蓑笠眠，夢破寒沙風雨急。"]'),
('cc5f5606-852f-49a0-8267-030d5ea50cd3','同子蒼放船南山石壁下','李彭','宋','宋诗','song-poetry','','[]','南山修源何所似，顧癡鋪張側釐紙。',160,'全唐诗/poet.song.79000.json','["南山修源何所似，顧癡鋪張側釐紙。", "酒酣潄墨風雨来，咫尺煙昏生萬里。", "韓侯静者妙英姿，乃呼扁舟共遨戲。", "我曹竟墮善幻中，叩舷歌呼但霑醉。", "寺下回潭凝不流，中有卧石如潛虬。", "孤峰已銜半規日，連山倒垂波底浮。", "韓侯風雅才甚優，胸中何止吞萬牛。", "未向承明草蓮燭，小留南國馴沙鷗。", "會須唤仗入天陛，尚憶谿邊横小舟。", "但願故人俱厚禄，平子不妨吟四愁。"]'),
('7f2228d8-de18-4d4f-b7d7-1f412e6f6b8e','何生復用塗字韻喜予從東坡遊作三篇見寄次韻答之後篇柬劉壯輿  其一','李彭','宋','宋诗','song-poetry','','[]','嶠南將成金匱書，喜又賜環香拂塗。',64,'全唐诗/poet.song.79000.json','["嶠南將成金匱書，喜又賜環香拂塗。", "萬釘圍腰乃爲祟，慣作臞仙多槁枯。", "元符相國泣前魚，長流百粤復羌胡。", "周漢二宣果明哲，金玉王度復關渠。"]'),
('500341a5-9225-4aa6-acd8-d38f2792e614','何生復用塗字韻喜予從東坡遊作三篇見寄次韻答之後篇柬劉壯輿  其二','李彭','宋','宋诗','song-poetry','','[]','東坡十年作謗書，多情杖屨作歸塗。',64,'全唐诗/poet.song.79000.json','["東坡十年作謗書，多情杖屨作歸塗。", "雪堂公去頗削迹，來禽青李皆已枯。", "秋風醉索武昌魚，脚敲兩舷聲函胡。", "只今諸生典刑在，他日明公遊石渠。"]'),
('1ed57dd2-d4d4-4a3e-85a3-241c5f85c5f7','何生復用塗字韻喜予從東坡遊作三篇見寄次韻答之後篇柬劉壯輿  其三','李彭','宋','宋诗','song-poetry','','[]','冰玉堂前十國書，君能讀之行坦塗。',64,'全唐诗/poet.song.79000.json','["冰玉堂前十國書，君能讀之行坦塗。", "一洗談天千古舌，吕梁大壑何時枯。", "願君不用校魯魚，亦須調笑酒家胡。", "玉局仙翁無浪語，大禹以來未有渠。"]'),
('0472cb7d-18fd-4fce-95b5-7fd7bdd173cf','喜二何從山谷遊復用塗字韻詩','李彭','宋','宋诗','song-poetry','','[]','水部諸郎蠆尾書，涪翁杖履傲當塗。',64,'全唐诗/poet.song.79000.json','["水部諸郎蠆尾書，涪翁杖履傲當塗。", "斑斑束笋門下士，梔貎蠟言嚬笑枯。", "翰墨瀾翻縱壑魚，風采灑落鳯棲梧。", "寄語南州雙白璧，從今價重百車渠。"]'),
('926dc5cf-d29c-401a-a875-a754fdf17039','張僧繇畫胡僧看經','李彭','宋','宋诗','song-poetry','','[]','蒼崖倚天暝色起，風微槲葉藏猱子。',64,'全唐诗/poet.song.79000.json','["蒼崖倚天暝色起，風微槲葉藏猱子。", "老僧龐眉雪覆顴，梵音清遠發皓齒。", "向來萬法出此經，行行春蚓紆黄紙。", "覿面相呈事儼然，歸雲欲渡前溪水。"]'),
('7d934c1b-e4a8-4c36-ace6-82670ffd348b','題夏氏萬賞亭','李彭','宋','宋诗','song-poetry','','[]','公家文莊佐縣官，萬國朝宗天不言。',224,'全唐诗/poet.song.79000.json','["公家文莊佐縣官，萬國朝宗天不言。", "桂梁蘭室治私第，鳷鵲建章争絕倫。", "昭華穠李態度新，綠尊翠杓羅繽紛。", "人歸夜臺金狄泣，一種風流今尚存。", "小君家聲自陰后，五侯四貴印如斗。", "渠渠夏屋幾百椽，誰能近前畏左右。", "去天尺五付此郎，詩豪酒聖復専場。", "錦韉花驄折楊柳，霸陵惡少艾如張。", "危亭複閣來南州，佳客争門陪俊遊。", "朱轓皂蓋駐五馬，叵羅醉擲高陽侯。", "青蛾皓齒動星眸，尊前舞罷錦纒頭。", "參横月落了不問，四并在手吾何憂。", "腐儒蕭然愧環堵，藜莧胸中扊扅句。", "頽然被酒燭如虹，戲效吳歌歌白紵。"]'),
('51099b8a-f1c2-4177-96e7-5c88baa3e51e','戲答賦蚊','李彭','宋','宋诗','song-poetry','','[]','江湖白鳥傳自古，蟄蟄孫寧亦如許。',96,'全唐诗/poet.song.79000.json','["江湖白鳥傳自古，蟄蟄孫寧亦如許。", "聚雷豈解殷晴空，媒孽耳根良自苦。", "野人睡美不聞鐘，草木苯尊森蟠胸。", "唼膚攻喙漫不省，躍躍自喜安足雄。", "若人才高樂譏評，滑稽能發古人興。", "勾引西風鏖細蟲，小醜何勞霍去病。"]'),
('6c31267d-961e-413f-90f6-237bc1d5a389','遊東園戲作長句','李彭','宋','宋诗','song-poetry','','[]','久客殊方無永味，排遣春愁逐遨戲。',80,'全唐诗/poet.song.79000.json','["久客殊方無永味，排遣春愁逐遨戲。", "曉濟吳榜訪東園，欣欣草木多佳氣。", "縹瓷竹葉沃春心，黑面酪奴驅晝睡。", "親黨諸郎意氣豪，挽強對弈真能事。", "鄙夫魯鈍獨長吟，一聲望帝動歸思。"]'),
('29449398-52c0-4af9-872c-3e7234daa52b','贈吳雲叟','李彭','宋','宋诗','song-poetry','','[]','宛城居士如冰雪，大藥親逢悟禪悦。',64,'全唐诗/poet.song.79000.json','["宛城居士如冰雪，大藥親逢悟禪悦。", "丹霞正印君得提，洞下靈源渠未絕。", "净名杜口涉言詮，口如布穀意莫傳。", "心猿睡起六窗净，爲君作戲彈無弦。"]'),
('17857c01-1617-4512-bb9e-e0d29ae5b12e','贈張聖達','李彭','宋','宋诗','song-poetry','','[]','人言汝潁多奇士，秀潤如君飽風味。',64,'全唐诗/poet.song.79000.json','["人言汝潁多奇士，秀潤如君飽風味。", "兩鞬馳射不作難，三峽倒流聊復爾。", "平生未識嵩少雲，三十六峰巖壑春。", "因君便覺來眼界，翻作新詩持餉君。"]'),
('89ede2b1-eb51-49c3-b0fa-9887286f3d9b','張子和子文以長句送朋壺次韻答之','李彭','宋','宋诗','song-poetry','','[]','下自成蹊藝桃李，此語聊持餉吾子。',256,'全唐诗/poet.song.79000.json','["下自成蹊藝桃李，此語聊持餉吾子。", "南風吹句落窗几，蕭然出塵天下士。", "詩壇挑戰生一秦，窮瞎水部好仍昆。", "氣無萬里照夜白，伏櫪麒麟收驚魂。", "荆州但獲一人半，二雋風流眼中見。", "機雲空誇千里蓴，如公筆端那復倦。", "我誦懷沙自療饑，時時間出危苦詞。", "鳴蛙兩部頗娯聽，鉅竹千竿端相持。", "督郵雖賤不勤置，儼然真辨絕交事。", "知君風味似建康，連璧頓來隨俗吏。", "漫澆平時過秦胸，經醉咄咄成書空。", "兒曹爲具明蠒紙，欲賦雌蜺吞晴虹。", "懸知在德不在酒，耳熱清狂須酒後。", "客來舉觴不得言，舌本因之忘可否。", "擊柝相聞非路長，濤波隔津成兩鄉。", "待我營巢浣花了，過君更僕對繩床。"]'),
('1ae43724-aa39-4814-9871-1094ae3fb0af','用擬古韻答瑛上人','李彭','宋','宋诗','song-poetry','','[]','劇飲徑須尊有癭，搜攪新詩轉遒緊。',64,'全唐诗/poet.song.79000.json','["劇飲徑須尊有癭，搜攪新詩轉遒緊。", "誰知雲窗除饉男，燕坐微吟兼粲忍。", "吾衰霾霧滿胸中，玩味甘腴真雋永。", "含毫覓句剩欲酬，時有寒泉汲舊井。"]'),
('9303e10c-4761-4658-af2c-5c9e522fbdf2','先成都訪故園得顔家斷壠碑','李彭','宋','宋诗','song-poetry','','[]','我生性僻喜客卿，有練先書無復贏。',176,'全唐诗/poet.song.79000.json','["我生性僻喜客卿，有練先書無復贏。", "墨池筆冡聊爾耳，春蛇秋蚓勞譏評。", "正書不數黄庭經，况復焦巖瘞鶴銘。", "永和題尾束高閣，醬瓿往往多蘭亭。", "怒猊渇驥日遠屏，嚴家餓隸當吞聲。", "千金敝帚不自見，憎雞愛騖何癡生。", "我家成都萬人傑，向來古心冶金鐵。", "顔公斷石出糞壤，一落眼界清思發。", "政如令嚴亞夫軍，中天夜寂懸明月。", "速須乞靈向若人，運斤成風萬鈞力。", "筆端寫我剛直胸，復與顔公振遺烈。"]'),
('3d542362-1d23-4d77-84cd-51ec7e13ceb3','宴清心閣','李彭','宋','宋诗','song-poetry','','[]','馬尾垂楊已墮綿，春風暴謔惱中年。',128,'全唐诗/poet.song.79000.json','["馬尾垂楊已墮綿，春風暴謔惱中年。", "驅車作意訪花縣，地主風流仍更賢。", "倦遊不比長卿慢，自迎傑閣開清宴。", "高談雄辨俯飛鳥，急管哀絃徹河漢。", "君侯筆端妙入神，百斛炳焕扛龍文。", "承明合受鸎花繞，何事斂板趨埃塵。", "清朝好士如好色，况茲卓絕流輩百。", "追鋒看即朝日邊，莫道垂綸在幽昃。"]'),
('53ff7ea8-cc69-4380-b94e-578aa52ea1a7','阻風雨封家市','李彭','宋','宋诗','song-poetry','','[]','往時李成寫驟雨，萬里古色毫端聚。',96,'全唐诗/poet.song.79000.json','["往時李成寫驟雨，萬里古色毫端聚。", "行人深藏鳥不度，便覺非復鵝溪素。", "龍眠老腕作陽關，北風低草雲埋山。", "行人客子兩愁絕，未信蒲萄能解顔。", "兩郎了了解人意，似是畫我封家市。", "戲作新詩排晝睡，忽有野雁鳴天際。"]'),
('7d937d86-e886-4d42-a763-747db4cf2c2a','贈中上座','李彭','宋','宋诗','song-poetry','','[]','粲可仍孫本吳産，萬遍蓮花亦遮眼。',64,'全唐诗/poet.song.79000.json','["粲可仍孫本吳産，萬遍蓮花亦遮眼。", "時時幻作文於菟，寂寥恨得斯人晚。", "我如叔夜七不堪，倦書羞學蠹書蟫。", "已約東湖徐孺子，招公山北復山南。"]'),
('adbee19b-1c6a-4d04-94cc-2bf36bcea88f','贈宗紱上座','李彭','宋','宋诗','song-poetry','','[]','蒲萄不飲熊耳杯，薰爐甘作槖駝坐。',80,'全唐诗/poet.song.79000.json','["蒲萄不飲熊耳杯，薰爐甘作槖駝坐。", "胸中皎鏡湛靈源，結習已空花自墮。", "眼明見此除饉男，妙語時時零玉唾。", "稻畦摩衲丈夫事，吾獨知之胡不果。", "鈎章棘句竟何禆，徒遣詩人嘲飯顆。"]'),
('9c5cbeb3-5514-4713-b227-3c17c330b2e0','觀法華牛鬬戲呈戒上座','李彭','宋','宋诗','song-poetry','','[]','雞棲于塒晚山碧，兩牛偃蹇萬鈞力。',96,'全唐诗/poet.song.79000.json','["雞棲于塒晚山碧，兩牛偃蹇萬鈞力。", "黄鐘滿脰鳴相歡，歘起緣何作勍敵。", "水牯敗績秋風前，穿林觳觫蹊人田。", "幾無將軍破燕虜，適堪衞尉駕車轅。", "碧眼山僧可人意，大牛小牛與穿鼻。", "更須宴坐三十年，直待無鞭更無轡。"]'),
('5f9954f7-7a37-43d4-8d96-4f0b3dcfbf23','雪夜書懷','李彭','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','夜烹伏雌歌偪側，泰山其頹吾道阨。',144,'全唐诗/poet.song.79000.json','["夜烹伏雌歌偪側，泰山其頹吾道阨。", "天邊奎壁殞蘇公，諸君往往瀕蠻貊。", "帝遣仙儒玉局翁，涕下悲吟夜蕭索。", "冰姿玉立似平生，化作人間截肪白。", "黄屋久悟金縢書，豫行温詔歸遷客。", "嶠南華髪老先生，解羈來卜愚溪宅。", "枉遭越犬吠蒼皇，莫吟冰柱要呵責。", "重瞳雖復達四聰，尚恐乘軒多令色。", "短檠花重寒不眼，南望猶嗟萬山隔。"]'),
('03caa098-e121-409a-b724-c61ab2c9c2d2','蝴蝶詩','李彭','宋','宋诗','song-poetry','','[]','碧梧翠竹名家兒，今作栩栩蝴蝶飛。',238,'全唐诗/poet.song.79000.json','["碧梧翠竹名家兒，今作栩栩蝴蝶飛。", "山川阻深網羅密，君從何處能來歸。", "疑君枕肱作莊夢，誤隨秋風訪天涯。", "大兒稍黠兒中虎，小兒初學繡帳語。", "青娥皓齒越中女，夜挑錦字停機杼。", "可歎不可思，可思不可見。", "君來翻作昧平生，看朱成碧非君面。", "耿蘭作報斷人腸，况復雀聲哦洞房。", "不知真是玉人否，大鈞刻彫不可量。", "君不聞蜀天子，化爲杜鵑似老烏。", "悲啼清血百花盡，有恨不吐歸黄壚。", "又不見湘纍平生女嬃罵，空遺離騷萬鈞價。", "楚些許時招不來，亦復穿花繞寒夜。", "願君莫飛入兔園，青春粲粲花葉繁。", "雄蜂雌蝶閙如雨，於君一脚不可安。"]'),
('0d43c206-2422-47e0-aeb5-68bfee2ad75e','贈詵首座','李彭','宋','宋诗','song-poetry','','[]','上人鬚髪森如戟，年少寧爲萬人敵。',64,'全唐诗/poet.song.79000.json','["上人鬚髪森如戟，年少寧爲萬人敵。", "父兄膏血染敵戈，晚作梵王門下客。", "西州白㲲爛生光，來逐鳯棲山寺凉。", "萬遍蓮花君自足，曹溪一滴定須嘗。"]'),
('33e41e31-666e-410f-a18c-7ec190a310ba','中秋遇雨夜將半素月流天可愛感予賦詩','李彭','宋','宋诗','song-poetry','','[]','雲將長空斮絮晴，膚寸而合雨建瓴。',96,'全唐诗/poet.song.79000.json','["雲將長空斮絮晴，膚寸而合雨建瓴。", "阿香推車不知倦，雅意望舒無復明。", "地行賤臣未辨訴，斜漢左界俄無聲。", "雖非西園清夜樂，起予縹瓷來酌醽。", "舉觴嬋娟聽我語，樽下藉汝攻愁城。", "長令屏翳當令節，莫遣楚氛蔽明月。"]'),
('56900f35-049d-470d-b735-79ec39c3471e','頌一百則  其一','釋重顯','宋','宋诗','song-poetry','','[]','聖諦廓然，何當辨的。',60,'全唐诗/poet.song.8000.json','["聖諦廓然，何當辨的。", "對朕者誰，還云不識。", "因茲暗渡江，豈象生深棘。", "闔國人追不再來，千古萬古空相憶。", "休相憶，清風匝地有何極。"]'),
('b30fe2be-7a80-40dc-9e04-5385d4975db4','頌一百則  其二','釋重顯','宋','宋诗','song-poetry','','[]','至道無難，言端語端。',61,'全唐诗/poet.song.8000.json','["至道無難，言端語端。", "一有多種，二無兩般。", "天際日上月下，檻前山深水寒。", "髑髏識盡喜何立，枯木龍吟消未乾。", "難難，揀擇明白君自看。"]'),
('f66f5016-f92c-4692-b896-fdca1c7b7bae','頌一百則  其三','釋重顯','宋','宋诗','song-poetry','','[]','日面佛，月面佛，五帝三皇是何物。',44,'全唐诗/poet.song.8000.json','["日面佛，月面佛，五帝三皇是何物。", "二十年來曾苦辛，爲君幾下蒼龍窟。", "屈堪述明眼，衲僧莫輕忽。"]'),
('3a6573a2-28d5-438e-8453-8783dfd0174a','頌一百則  其四','釋重顯','宋','宋诗','song-poetry','','[]','一勘破，二勘破，雪上加霜曾險墮。',50,'全唐诗/poet.song.8000.json','["一勘破，二勘破，雪上加霜曾險墮。", "飛騎將軍入虜庭，載得完全能幾箇。", "急走過，不放過，孤峰頂上草裏坐。", "咄。"]'),
('5779ad0a-46e5-4800-bd51-66e24489961d','頌一百則  其五','釋重顯','宋','宋诗','song-poetry','','[]','牛頭沒，馬頭迴，曹溪鏡裏絕塵埃。',32,'全唐诗/poet.song.8000.json','["牛頭沒，馬頭迴，曹溪鏡裏絕塵埃。", "打鼓看來君不見，百花春至爲誰開。"]'),
('ebbb9ac4-8de5-41ff-8015-ad4a420249e5','頌一百則  其六','釋重顯','宋','宋诗','song-poetry','','[]','去卻一，拈得七，上下四維無等匹。',66,'全唐诗/poet.song.8000.json','["去卻一，拈得七，上下四維無等匹。", "徐行踏斷流水聲，縱觀寫出飛義迹。", "草茸茸，煙羃羃，空生巖畔花狼藉。", "彈指堪悲舜若多，莫動著，動著三十棒。"]'),
('8cc5ea00-0a33-4273-9735-ccebb60d377e','頌一百則  其七','釋重顯','宋','宋诗','song-poetry','','[]','江國春風吹不起，鷓鴣啼在深花裏。',32,'全唐诗/poet.song.8000.json','["江國春風吹不起，鷓鴣啼在深花裏。", "三級浪高魚化龍，癡人猶戽夜塘水。"]'),
('5142837f-dd22-43b9-9e3d-218a8270a998','頌一百則  其八','釋重顯','宋','宋诗','song-poetry','','[]','翠巖示徒，千古無對。',60,'全唐诗/poet.song.8000.json','["翠巖示徒，千古無對。", "關字相酬，失錢遭罪。", "潦倒保福，仰揚難得。", "嘮嘮翠巖，分明是賊。", "白珪無玷，誰辨真假。", "長慶相諳，眉毛生也。"]'),
('680c1a01-2403-43a4-806a-d0067218dbec','頌一百則  其九','釋重顯','宋','宋诗','song-poetry','','[]','句裏呈機劈面來，爍迦羅眼絕纖埃。',32,'全唐诗/poet.song.8000.json','["句裏呈機劈面來，爍迦羅眼絕纖埃。", "東南西北門相對，無限輪鎚擊不開。"]'),
('44a6b78f-e75a-4e0c-9947-b229c3e524b7','頌一百則  其一○','釋重顯','宋','宋诗','song-poetry','','[]','兩喝與三喝，作者知機變。',36,'全唐诗/poet.song.8000.json','["兩喝與三喝，作者知機變。", "若謂騎虎頭，二俱成瞎漢。", "誰瞎漢，拈來天下與人看。"]'),
('ac00e603-6d2a-4777-9207-7d013895ffae','頌一百則  其一一','釋重顯','宋','宋诗','song-poetry','','[]','凜凜孤風不自誇，端居寰海定龍蛇。',32,'全唐诗/poet.song.8000.json','["凜凜孤風不自誇，端居寰海定龍蛇。", "大中天子曾輕觸，三度親遭弄爪牙。"]'),
('4c8bb1e9-a39d-4a02-a7a2-be52bbe9b32a','頌一百則  其一二','釋重顯','宋','宋诗','song-poetry','','[]','金烏急，玉兔速，善應何曾有輕觸。',66,'全唐诗/poet.song.8000.json','["金烏急，玉兔速，善應何曾有輕觸。", "展事投機見洞山，跛鼇盲龜入空谷。", "花簇簇，錦簇簇，南地竹兮北地木。", "因思長慶陸大夫，解道合笑不合哭。", "咦。"]'),
('44cd53f3-cba8-424c-a91a-df46f05ca7af','頌一百則  其一三','釋重顯','宋','宋诗','song-poetry','','[]','老新開，端的別，解道銀碗裏盛雪。',48,'全唐诗/poet.song.8000.json','["老新開，端的別，解道銀碗裏盛雪。", "九十六箇應自知，不知卻問天邊月。", "提婆宗，提婆宗，赤幡之下起清風。"]'),
('69910392-cb6a-4cb6-86c9-ada661d1d197','頌一百則  其一四','釋重顯','宋','宋诗','song-poetry','','[]','對一說，太孤絕，無孔鐵鎚重下楔。',43,'全唐诗/poet.song.8000.json','["對一說，太孤絕，無孔鐵鎚重下楔。", "閻浮樹下笑呵呵，昨夜驪龍拗角折。", "別別，韶陽老人得一橛。"]'),
('295021db-5c10-445c-a3c6-635a4c2ba027','頌一百則  其一五','釋重顯','宋','宋诗','song-poetry','','[]','倒一說，分一節，同死同生爲君決。',43,'全唐诗/poet.song.8000.json','["倒一說，分一節，同死同生爲君決。", "八萬四千非鳳毛，三十三人入虎穴。", "別別，擾擾匆匆水裏月。"]'),
('52bbf667-07ca-4b9c-b28d-5484b180255d','頌一百則  其一六','釋重顯','宋','宋诗','song-poetry','','[]','古佛有家風，對揚遭貶剝。',42,'全唐诗/poet.song.8000.json','["古佛有家風，對揚遭貶剝。", "子母不相知，是誰同啐啄。", "啄覺猶在，殻重遭撲，天下衲僧徒名邈。"]'),
('8af7ffd5-0a67-4e35-9506-fe96290dd69d','頌一百則  其一七','釋重顯','宋','宋诗','song-poetry','','[]','一箇兩箇千萬箇，脫卻籠頭缷角駄。',32,'全唐诗/poet.song.8000.json','["一箇兩箇千萬箇，脫卻籠頭缷角駄。", "左轉右轉隨後來，紫胡要打劉鐵磨。"]'),
('f96f42bc-1958-41cb-9ac7-53afa814d11a','頌一百則  其一八','釋重顯','宋','宋诗','song-poetry','','[]','無縫塔，見還難，澄潭不許蒼龍蟠。',32,'全唐诗/poet.song.8000.json','["無縫塔，見還難，澄潭不許蒼龍蟠。", "層落落，影團團，千古萬古與人看。"]'),
('81cf2740-1e53-4f9f-9a29-35ac0ab81ef0','頌一百則  其一九','釋重顯','宋','宋诗','song-poetry','','[]','對揚深愛老俱胝，宇宙空來更有誰。',32,'全唐诗/poet.song.8000.json','["對揚深愛老俱胝，宇宙空來更有誰。", "曾向滄溟下浮木，夜濤相共接盲龜。"]'),
('dd936330-d7ae-4e17-96ed-3b49674114af','頌一百則  其二○','釋重顯','宋','宋诗','song-poetry','','[]','龍牙山裏龍無眼，死水何曾振古風。',32,'全唐诗/poet.song.8000.json','["龍牙山裏龍無眼，死水何曾振古風。", "禪板蒲團不能用，只應分付與盧公。"]'),
('e98089ba-1fc6-488f-bab0-cfc4d009495d','頌一百則  其二一','釋重顯','宋','宋诗','song-poetry','','[]','盧公付了亦何憑，坐倚休將繼祖懷。',32,'全唐诗/poet.song.8000.json','["盧公付了亦何憑，坐倚休將繼祖懷。", "堪對暮雲歸未合，遠山無限碧層層。"]'),
('d60c2f7c-30ac-450c-b8fe-2764b87a7229','頌一百則  其二二','釋重顯','宋','宋诗','song-poetry','','[]','蓮花荷葉報君知，出水何如未出時。',32,'全唐诗/poet.song.8000.json','["蓮花荷葉報君知，出水何如未出時。", "江北江南問王老，一狐疑了一狐疑。"]'),
('ea999f70-30ed-462f-8738-ffc5bc70abd1','頌一百則  其二三','釋重顯','宋','宋诗','song-poetry','','[]','象骨巖高人不到，到者須是弄蛇手。',96,'全唐诗/poet.song.8000.json','["象骨巖高人不到，到者須是弄蛇手。", "稜師備師不奈何，喪身失命有多少。", "韶陽知，重撥草，南北東西無處討。", "忽然突出拄杖頭，拋對雪峰大張口。", "大張口兮同閃電，剔起眉毛還不見。", "如今藏在乳峰前，來者一一看方便。"]'),
('313cc835-8288-4cbb-8279-c32ce0ef86d8','頌一百則  其二四','釋重顯','宋','宋诗','song-poetry','','[]','妙峰孤頂草離離，拈得分明付與誰。',32,'全唐诗/poet.song.8000.json','["妙峰孤頂草離離，拈得分明付與誰。", "不是孫公辨端的，髑髏著地幾人知。"]'),
('796a9503-3594-4b2f-abea-d4e3a7e1d117','頌一百則  其二五','釋重顯','宋','宋诗','song-poetry','','[]','曾騎鐵馬入重城，敕下傳聞六國清。',32,'全唐诗/poet.song.8000.json','["曾騎鐵馬入重城，敕下傳聞六國清。", "猶握金鞭問歸容，夜深誰共御街行。"]'),
('80de2d02-3225-4125-ab3a-16fdb4473900','頌一百則  其二六','釋重顯','宋','宋诗','song-poetry','','[]','眼裏塵沙耳裏土，千峰萬峰不肯住。',32,'全唐诗/poet.song.8000.json','["眼裏塵沙耳裏土，千峰萬峰不肯住。", "落花流水太茫茫，剔起眉毛何處去。"]'),
('fba3e57d-1f85-4d7f-8f50-966a84bcf8c5','頌一百則  其二七','釋重顯','宋','宋诗','song-poetry','','[]','祖域交馳天馬駒，化門舒卷不同途。',32,'全唐诗/poet.song.8000.json','["祖域交馳天馬駒，化門舒卷不同途。", "電光石火存機變，堪笑人來捋虎鬚。"]'),
('810a65a2-e2e6-4155-9231-6f4f506eb309','頌一百則  其二八','釋重顯','宋','宋诗','song-poetry','','[]','問既有宗，答亦攸同。',55,'全唐诗/poet.song.8000.json','["問既有宗，答亦攸同。", "三句可辨，一鏃遼空。", "大野兮涼飇颯颯，長天兮疏雨濛濛。", "君不見少林久坐未歸客，靜依熊耳一叢叢。"]'),
('7375d756-9cdf-42ae-bb48-fd1698ee8a20','頌一百則  其二九','釋重顯','宋','宋诗','song-poetry','','[]','祖佛從來不爲人，衲僧今古競頭走。',48,'全唐诗/poet.song.8000.json','["祖佛從來不爲人，衲僧今古競頭走。", "明鏡當臺列象殊，一一面南看北斗。", "斗柄垂，無處討。", "拈得鼻孔失卻口。"]'),
('c3fe119d-ff1a-4a2b-94b6-2a029283c090','頌一百則  其三○','釋重顯','宋','宋诗','song-poetry','','[]','劫火光中立問端，衲僧猶滯兩重關。',32,'全唐诗/poet.song.8000.json','["劫火光中立問端，衲僧猶滯兩重關。", "可憐一句隨他語，萬里區區獨往還。"]'),
('e06f5a60-de74-4477-b894-39bf0c80ee42','頌一百則  其三一','釋重顯','宋','宋诗','song-poetry','','[]','鎮州出大蘿蔔，天下衲僧取則。',39,'全唐诗/poet.song.8000.json','["鎮州出大蘿蔔，天下衲僧取則。", "只知自古至今，爭辨鵠白烏黑。", "賊賊，衲僧鼻孔曾拈得。"]'),
('9501475f-28a2-4b50-9184-168bdaf9e6ca','頌一百則  其三二','釋重顯','宋','宋诗','song-poetry','','[]','此錯彼錯，切忌拈卻。',48,'全唐诗/poet.song.8000.json','["此錯彼錯，切忌拈卻。", "四海浪平，百川潮落。", "古策風高十二門，門門有路空蕭索。", "非蕭索，作者好求無病藥。"]'),
('d6334867-5a0b-467f-b8c4-32ede14e7b9e','頌一百則  其三三','釋重顯','宋','宋诗','song-poetry','','[]','斷際全機繼後蹤，持來何必在從容。',32,'全唐诗/poet.song.8000.json','["斷際全機繼後蹤，持來何必在從容。", "巨靈擡手無多子，分破華山千萬重。"]'),
('00e3f550-2956-403c-a447-3c4b95836789','頌一百則  其三四','釋重顯','宋','宋诗','song-poetry','','[]','團團珠繞玉珊珊，馬載驢駝上鐵船。',32,'全唐诗/poet.song.8000.json','["團團珠繞玉珊珊，馬載驢駝上鐵船。", "分付海山無事客，釣鼇時下一棬攣。"]'),
('bccb015d-9ee7-418f-8c13-3d01654da89d','頌一百則  其三五','釋重顯','宋','宋诗','song-poetry','','[]','出草入草，誰解尋討。',53,'全唐诗/poet.song.8000.json','["出草入草，誰解尋討。", "白雲重重，紅日杲杲。", "左顧無暇，右眄已老。", "君不見寒山子，行太早。", "十年歸不得，忘卻來時道。"]'),
('3f6414b0-00b9-460f-9079-56b8c3acf3cb','頌一百則  其三六','釋重顯','宋','宋诗','song-poetry','','[]','千峰盤屈色如藍，誰謂文殊是對譚。',32,'全唐诗/poet.song.8000.json','["千峰盤屈色如藍，誰謂文殊是對譚。", "堪笑清涼多少衆，前三三與後三三。"]'),
('88e14bbf-01f8-4ce8-9900-8e41b5c74a6a','頌一百則  其三七','釋重顯','宋','宋诗','song-poetry','','[]','大地絕纖埃，何人眼不開。',44,'全唐诗/poet.song.8000.json','["大地絕纖埃，何人眼不開。", "始隨芳草去，又逐落花迴。", "羸鶴翹寒木，狂猿嘯古臺。", "長沙無限意。", "咄。"]'),
('ec96b750-c327-4517-b63d-81a33f0e5397','頌一百則  其三八','釋重顯','宋','宋诗','song-poetry','','[]','三界無法，何處求心。',36,'全唐诗/poet.song.8000.json','["三界無法，何處求心。", "白雲爲蓋，流泉作琴。", "一曲兩曲無人會，雨過夜堂秋水深。"]'),
('819f2534-2bf0-4231-ab6f-262e2bef26a6','頌一百則  其三九','釋重顯','宋','宋诗','song-poetry','','[]','擒得盧陂跨鐵牛，三玄戈甲未輕酬。',32,'全唐诗/poet.song.8000.json','["擒得盧陂跨鐵牛，三玄戈甲未輕酬。", "楚王城畔朝宗水，喝下曾令卻倒流。"]'),
('121ed93d-7834-4a77-a1b4-e97dc9246cc1','頌一百則  其四○','釋重顯','宋','宋诗','song-poetry','','[]','花藥欄，莫顢頇，星在秤兮不在盤。',32,'全唐诗/poet.song.8000.json','["花藥欄，莫顢頇，星在秤兮不在盤。", "便與麽，太無端，金毛師子大家看。"]'),
('9ad36679-9333-4eac-a957-239a47e1d72a','頌一百則  其四一','釋重顯','宋','宋诗','song-poetry','','[]','聞見覺知非一一，山河不在鏡中觀。',32,'全唐诗/poet.song.8000.json','["聞見覺知非一一，山河不在鏡中觀。", "霜天月落夜將半，誰共澄潭照影寒。"]'),
('98eaab9d-3fe0-4339-a167-4e18acfb85ad','頌一百則  其四二','釋重顯','宋','宋诗','song-poetry','','[]','活中有眼還同死，藥忌何須鑒作家。',32,'全唐诗/poet.song.8000.json','["活中有眼還同死，藥忌何須鑒作家。", "古佛尚言曾未到，不知誰解撒塵沙。"]'),
('5573a127-8cc6-49e1-9b97-262f0604fc58','頌一百則  其四三','釋重顯','宋','宋诗','song-poetry','','[]','雪材打，雪材打，龐老機關沒可把。',44,'全唐诗/poet.song.8000.json','["雪材打，雪材打，龐老機關沒可把。", "天上人閑不自知，眼裏耳裏絕蕭灑。", "蕭灑絕，碧眼胡僧難辨別。"]'),
('c3250ce8-b60f-45ea-b85b-0c169193ad7e','頌一百則  其四四','釋重顯','宋','宋诗','song-poetry','','[]','垂手還同萬仞崖，正偏何心在安排。',32,'全唐诗/poet.song.8000.json','["垂手還同萬仞崖，正偏何心在安排。", "琉璃古殿照明月，忍俊韓獹空上階。"]'),
('cd2560d7-eace-4de0-b4c8-e0fd682107e5','頌一百則  其四五','釋重顯','宋','宋诗','song-poetry','','[]','一拽石，二般土，發機須是千鈞弩。',48,'全唐诗/poet.song.8000.json','["一拽石，二般土，發機須是千鈞弩。", "象骨老師曾輥毬，爭似禾山解打鼓。", "報君知，莫莽鹵，甜者甜兮苦者苦。"]'),
('36995b1c-2cf9-4918-9d4a-5d4f95c73a0e','頌一百則  其四六','釋重顯','宋','宋诗','song-poetry','','["\u897f\u6e56"]','編辟曾挨老古錐，七斤衫重幾人知。',32,'全唐诗/poet.song.8000.json','["編辟曾挨老古錐，七斤衫重幾人知。", "如今拋擲西湖裏，下載清風付與誰。"]'),
('981c4a5e-c7c3-4696-a210-ce7d94eed8bf','頌一百則  其四七','釋重顯','宋','宋诗','song-poetry','','[]','虛堂雨滴聲，作者難酬對。',36,'全唐诗/poet.song.8000.json','["虛堂雨滴聲，作者難酬對。", "若謂曾入流，依前還不會。", "會不會，南山北山轉滂霈。"]'),
('5300e9db-3c2a-4454-a1f4-1a4e9bb1e7ac','頌一百則  其四八','釋重顯','宋','宋诗','song-poetry','','[]','一二三，四六六，碧眼胡僧數不足。',48,'全唐诗/poet.song.8000.json','["一二三，四六六，碧眼胡僧數不足。", "少林謾道付神光，卷衣又說歸天竺。", "天竺茫茫無處尋，夜來卻對乳峰宿。"]'),
('499570d3-eb03-404e-8a85-88d7b971e0c2','頌一百則  其四九','釋重顯','宋','宋诗','song-poetry','','[]','來問若成風，應機非善巧。',40,'全唐诗/poet.song.8000.json','["來問若成風，應機非善巧。", "可悲獨眼龍，曾未呈牙爪。", "牙爪開，生雲雷，逆水之波經幾迴。"]'),
('9cf3e36b-4e6a-4bd6-aeda-76773b0a2850','頌一百則  其五○','釋重顯','宋','宋诗','song-poetry','','[]','透網金鱗，休云滯水。',48,'全唐诗/poet.song.8000.json','["透網金鱗，休云滯水。", "搖乾蕩坤，振鬣擺尾。", "千尺鯨噴洪浪飛，一聲雷振清飇起。", "清飇起，天上人間知幾幾。"]'),
('fd746197-11ec-4de7-8183-d811db76fa83','頌一百則  其五一','釋重顯','宋','宋诗','song-poetry','','[]','鉢裏飯，桶裏水，多口阿師難下嘴。',48,'全唐诗/poet.song.8000.json','["鉢裏飯，桶裏水，多口阿師難下嘴。", "北斗南星位不殊，白浪滔天平地起。", "擬不擬，止不止，箇箇無裩長者子。"]'),
('58984c26-dfb5-4d3f-8abe-6fa8345cec96','頌一百則  其五二','釋重顯','宋','宋诗','song-poetry','','[]','末後句，爲君說，明暗雙雙底時節。',60,'全唐诗/poet.song.8000.json','["末後句，爲君說，明暗雙雙底時節。", "同條生也共相知，不同條死還殊絕。", "還殊絕，黄頭碧眼須甄別。", "南北東西歸去來，夜深同看千巖雪。"]'),
('7a58fe3b-4cc5-411b-af10-fe4e28c15bed','頌一百則  其五三','釋重顯','宋','宋诗','song-poetry','','[]','孤危不立道方高，入海還須釣巨鼇。',32,'全唐诗/poet.song.8000.json','["孤危不立道方高，入海還須釣巨鼇。", "堪笑同時灌溪老，解云劈箭亦徒勞。"]'),
('4718f966-4618-4c07-b6cd-54611abf2e0e','頌一百則  其五四','釋重顯','宋','宋诗','song-poetry','','[]','野鴨子，知何許，馬祖見來相共語。',42,'全唐诗/poet.song.8000.json','["野鴨子，知何許，馬祖見來相共語。", "話盡山雲海月情，依前不會還飛去。", "欲飛去，卻把住道道。"]'),
('abeedc27-778a-4120-8a60-b1bc56f27b08','頌一百則  其五五','釋重顯','宋','宋诗','song-poetry','','[]','虎頭虎尾一時收，凜凜威風四百州。',24,'全唐诗/poet.song.8000.json','["虎頭虎尾一時收，凜凜威風四百州。", "卻問不知何太險。"]'),
('aeaceb47-4869-4ea2-92e2-9c9bf11f4c67','頌一百則  其五六','釋重顯','宋','宋诗','song-poetry','','[]','兔馬有角，牛羊無角。',48,'全唐诗/poet.song.8000.json','["兔馬有角，牛羊無角。", "絕毫絕釐，如山如嶽。", "黄金靈骨今猶在，白浪滔天何處著。", "無處著，隻履西歸曾失卻。"]'),
('6e2ac410-fd69-49d4-9acb-142a56c787e8','頌一百則  其五七','釋重顯','宋','宋诗','song-poetry','','[]','與君放出關中主，放箭之徒莫莽鹵。',66,'全唐诗/poet.song.8000.json','["與君放出關中主，放箭之徒莫莽鹵。", "取箇眼兮耳必聾，捨箇耳兮目雙瞽。", "可憐一鏃破三關，的的分明箭後路。", "君不見玄沙有言兮，大丈夫先天爲心祖。"]'),
('f609b209-7cd8-444a-b232-36f84187652d','頌一百則  其五八','釋重顯','宋','宋诗','song-poetry','','[]','似海之深，如山之固。',35,'全唐诗/poet.song.8000.json','["似海之深，如山之固。", "蚊虻弄空裏猛風，螻蟻撼於鐵柱。", "揀兮擇兮，當軒布鼓。"]'),
('007a5488-eb1a-4205-a29e-55a95760c164','頌一百則  其五九','釋重顯','宋','宋诗','song-poetry','','[]','象王嚬呻，師子哮吼。',30,'全唐诗/poet.song.8000.json','["象王嚬呻，師子哮吼。", "無味之譚，塞斷人口。", "南北東西，烏飛兔走。"]'),
('e9872f84-df4a-4bb6-a996-b5659e8dc691','頌一百則  其六○','釋重顯','宋','宋诗','song-poetry','','[]','水灑不著，風吹不入。',36,'全唐诗/poet.song.8000.json','["水灑不著，風吹不入。", "虎步龍行，鬼號神泣。", "頭長三尺知是誰，相對無言獨足立。"]'),
('8b39ed94-bfdf-46e3-b6f7-2e7ed07cba60','頌一百則  其六一','釋重顯','宋','宋诗','song-poetry','','[]','拄杖子，吞乾坤，徒說桃花浪奔。',73,'全唐诗/poet.song.8000.json','["拄杖子，吞乾坤，徒說桃花浪奔。", "燒尾者不在拏雲攫霧，曝鰓者何必喪膽設魂。", "拈了也，聞不聞，直須灑灑落落，休更紛紛紜紜。", "七十二棒且輕恕，一百五十難放君。"]'),
('0f42bbd6-c48a-423c-a00b-b7b7aeab2114','頌一百則  其六二','釋重顯','宋','宋诗','song-poetry','','[]','野老從教不展眉，且圖家國立雄基。',32,'全唐诗/poet.song.8000.json','["野老從教不展眉，且圖家國立雄基。", "謀臣猛將今何在，萬里風清祇自知。"]'),
('e0ba38af-e33c-4e76-9f93-b7c2c67175cd','頌一百則  其六三','釋重顯','宋','宋诗','song-poetry','','[]','看看，古岸何人把釣竿。',27,'全唐诗/poet.song.8000.json','["看看，古岸何人把釣竿。", "雲冉冉，水漫漫，明月蘆花君自看。"]'),
('0a3e82c8-1319-43c2-b4f7-9296afceea49','頌一百則  其六四','釋重顯','宋','宋诗','song-poetry','','[]','兩堂俱是杜禪和，撥動煙塵不奈何。',32,'全唐诗/poet.song.8000.json','["兩堂俱是杜禪和，撥動煙塵不奈何。", "賴得南泉能舉令，一刀兩段任偏頗。"]'),
('2e888183-066e-40b5-87da-513ab683e5bf','頌一百則  其六五','釋重顯','宋','宋诗','song-poetry','','[]','公案圓來問趙州，長安城裏任閑遊。',32,'全唐诗/poet.song.8000.json','["公案圓來問趙州，長安城裏任閑遊。", "草鞋閉戴無人會，歸到家山便即休。"]'),
('7ceb8d8e-9243-4191-b028-a7cddb858a0c','頌一百則  其六六','釋重顯','宋','宋诗','song-poetry','','[]','機輪曾未轉，轉必兩頭走。',65,'全唐诗/poet.song.8000.json','["機輪曾未轉，轉必兩頭走。", "明鏡忽臨臺，當下分妍醜。", "妍醜分兮迷雲開，慈門何處生塵埃。", "因思良馬窺鞭影，千里追風喚得過。", "喚得迴，鳴指三下。"]'),
('d04ee619-4b59-4b17-949c-b6becbb4e751','頌一百則  其六七','釋重顯','宋','宋诗','song-poetry','','[]','問曾不知，答還不會。',64,'全唐诗/poet.song.8000.json','["問曾不知，答還不會。", "月冷風高，古巖寒檜。", "堪笑路逢達道人，不將語默對。", "手把白玉鞭，驪珠盡擊碎。", "不擊碎，增瑕纇，國有憲章，三千條罪。"]'),
('f85b7051-cdad-4f2c-b7ce-b0c4f5dcb85e','頌一百則  其六八','釋重顯','宋','宋诗','song-poetry','','[]','南山雲，北山雨，四七二三面相睹。',48,'全唐诗/poet.song.8000.json','["南山雲，北山雨，四七二三面相睹。", "新罷國裏曾上堂，大唐國裏未打鼓。", "苦中樂，樂中苦，誰道黄金如糞土。"]'),
('f03d3244-8b11-4a7e-93fe-641e52d40818','頌一百則  其六九','釋重顯','宋','宋诗','song-poetry','','[]','黄巢過後曾收劍，大笑還應作者知。',32,'全唐诗/poet.song.8000.json','["黄巢過後曾收劍，大笑還應作者知。", "三十山藤且輕恕，得便宜是落便宜。"]'),
('a0532160-92ba-4c46-9d64-169630d86118','頌一百則  其七○','釋重顯','宋','宋诗','song-poetry','','[]','不向雙林寄此身，卻於梁土惹埃塵。',32,'全唐诗/poet.song.8000.json','["不向雙林寄此身，卻於梁土惹埃塵。", "當時不得志公老，也是恓恓去國人。"]'),
('df76ef6e-1faa-4693-a9b9-7e76ff823691','頌一百則  其七一','釋重顯','宋','宋诗','song-poetry','','[]','雙收雙放若爲宗，騎虎由來要絕功。',32,'全唐诗/poet.song.8000.json','["雙收雙放若爲宗，騎虎由來要絕功。", "笑罷不知何處去，只應千古動悲風。"]'),
('cf80e19c-7391-474a-a037-53d5f66a8d92','頌一百則  其七二','釋重顯','宋','宋诗','song-poetry','','[]','由基箭射猿，遶樹何太直。',39,'全唐诗/poet.song.8000.json','["由基箭射猿，遶樹何太直。", "千箇與箇，是誰曾中的。", "相喚相呼歸去來，曹溪路上休登陟。"]'),
('22e0ae1d-9d34-4e9d-a2bb-cc68eb0abcc8','頌一百則  其七三','釋重顯','宋','宋诗','song-poetry','','[]','卻請和尚道，虎頭生角出荒草。',30,'全唐诗/poet.song.8000.json','["卻請和尚道，虎頭生角出荒草。", "十洲春盡花凋殘，珊瑚樹林日杲杲。"]'),
('07f8b545-e1b8-4536-baac-d8c34b88d3a3','頌一百則  其七四','釋重顯','宋','宋诗','song-poetry','','[]','和尚也併卻，龍蛇陣上看謀略。',30,'全唐诗/poet.song.8000.json','["和尚也併卻，龍蛇陣上看謀略。", "令人長憶李將軍，萬里天邊飛一鶚。"]'),
('a9dec661-3fc7-49aa-b873-f323fa6afe53','頌一百則  其七五','釋重顯','宋','宋诗','song-poetry','','[]','和尚有也未，金毛師子不踞地。',30,'全唐诗/poet.song.8000.json','["和尚有也未，金毛師子不踞地。", "兩兩三三舊路行，大雄山上空彈指。"]'),
('e21a321a-a821-47db-8ac1-67877363ec6a','頌一百則  其七六','釋重顯','宋','宋诗','song-poetry','','[]','藏頭白，海頭黑，明眼衲僧會不得。',48,'全唐诗/poet.song.8000.json','["藏頭白，海頭黑，明眼衲僧會不得。", "馬駒踏殺天下人，臨際者是白拈賊。", "離四句，絕百非，天上人間唯我知。"]'),
('938af550-369a-4d56-b354-710cafc5cb4d','頌一百則  其七七','釋重顯','宋','宋诗','song-poetry','','[]','白雲影裏笑呵呵，兩手持來付與他。',31,'全唐诗/poet.song.8000.json','["白雲影裏笑呵呵，兩手持來付與他。", "若是金毛師子，三千里外見淆訛。"]'),
('63d3d792-299c-4f7e-a441-dce3a74e48d7','頌一百則  其七八','釋重顯','宋','宋诗','song-poetry','','[]','前箭猶輕後箭深，誰云黄葉是黄金。',32,'全唐诗/poet.song.8000.json','["前箭猶輕後箭深，誰云黄葉是黄金。", "曹溪波浪如相似，無限平人被陸沉。"]'),
('c3b70b21-15cf-4563-96bf-f0d7366e44b6','頌一百則  其七九','釋重顯','宋','宋诗','song-poetry','','[]','犀牛扇子用多時，問著元來總不知。',32,'全唐诗/poet.song.8000.json','["犀牛扇子用多時，問著元來總不知。", "無限清風與頭角，盡同雲雨去難追。"]'),
('d6153dbe-9205-406f-abf8-c53d0b66b473','頌一百則  其八○','釋重顯','宋','宋诗','song-poetry','','[]','列聖叢中作者知，法王法令不如斯。',32,'全唐诗/poet.song.8000.json','["列聖叢中作者知，法王法令不如斯。", "會中若有仙陀客，何必文殊下一搥。"]'),
('a57d0445-938a-4a83-a8af-467f93112fff','頌一百則  其八一','釋重顯','宋','宋诗','song-poetry','','[]','呼即易，遣即難，互換機鋒子細看。',52,'全唐诗/poet.song.8000.json','["呼即易，遣即難，互換機鋒子細看。", "劫石固來猶可壞，滄溟深處立須乾。", "烏臼老，烏臼老，幾何般，與他杓柄太無端。"]'),
('6638f0c6-cf50-4ed9-92af-b09f48536dca','頌一百則  其八二','釋重顯','宋','宋诗','song-poetry','','[]','盡機不成瞎，按牛頭喫草。',44,'全唐诗/poet.song.8000.json','["盡機不成瞎，按牛頭喫草。", "四七二三諸祖師，寶器持來成過咎。", "過咎深，無處尋，天上人間同陸沉。"]'),
('52b88a4f-139b-4fb0-87a9-7f3c85a0f81b','頌一百則  其八三','釋重顯','宋','宋诗','song-poetry','','[]','超譚禪客問偏多，縫罅披離見也麽。',32,'全唐诗/poet.song.8000.json','["超譚禪客問偏多，縫罅披離見也麽。", "餬餅𡎺來猶不住，至今天下有淆訛。"]'),
('5899deef-7fab-48bf-94d2-e4627e18cfd6','頌一百則  其八四','釋重顯','宋','宋诗','song-poetry','','[]','了事衲僧消一箇，長連床上展脚臥。',32,'全唐诗/poet.song.8000.json','["了事衲僧消一箇，長連床上展脚臥。", "夢中曾說悟圓通，香水洗來驀面唾。"]'),
('f25dd8c0-6072-48b3-a583-2a84a70f3771','頌一百則  其八五','釋重顯','宋','宋诗','song-poetry','','[]','投子投子，機輪無阻。',54,'全唐诗/poet.song.8000.json','["投子投子，機輪無阻。", "放一得二，同彼同此。", "可憐無限弄潮人，畢竟還落潮中死。", "忽然活百川，倒流鬧{洱舌}{洱舌}。"]'),
('ac83e2ca-0267-4e33-b32a-c457f77abe0a','頌一百則  其八六','釋重顯','宋','宋诗','song-poetry','','[]','六識無功伸一問，作家曾共辨來端。',32,'全唐诗/poet.song.8000.json','["六識無功伸一問，作家曾共辨來端。", "茫茫急水打毬子，落處不停誰解看。"]'),
('ef1aa211-0846-4b7e-86e7-4a03b09e9cdc','頌一百則  其八七','釋重顯','宋','宋诗','song-poetry','','[]','麈中麈，君看取。',34,'全唐诗/poet.song.8000.json','["麈中麈，君看取。", "下一箭，走三步。", "五步若活，成羣趁虎，正眼從來付獵人。"]'),
('4650a1a3-fb00-4ea3-b86f-779bb617f86f','頌一百則  其八八','釋重顯','宋','宋诗','song-poetry','','[]','咄這維摩老，悲生空懊惱。',60,'全唐诗/poet.song.8000.json','["咄這維摩老，悲生空懊惱。", "臥疾毗耶離，全身太枯槁。", "七佛祖師來，一室且頻掃。", "請問不二門，當時便靠倒。", "不靠倒，金毛師子無處討。"]'),
('baa5ced6-c8c8-4925-80bc-34ee711f5a47','頌一百則  其八九','釋重顯','宋','宋诗','song-poetry','','[]','見之不取，思之千里。',55,'全唐诗/poet.song.8000.json','["見之不取，思之千里。", "好箇班班，爪牙未備。", "君不見大雄山下忽相逢，落落聲光皆振地。", "大丈夫，見也無，收虎尾兮捋虎鬚。"]'),
('3f2e0639-e5e6-4422-a82d-e150ab3cf897','頌一百則  其九○','釋重顯','宋','宋诗','song-poetry','','[]','自照列孤明，爲君通一線。',36,'全唐诗/poet.song.8000.json','["自照列孤明，爲君通一線。", "花謝樹無影，看時誰不見。", "見不見，倒騎牛兮入佛殿。"]'),
('f5329143-447a-4928-b861-6443ac55edcc','頌一百則  其九一','釋重顯','宋','宋诗','song-poetry','','[]','盡大地是藥，古今何太錯。',35,'全唐诗/poet.song.8000.json','["盡大地是藥，古今何太錯。", "閉門不造車，通途自寥廓。", "錯錯，鼻孔遼天亦穿卻。"]'),
('6564e339-919c-4053-8884-7ef1cbb15089','頌一百則  其九二','釋重顯','宋','宋诗','song-poetry','','[]','盲聾音啞，杳絕機宜。',50,'全唐诗/poet.song.8000.json','["盲聾音啞，杳絕機宜。", "天上天下，堪笑堪悲。", "離朱不辨正色，師曠豈識玄絲。", "爭如獨坐虛窗下，葉落花開自有時。"]'),
('503a16f8-3247-40f1-8e72-1d1139bb78ae','頌一百則  其九三','釋重顯','宋','宋诗','song-poetry','','[]','徧身是，通身是，拈來猶較十萬里。',69,'全唐诗/poet.song.8000.json','["徧身是，通身是，拈來猶較十萬里。", "展翅崩騰六合雲，搏風鼓蕩四溟水。", "是何埃塏兮忽生，那箇毫釐兮未止。", "君不見網珠垂範影重重，棒頭手眼從何起。", "喝。"]'),
('39fa9f38-ffc9-4446-b520-5233087dade4','頌一百則  其九四','釋重顯','宋','宋诗','song-poetry','','[]','一片虛凝絕謂情，天人從此見空生。',32,'全唐诗/poet.song.8000.json','["一片虛凝絕謂情，天人從此見空生。", "蚌含玄兔深深意，曾與禪家作戰爭。"]'),
('c8d4ee9f-8b7c-4738-ac92-f751cb4582e6','頌一百則  其九五','釋重顯','宋','宋诗','song-poetry','','[]','全象全牛翳不殊，從來作者共名模。',32,'全唐诗/poet.song.8000.json','["全象全牛翳不殊，從來作者共名模。", "如今要見黄頭老，剎剎塵塵在半途。"]'),
('a7305dda-7a44-4db7-9c29-3d57102516fd','頌一百則  其九六','釋重顯','宋','宋诗','song-poetry','','[]','頭兮第一，第二臥龍。',46,'全唐诗/poet.song.8000.json','["頭兮第一，第二臥龍。", "不鑒止水，無處有月。", "波澄有處，無風浪起。", "稜禪客，稜禪客，三月禹門遭點額。"]'),
('877e699e-d19f-449d-ad31-7b1a1cd103ef','頌一百則  其九七','釋重顯','宋','宋诗','song-poetry','','[]','泥佛不度水，神光照天地。',72,'全唐诗/poet.song.8000.json','["泥佛不度水，神光照天地。", "立雪如未休，何人不雕僞。", "金佛不度爐，人來訪紫胡。", "牌中數箇字，清風何處無。", "木佛不度火，常思破竈墮。", "杖子忽擊著，方知辜負我。"]'),
('b129d140-913f-4b2a-88e5-fd6975f9ebfa','頌一百則  其九八','釋重顯','宋','宋诗','song-poetry','','[]','明珠在掌，有功者賞。',40,'全唐诗/poet.song.8000.json','["明珠在掌，有功者賞。", "胡漢不來，全無伎倆。", "伎倆既無，波旬失途。", "瞿曇瞿曇，識我也無。"]'),
('fe9bafa3-e9bc-4bc0-ad9d-eda5f93d8434','頌一百則  其九九','釋重顯','宋','宋诗','song-poetry','','[]','禪家流，愛輕薄，滿肚參來用不著。',43,'全唐诗/poet.song.8000.json','["禪家流，愛輕薄，滿肚參來用不著。", "堪悲堪笑天平老，卻謂當初悔行脚。", "錯錯，西院清風頓銷鑠。"]'),
('102114e7-d219-448a-815a-e68e31b4626d','頌一百則  其一○○','釋重顯','宋','宋诗','song-poetry','','[]','一國之師亦強名，南陽獨許振嘉聲。',32,'全唐诗/poet.song.8000.json','["一國之師亦強名，南陽獨許振嘉聲。", "大唐扶得真天子，曾踏毗盧頂上行。"]'),
('23528a30-2df3-40bd-a796-093df96bea07','頌一百則  其一○一','釋重顯','宋','宋诗','song-poetry','','[]','鐵鎚擊碎黄金骨，天地之間更何物。',32,'全唐诗/poet.song.8000.json','["鐵鎚擊碎黄金骨，天地之間更何物。", "三千剎海夜澄澄，不知誰入蒼龍窟。"]'),
('5fe95cbb-b5b4-40cb-9bb7-7d2790016619','頌一百則  其一○二','釋重顯','宋','宋诗','song-poetry','','[]','要平不平，大巧若拙。',47,'全唐诗/poet.song.8000.json','["要平不平，大巧若拙。", "或指或掌，倚天照雪。", "大冶兮磨礱不下，良工兮拂拭未歇。", "別別，珊瑚枝枝撐著月。"]'),
('d2fbaee0-eb6e-4e57-8d5a-ac5e57d9c51b','謝李兵部','蒋堂','宋','宋诗','song-poetry','','[]','黄菌誕邱園，靈貺賁醴泉。',48,'全唐诗/poet.song.8000.json','["黄菌誕邱園，靈貺賁醴泉。", "至和非我召，美化自公宣。", "秀色鄰三逕，幽光被一廛。", "時髦秉筆者，爲我列羣編。"]'),
('46283d3f-0665-4244-811c-aa79b5560b3d','前題','蒋堂','宋','宋诗','song-poetry','','[]','使君有意飾門閭，雅爲靈芝揭表初。',32,'全唐诗/poet.song.8000.json','["使君有意飾門閭，雅爲靈芝揭表初。", "招隱溪邊往還者，從茲認得野人居。"]'),
('2145772a-3dad-4a97-87dc-82e95915f0e8','隱圃','蒋堂','宋','宋诗','song-poetry','','[]','雅得莵裘地，清宜隱者心。',48,'全唐诗/poet.song.8000.json','["雅得莵裘地，清宜隱者心。", "綠葵才有甲，青桂漸成陰。", "獨曳山筇往，無勞車駕尋。", "湛然常寂處，水月一菴深。"]'),
('7f02bb71-cdbe-42c0-bb45-ad91a3ebf715','溪館二首  其一','蒋堂','宋','宋诗','song-poetry','','[]','年來納組去，林下得身還。',48,'全唐诗/poet.song.8000.json','["年來納組去，林下得身還。", "泚泚清流處，重重碧樹間。", "淵魚樂且靜，庭鶴壽而閑。", "粗有淮安趣，誰同賦小山。"]'),
('c5b59b60-8cb8-4b74-9bd0-effe2cda0bbf','溪館二首  其二','蒋堂','宋','宋诗','song-poetry','','[]','野意本自遂，茲溪稱獨醒。',48,'全唐诗/poet.song.8000.json','["野意本自遂，茲溪稱獨醒。", "雲蘿環靜室，水石照疏櫺。", "殺竹編書古，紉蘭作佩聲。", "王通昔不遇，時亦坐汾亭。"]'),
('dc6d072b-0225-497c-96f0-fdcd182c7e68','南湖臺三首  其一','蒋堂','宋','宋诗','song-poetry','','[]','危臺竹樹間，湖水伴身閑。',48,'全唐诗/poet.song.8000.json','["危臺竹樹間，湖水伴身閑。", "清淺採香徑，方圓明月灣。", "放魚隨物性，載石作家山。", "自喜歸休早，今勝賀老還。"]'),
('8f23e762-9a28-404b-b3fc-6083b544cbdd','南湖臺三首  其二','蒋堂','宋','宋诗','song-poetry','','[]','嶢榭水中央，茲爲隱遯鄉。',48,'全唐诗/poet.song.8000.json','["嶢榭水中央，茲爲隱遯鄉。", "小園香寂寂，一派曉泱泱。", "煙草碧彌岸，霜桃紅壓墻。", "鴟夷倘在此，未必入滄浪。"]'),
('4f7cf5e5-b22e-4778-9dac-ed274bd219c2','南湖臺三首  其三','蒋堂','宋','宋诗','song-poetry','','[]','水次揭危亭，煙堤四面平。',48,'全唐诗/poet.song.8000.json','["水次揭危亭，煙堤四面平。", "栽蘆延宿鷺，種柳待啼鶯。", "雪霽清流漲，風來夜艇横。", "輕肥莫臨顧，我老懶逢迎。"]'),
('b4dd1b6c-925c-4449-8d9b-65f017722910','和梅摯北池十詠  其一','蒋堂','宋','宋诗','song-poetry','','[]','池上有虚閣，翬簷迅若翔。',48,'全唐诗/poet.song.8000.json','["池上有虚閣，翬簷迅若翔。", "百壺多盛集，四座仰惟良。", "蘚印文綦綠，蓮依桂楫香。", "何由陪嘯咏，敷袵納微凉。"]'),
('75945a2d-6686-4b6b-bf71-06c277380e71','和梅摯北池十詠  其二','蒋堂','宋','宋诗','song-poetry','','[]','池上有奇桂，青青歲紀深。',48,'全唐诗/poet.song.8000.json','["池上有奇桂，青青歲紀深。", "舊枝憐茂植，時亦欠清吟。", "夕月漏孤影，秋霜滋勁心。", "今方遇真賞，風什播瑤音。"]'),
('3cff6c0d-176e-46e1-9eda-8cdb137eb452','和梅摯北池十詠  其三','蒋堂','宋','宋诗','song-poetry','','[]','池上有孤島，影搖波底天。',48,'全唐诗/poet.song.8000.json','["池上有孤島，影搖波底天。", "蓬壺欣彷彿，仙客得留連。", "岸草襯丹轂，灘蘆隈畫船。", "羨君休澣日，寄傲一尊前。"]'),
('c35ab4b3-709a-4fc2-9042-4899c8082362','和梅摯北池十詠  其四','蒋堂','宋','宋诗','song-poetry','','[]','池上有修竹，遙聞手自栽。',48,'全唐诗/poet.song.8000.json','["池上有修竹，遙聞手自栽。", "幾因風韻響，時感隼旟來。", "粉籜經梅脱，虬根遇石回。", "嬋娟綠陰下，小閣爲誰開。"]'),
('49118fc5-bd74-44ac-ab8f-b87531c41699','和梅摯北池十詠  其五','蒋堂','宋','宋诗','song-poetry','','[]','池上有垂柳，煙籠濯濯枝。',48,'全唐诗/poet.song.8000.json','["池上有垂柳，煙籠濯濯枝。", "芳根逢茂育，老翠勝平時。", "體弱因風舞，詞清入笛吹。", "金城久不到，遙想歎羈離。"]'),
('96af2116-e8da-461e-9961-c2146cdbeba1','和梅摯北池十詠  其六','蒋堂','宋','宋诗','song-poetry','','[]','池上有叢菊，繁英滿舊蹊。',48,'全唐诗/poet.song.8000.json','["池上有叢菊，繁英滿舊蹊。", "金刀惜頻翦，粉蜨得幽棲。", "醉卉誰同插，香牋手自題。", "遙思清賞處，野步岸東西。"]'),
('62e61eb6-2f2e-49c2-ba9f-3cf05ac292b1','和梅摯北池十詠  其七','蒋堂','宋','宋诗','song-poetry','','[]','池上有時釣，閑忘侍從身。',48,'全唐诗/poet.song.8000.json','["池上有時釣，閑忘侍從身。", "波平方浸月，吏退閴無人。", "藻映魴魚尾，風搖獨繭綸。", "一亭容膝地，雅飾免荒蓁。"]'),
('b39aded0-a714-4475-9a9e-313d9c6a2c5d','和梅摯北池十詠  其八','蒋堂','宋','宋诗','song-poetry','','[]','池上有時宴，笙簧沸欲凝。',48,'全唐诗/poet.song.8000.json','["池上有時宴，笙簧沸欲凝。", "歡多漏移刻，坐久月和燈。", "席客詠持蟹，女倡歌采菱。", "醉來忘萬事，風靜水波澄。"]'),
('774c52e1-1b2a-40b1-8726-9377c6d386fe','和梅摯北池十詠  其九','蒋堂','宋','宋诗','song-poetry','','[]','池上有雛鶴，來從淮水壖。',48,'全唐诗/poet.song.8000.json','["池上有雛鶴，來從淮水壖。", "舊巢離海樹，清唳入吳天。", "骨峭翹霜月，翎疏刷野泉。", "使君宜得伴，仙格本千年。"]'),
('984e4b6a-4baf-448d-ae17-b59e646f8dfc','和梅摯北池十詠  其一○','蒋堂','宋','宋诗','song-poetry','','[]','池上有馴鹿，亭臺深處行。',48,'全唐诗/poet.song.8000.json','["池上有馴鹿，亭臺深處行。", "長隨熊軾慣，且免兔罝驚。", "遙草眠多穏，流泉飲亦清。", "寸岑有靈囿，可使遂微生。"]'),
('f05c327b-b57b-44c9-9d55-820215214e73','詠金竹','蒋堂','宋','宋诗','song-poetry','','[]','百鎰先寒一徑深，潛疑造化鑄成林。',32,'全唐诗/poet.song.8000.json','["百鎰先寒一徑深，潛疑造化鑄成林。", "貪夫或有凭闌者，不見修篁但見金。"]'),
('abbf8e37-cbe6-49bf-b2fa-5626304d8d43','吳淞江','蒋堂','宋','宋诗','song-poetry','','[]','江人見我謂誰何，行李無羈野意多。',64,'全唐诗/poet.song.8000.json','["江人見我謂誰何，行李無羈野意多。", "六幅青帆趁潮去，一罇白酒扣舷歌。", "沙邊歷歷辨雲樹，島外濺濺弄月波。", "興盡歸來還更喜，舞鷗相送入煙蘿。"]'),
('c36c9a61-7cb1-42cb-9823-febe7c170de8','題山亭','蒋堂','宋','宋诗','song-poetry','','[]','山亭深處枕清溪，萬目回環盡翠微。',64,'全唐诗/poet.song.8000.json','["山亭深處枕清溪，萬目回環盡翠微。", "梅蕚破香知臘近，柳梢含綠認春歸。", "風前列嶂琴三疊，雪後羣山玉四圍。", "顧我此來盤礴久，塵勞瀟灑頓忘機。"]'),
('57026fb8-cf08-4aa8-843f-0d8503602618','過葛墟讀蔣冽大宗碑','蒋堂','宋','宋诗','song-poetry','','[]','天寶年中立此碑，軒裳鱗次美當時。',32,'全唐诗/poet.song.8000.json','["天寶年中立此碑，軒裳鱗次美當時。", "自從寂絕牛頭夢，力振家聲合在茲。"]'),
('af1b5af3-6ab8-491d-8385-446404b3d77c','遊松江  其一','蒋堂','宋','宋诗','song-poetry','','[]','曙光東向欲曨明，漁艇縱横暎遠汀。',64,'全唐诗/poet.song.8000.json','["曙光東向欲曨明，漁艇縱横暎遠汀。", "濤面白煙昏落月，嶺頭殘燒混疏星。", "鳴榔莫觸蛟龍睡，舉網時聞魚鼈腥。", "我實宦游無况者，擬來隨爾带笭箵。"]'),
('fb16a197-361b-4bb1-ad28-c7e4b5150f83','遊松江  其二','蒋堂','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','月晃長江上下同，畫橋横截冷光中。',64,'全唐诗/poet.song.8000.json','["月晃長江上下同，畫橋横截冷光中。", "雲頭艶艶開金餅，水面沉沉卧彩虹。", "佛氏解爲銀色界，仙家多住玉壺中。", "地雄景勝言不盡，但欲追隨乘曉風。"]'),
('42a51880-b845-449c-8e1f-670d9e93f9c3','堯峰新井歌','蒋堂','宋','宋诗','song-poetry','','[]','白雲莽莽青山頭，一穴四面飛泉流。',320,'全唐诗/poet.song.8000.json','["白雲莽莽青山頭，一穴四面飛泉流。", "其初山間舊井涸，枯腸燥吻海衆羞。", "於時大士寶雲者，頤指土脈智慮周。", "山靈所感道心爽，檀施聿來工力鳩。", "雲鍤齊下遠雷動，石火內擊飛星稠。", "百尺虚空廓地表，一泓清冽呀深幽。", "人疑從天隨月窟，或問何處移龍湫。", "次則其徒駭殊勝，競持應器嘗甘柔。", "饑狖連臂喜跳擲，渴鳥引喙鳴鉤輈。", "碧甃光中轆轤曉，銀床側畔梧桐秋。", "寶方金地互相映，谷鮒坎蛙難此留。", "傍睨江形小衣带，下窺湖面卑浮漚。", "何茲鑿飲有功利，一掬入口醍醐優。", "熱者濯之昏鈍决，病者沃之沈痼瘳。", "而我時邀墨客去，松澗遠挈都籃游。", "凈瓶汲引試香荈，雅具羅列無腥甌。", "比之玉乳不差别，誚彼鍊丹多謬悠。", "今茲泉眼在魯塢，所喜雲液鄰莵裘。", "苧翁既往乏鑒者，水記未載予將修。", "此山此井永不廢，此歌其庶傳南州。"]'),
('45fa1bd9-8304-47b6-b32a-a60f26289d04','再題半峰亭','蒋堂','宋','宋诗','song-poetry','','[]','何名半峰亭，堯峰路之半。',72,'全唐诗/poet.song.8000.json','["何名半峰亭，堯峰路之半。", "遊客趨層崖，斗上多股戰。", "寶雲構茲軒，接引心不倦。", "所冀冠蓋來，少休松石畔。", "雄視金仙居，巍乎倚雲漢。", "自此更攀緣，須臾跡彼岸。"]'),
('54797f16-50d5-4b3c-9323-071748fb2195','絕句','蒋堂','宋','宋诗','song-poetry','','["\u592a\u6e56"]','歸來深隱太湖濱，天與扶持百歲身。',32,'全唐诗/poet.song.8000.json','["歸來深隱太湖濱，天與扶持百歲身。", "雖是浮雲隔雙闕，丹心愛戴在君親。"]'),
('3a1ad3c6-d311-485f-94ed-f58f4f880c40','吳江橋','蒋堂','宋','宋诗','song-poetry','','[]','雁翅橋橫五湖北，翬飛亭屹大江心。',32,'全唐诗/poet.song.8000.json','["雁翅橋橫五湖北，翬飛亭屹大江心。", "魚龍淵藪風月窟，若比廣寒宮更深。"]'),
('230fb51c-d961-49fe-a31e-4ac43197b82e','閔山','蒋堂','宋','宋诗','song-poetry','','[]','東南亘羣山，形氣成斷續。',240,'全唐诗/poet.song.8000.json','["東南亘羣山，形氣成斷續。", "茲山窮嶄絕，孤峙越之腹。", "鬰蒼瞰城闉，勝秀爲民福。", "所宜禁樵蘇，主者在嚴肅。", "不知平昔時，誰氏來班錄。", "私庖計薪爨，無時伐良木。", "官膳利貨財，彌年翦修竹。", "忽忽事斧斤，丁丁響川谷。", "萬葉壞密幄，千竿倒寒玉。", "輪囷無完枝，檀欒鮮遺族。", "戕賊殊未厭，峰巒翠將禿。", "鶴侶怨且驚，雲容慘以惡。", "非唯挫生意，仰乃傷雅俗。", "王者有仁恩，行葦亦沾沐。", "嗟嗟若人者，忍不思化育。", "今予剖信符，於茲憩丹轂。", "謂山豈無靈，胡爲人所黷。", "呼吏對泉石，申禁護林麓。", "庶幾養翹英，勿使罹殘酷。", "來者賢使君，斯言願爲復。"]'),
('9ee0f6ed-1f94-45da-9480-6b90528d5cc3','題曲水閣','蒋堂','宋','宋诗','song-poetry','','[]','危構跨大淵，淪清滌世紛。',48,'全唐诗/poet.song.8000.json','["危構跨大淵，淪清滌世紛。", "飛湍逢石轉，漱玉隔山聞。", "影亂林花落，叢幽澗草薰。", "茲爲禊飲地，何羨右將軍。"]'),
('1ec0e737-de68-40cc-aeca-96430e53315b','諸官詩成因書二韻於後','蒋堂','宋','宋诗','song-poetry','','[]','一派西園曲水聲，水邊終日會冠纓。',32,'全唐诗/poet.song.8000.json','["一派西園曲水聲，水邊終日會冠纓。", "幾多詩筆無停綴，不似當年有罰觥。"]'),
('1e7e3c12-e702-4679-b2d1-5b873456932b','寄題望湖樓','蒋堂','宋','宋诗','song-poetry','','[]','城上危樓勢孤峙，樓頭盡見湖中水。',128,'全唐诗/poet.song.8000.json','["城上危樓勢孤峙，樓頭盡見湖中水。", "水色澄明游者多，古來雅以鑒爲比。", "家家畫舫日斜歸，處處菱歌煙際起。", "清漣蒙潤一都會，碧底涵空三百里。", "溥哉利及鎮東人，而我常嗟馬臻死。", "今滋史君多感慨，所以望湖心不已。", "頻登雉堞追古往，盛集賓朋爲宴喜。", "樓南極目芙蓉花，萬疊紅英照千騎。"]'),
('18203ba5-d32b-461b-b2e6-f276f8fdd7ab','寄題西園','蒋堂','宋','宋诗','song-poetry','','[]','西園昔日多遊從，迴流屢泛卮酒空。',128,'全唐诗/poet.song.8000.json','["西園昔日多遊從，迴流屢泛卮酒空。", "前亭後亭草茵軟，曉景晚景煙嵐融。", "角巾蕭灑竹林際，履綦來往花陰中。", "時方偃蕃適四體，不料游宦如孤蓬。", "數移五馬臨大屏，幾悵二毛成老翁。", "昨去鄰封亦甚邇，祇限一水無由通。", "錦城此舉又遠適，流觴雅會何時同。", "錢塘山色望不見，稽山況在錢塘東。"]'),
('8b2345f3-a8be-46ae-ba9d-8f29d2297398','棹歌','蒋堂','宋','宋诗','song-poetry','','[]','湖之水兮碧泱泱，環越境兮潤吳疆。',163,'全唐诗/poet.song.8000.json','["湖之水兮碧泱泱，環越境兮潤吳疆。", "蒲蠃所萃兮雁鶩羣翔，朝有行艫兮暮有歸艎。", "茭牧狎至兮漁采相望，溉我田疇兮生我稻粱。", "我歲穰熟兮我煉樂康，馬侯之功兮其誰敢忘。", "蓴絲紫兮箭筍黄，取其潔兮薦侯堂。", "醆斝具兮簫鼓張，日晻晻兮山蒼蒼。", "侯之來兮雲飛揚，隔微波兮潛幽光。", "念山可爲席兮湖不可荒，惟侯之靈一貧如洗與流比長。", "萬斯年兮福吾鄉，樂吾生兮徜徉。"]'),
('799dd1c6-f7e6-46f2-b431-d95e4871a035','飛來山','蒋堂','宋','宋诗','song-poetry','','[]','有山昔飛來，神怪安可測。',276,'全唐诗/poet.song.8000.json','["有山昔飛來，神怪安可測。", "萬壑鼓風雷，千巖爲羽翼。", "胡爲忽移徙，到此無傾側。", "靈越得奇峰，瑯琊失遺跡。", "煙雲隨而至，杉篁古所植。", "如何草創時，躺作瞿曇宅。", "聞之有苾蒭，歲久苦刓刻。", "鑿聲響深崖，火燼淬層壁。", "平爲土木基，蔑有蒼翠色。", "金粟千億身，窣堵百餘尺。", "回廊盡複疊，寸地無閑隙。", "一聚紅塵中，萬瓦青煙羃。", "成彼有爲善，斯可長太息。", "我試來尋山，山形俱變易。", "方念此嶄絕，安得如往昔。", "不謂山之足，下落言偃室。", "知是騫翥時，於茲墮巖石。", "屹爾畫疆畔，其誰敢侵蝕。", "隨宜得形勝，觸目見崷崒。", "小桂結沈陰，清露有疏滴。", "巾履日可賞，琴樽雅成飾。", "多謝對幽岑，亦足開煩臆。", "若在祇園間，豈更存餘碧。"]'),
('7dd67038-ad29-4b4c-a4e8-d15752a900d9','題妙喜庵','蒋堂','宋','宋诗','song-poetry','','[]','禪公覽古意裴徊，偶結雲庵向北來。',64,'全唐诗/poet.song.8000.json','["禪公覽古意裴徊，偶結雲庵向北來。", "滿目滄洲圍野景，一枝金策卓秋苔。", "沙邊水鳥銜花至，月下漁人施供迴。", "或記稽山舊徒侶，樵風應爲送浮杯。"]'),
('b3537b8c-9f07-49b1-aec2-a2f103d672f0','送梵才大師歸天台','蒋堂','宋','宋诗','song-poetry','','[]','老被詩名繫此身，思山深去避人羣。',64,'全唐诗/poet.song.8000.json','["老被詩名繫此身，思山深去避人羣。", "寶臺千尺隔江見，清磬一聲歸路聞。", "巖上開扉燈照月，庵前掃地雪和雲。", "終焉此是清涼處，凈住無慚相國文。"]'),
('cb8db34f-2f39-4326-b063-7aab41fbab44','贈陳虞卿','蒋堂','宋','宋诗','song-poetry','','[]','寵秩拜春坊，歸休識慮長。',48,'全唐诗/poet.song.8000.json','["寵秩拜春坊，歸休識慮長。", "掃門卑魏勃，設醴謝元王。", "一水蓴鱸國，羣山橘柚鄉。", "喜君添老杜，煙駕尚徜徉。"]'),
('1b57df29-9732-40e2-9d53-ad577bfe8ab3','過葉道卿侍讀小園','蒋堂','宋','宋诗','song-poetry','','[]','秀野亭連小隱堂，紅蕖綠篠媚滄浪。',32,'全唐诗/poet.song.8000.json','["秀野亭連小隱堂，紅蕖綠篠媚滄浪。", "卞山居士無歸意，卻借吳儂作醉鄉。"]'),
('70005f25-a1f0-4186-b8bf-e9f040c578f8','贈惟政禪師','蒋堂','宋','宋诗','song-poetry','','[]','禪客尋常入舊都，黄牛角上掛瓶盂。',32,'全唐诗/poet.song.8000.json','["禪客尋常入舊都，黄牛角上掛瓶盂。", "有時带笠穿雲去，便好和雲作畫圖。"]'),
('bc8dae46-531d-4baf-a1f7-0b6f16c178b4','清陰館種楠','蒋堂','宋','宋诗','song-poetry','','[]','手植楩楠二千樹，時當慶曆五年春。',32,'全唐诗/poet.song.8000.json','["手植楩楠二千樹，時當慶曆五年春。", "還期莫道空歸去，留得清陰與後人。"]'),
('630d662e-dc45-43bb-9cba-7c9f0003eb9f','東齋','蒋堂','宋','宋诗','song-poetry','','[]','守土無留事，休居有靜齋。',48,'全唐诗/poet.song.8000.json','["守土無留事，休居有靜齋。", "文纔化僭陋，術未迨乖崖。", "古帙書參畫，秋陰竹間槐。", "西人安枕外，聊此息筋骸。"]'),
('864351f1-8887-4911-8c2b-c82d8842d577','題月禪師方丈','蔣堂','宋','宋诗','song-poetry','','[]','我到雲房是有緣，坐移蓮刻聽禪詮。',32,'全唐诗/poet.song.8000.json','["我到雲房是有緣，坐移蓮刻聽禪詮。", "江邊異日人應記，吏部曾來見大顛。"]'),
('a183703c-60f1-44bf-b00f-e97f5ff9ef17','梅','蔣堂','宋','宋诗','song-poetry','','[]','玉骨絕纖塵，前身清凈身。',48,'全唐诗/poet.song.8000.json','["玉骨絕纖塵，前身清凈身。", "無花能伯仲，得雪愈精神。", "冷淡溪橋曉，殷勤江路春。", "寒郊痩島外，同氣更何人。"]'),
('284df099-a313-48ef-bc04-6992a1c23132','虎丘山  其一','蔣堂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','虎丘何爲山，鯨波湧而顯。',288,'全唐诗/poet.song.8000.json','["虎丘何爲山，鯨波湧而顯。", "惟青鎮一隅，峙秀狀無限。", "遙峰乃衆陰，四望拱孤巘。", "上有梵王家，高壓長洲苑。", "遊人接踵來，千里必重趼。", "奔走趨層巓，凌競陟雲棧。", "下瞰洞庭卑，傍睨靈巖淺。", "巍乎屹寶閣，仰之目睛眩。", "中有明光書，麗若日星烜。", "三朝所秘藏，百靈共幽贊。", "茲焉真福庭，瞻者皆色灑。", "敻覺塵世非，恍如化城現。", "塔頂拂彤霞，山脚環青甽。", "北崖宿雪寒，東阜晨曦暖。", "陰森巖腹空，詰屈廊腰轉。", "秋磬落雲端，宵燈耿天半。", "處者病惱蠲，來者鈍根遣。", "予膺邦寄時，所歷遊屐遍。", "不領旌旗行，恐驚禽鹿散。", "捫蘿窮邃深，據檻望平遠。", "尋幽既歡欣，訪古或興嘆。", "葬金墳已隳，淬劍池猶漫。", "冰霰凋古杉，朱丹浮斷簡。", "珍重講石存，譏評鬼詩誕。"]'),
('99b7fd7e-db6d-47fa-bfd2-f04c410f780c','虎丘山  其二','蔣堂','宋','宋诗','song-poetry','','[]','林端生色美新晴，棲閣依山若畫屏。',64,'全唐诗/poet.song.8000.json','["林端生色美新晴，棲閣依山若畫屏。", "石坐最宜人選勝，劍池潛想地遺靈。", "僧窗松竹冬尤茂，寺路煙霞晝亦冥。", "自愧踰年假麾守，一迴方得扣禪扃。"]'),
('49f63be9-1ef7-4c11-a371-ad8572602f0d','梔子花','蔣堂','宋','宋诗','song-poetry','','[]','庭前梔子樹，四畔有椏杈。',24,'全唐诗/poet.song.8000.json','["庭前梔子樹，四畔有椏杈。", "未結黄金子，先開白玉花。"]'),
('34095ddf-fae8-4ae7-9e4d-1c09a785835b','贈白雲張少愚','蔣堂','宋','宋诗','song-poetry','','[]','聘命當年下益州，戔戔束帛禮偏憂。',32,'全唐诗/poet.song.8000.json','["聘命當年下益州，戔戔束帛禮偏憂。", "山人著出隱居報，使者賫還答詔牛。"]'),
('e7586b34-acec-46a0-bd3e-f8eea035edd8','太伯廟','蔣堂','宋','宋诗','song-poetry','','[]','太伯何爲者，不以身爲身。',48,'全唐诗/poet.song.8000.json','["太伯何爲者，不以身爲身。", "遜避天下位，奔走勾吳濱。", "隱德照來世，遺祀傳斯民。", "吁此廉讓國，合生廉讓民。"]'),
('416e87d0-5108-4ee6-ae97-b3fa5ff8f770','望太湖','蔣堂','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','杳杳波濤閱古今，四邊無際莫知深。',64,'全唐诗/poet.song.8000.json','["杳杳波濤閱古今，四邊無際莫知深。", "潤通曉月爲清露，氣入霜天作溟陰。", "笠澤鱸肥人鱠玉，洞庭柑熟客分金。", "風煙觸目相招引，聊爲停橈一楚吟。"]'),
('0ba06477-0dc2-4e12-b02a-a7f161d89051','句  其一','蔣堂','宋','宋诗','song-poetry','','[]','離堆山外更西去，應入白雲餐蕨薇。',16,'全唐诗/poet.song.8000.json','["離堆山外更西去，應入白雲餐蕨薇。"]'),
('583341fb-b0df-420c-bbef-559461428d70','句  其二','蔣堂','宋','宋诗','song-poetry','','[]','深鎖煙光在樓閣，旋移春色入門牆。',16,'全唐诗/poet.song.8000.json','["深鎖煙光在樓閣，旋移春色入門牆。"]'),
('32fdaff6-b246-40e0-ae0f-8b045b4c922b','句  其三','蔣堂','宋','宋诗','song-poetry','','[]','嚮日草青牛引犢，經秋田熟稻生孫。',16,'全唐诗/poet.song.8000.json','["嚮日草青牛引犢，經秋田熟稻生孫。"]'),
('82cee55f-f7f6-48d9-a5d6-701f08d5fca3','大諫詩筆因題絕句','魏閑','宋','宋诗','song-poetry','','[]','文如吐鳳筆如龍，珍重華林墨尚濃。',32,'全唐诗/poet.song.8000.json','["文如吐鳳筆如龍，珍重華林墨尚濃。", "清氣已銷名迹在，世間誰復繼仙翁。"]'),
('d5b97beb-0e33-4b5b-a46e-2139d16c570a','山居頌','振禪師','宋','宋诗','song-poetry','','[]','呵呵呵，瘦松寒竹鎖清波。',60,'全唐诗/poet.song.8000.json','["呵呵呵，瘦松寒竹鎖清波。", "有時獨坐磐陀上，無人共唱太平歌。", "朝看白雲生洞口，暮觀明月照娑婆。", "有人問我居山事，三尺杖子攪黄河。"]'),
('6b36398d-ba2f-4291-b9ba-9cc385429aa5','張相公祠','許申','宋','宋诗','song-poetry','','[]','鐵胎重整英儀峻，燕廈新成暑氣涼。',48,'全唐诗/poet.song.8000.json','["鐵胎重整英儀峻，燕廈新成暑氣涼。", "韶石徧圖輝壁落，荔枝分植映房廊。", "開元舊事豐碑在，家笥猶傳故笏囊。"]'),
('081bc52a-c591-46c0-8a37-eb5f04a5874f','如歸亭  其一','許申','宋','宋诗','song-poetry','','[]','幅圓千里浸清流，蘋葉微風爲客收。',32,'全唐诗/poet.song.8000.json','["幅圓千里浸清流，蘋葉微風爲客收。", "畫作一圖何處設，煮茶閑看建溪頭。"]'),
('0e345038-02ed-482d-979d-514ecb752791','如歸亭  其二','許申','宋','宋诗','song-poetry','','[]','日脚青山晚半藏，水遙天遠岸無廂。',32,'全唐诗/poet.song.8000.json','["日脚青山晚半藏，水遙天遠岸無廂。", "雲邊一葉來何處，認是宣州出浦航。"]'),
('5a4fbe7a-6273-4ef7-bae1-17e16904febe','如歸亭  其三','許申','宋','宋诗','song-poetry','','[]','館娃宮在西山下，游鹿臺居西嶺頭。',32,'全唐诗/poet.song.8000.json','["館娃宮在西山下，游鹿臺居西嶺頭。", "倒翠盡傾菱鏡裏，夕陽平照滿川流。"]'),
('19bfd9b9-b87c-4fb5-b1e2-125e427a653a','如歸亭  其四','許申','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','尋常高諷散人歌，傲睨天隨奈爾何。',32,'全唐诗/poet.song.8000.json','["尋常高諷散人歌，傲睨天隨奈爾何。", "即問松江舊廬舍，羽真來往洞庭波。"]'),
('962a90ca-9d0f-47a0-b06d-e086d9781298','句','朱正辭','宋','宋诗','song-poetry','','[]','地形吞七澤，山勢壓重湖。',12,'全唐诗/poet.song.8000.json','["地形吞七澤，山勢壓重湖。"]'),
('2c557cc7-4032-49c6-b9c1-3af60f1ba8d7','寄葛源','張鑄','宋','宋诗','song-poetry','','[]','銀銅坑冶是新差，職任催綱勝一階。',32,'全唐诗/poet.song.8000.json','["銀銅坑冶是新差，職任催綱勝一階。", "更使下官供脚色，下官蹤跡轉沈埋。"]'),
('825047aa-cc2f-4e8f-bef2-047485489c0e','道士','張鑄','宋','宋诗','song-poetry','','[]','乘龍控鯉真吾偶，化石燒金即我曹。',64,'全唐诗/poet.song.8000.json','["乘龍控鯉真吾偶，化石燒金即我曹。", "塵世混來名異跡，蓬山思去夢魂勞。", "吟依古栢天風斷，嘯近僊壇海月高。", "九轉丹成顔愈少，髪勝純漆臉勝桃。"]'),
('b0cd75e2-7528-437d-a0ba-5f555d50a5ab','游虎邱','康孝基','宋','宋诗','song-poetry','','[]','虎邱天下名，勝概狀難成。',48,'全唐诗/poet.song.8000.json','["虎邱天下名，勝概狀難成。", "入寺登山險，開門見路平。", "雲連松色翠，風度磬聲清。", "好便稱居士，安閑過一生。"]'),
('8c8e3ff2-c1b6-4088-98d0-dbe626943e22','春遊','康孝基','宋','宋诗','song-poetry','','[]','行春喜入虎邱山，按轡風和草色閑。',64,'全唐诗/poet.song.8000.json','["行春喜入虎邱山，按轡風和草色閑。", "寺內翠微松檜裏，空中紺宇水雲間。", "桃花時作翻翻落，苔蘚晴留點點斑。", "不爲白公爲太守，霓裳一曲暮迴還。"]'),
('307a49ec-05e9-4482-99de-7aa248b1525a','寄題神山縣玉兔寺','康孝基','宋','宋诗','song-poetry','','[]','國朝梵剎多新額，玉兔名存四百年。',64,'全唐诗/poet.song.8000.json','["國朝梵剎多新額，玉兔名存四百年。", "曾爲皇唐稱瑞應，得於炎宋保流傳。", "荆山溫潤嘗凝化，月窟精神主缺圓。", "寺記廢興書異事，豐碑采摭盡雕鐫。"]'),
('576c2c21-de7c-46e3-8285-a6eb38747e2b','詠瑞檜','林坰','宋','宋诗','song-poetry','','[]','右殿當年欲葺時，槎牙高檜礙簷榱。',64,'全唐诗/poet.song.8000.json','["右殿當年欲葺時，槎牙高檜礙簷榱。", "人間斤斧難容手，天上風雷爲轉枝。", "煙色併來春益重，月華饒得夜相宜。", "真皇一駐鑾輿賞，從此聲名四海知。"]'),
('eca429ff-e3dd-4049-8a82-faa0b37a16b6','續縣令題雁詩','王奇','宋','宋诗','song-poetry','','[]','隻隻含蘆背曉霜，盡隨鴛鷺立寒塘。',32,'全唐诗/poet.song.8000.json','["隻隻含蘆背曉霜，盡隨鴛鷺立寒塘。", "晚來漁櫂驚飛去，書破遙天字一行。"]'),
('05079a87-176b-453c-ac54-587c1aa4c21c','題修仁縣羣峰驛','王奇','宋','宋诗','song-poetry','','[]','檻前流水面前山，幽鳥孤雲自往還。',48,'全唐诗/poet.song.8000.json','["檻前流水面前山，幽鳥孤雲自往還。", "農父不知佳景好，使車纔得片時閑。", "恍榔樹暗寒溪上，躑躅花紅暮雨間。"]'),
('7517daa1-332a-40c8-98aa-4e71f09328de','通天巖','王奇','宋','宋诗','song-poetry','','[]','松羅石室中，清雅勝支公。',24,'全唐诗/poet.song.8000.json','["松羅石室中，清雅勝支公。", "地靜無塵到，天高有穴通。"]'),
('bc3b6738-963c-4233-bd6c-99017bba9c3c','旅中有感','王奇','宋','宋诗','song-poetry','','[]','澤國來遊豈厭重，羈孤懷感自無窮。',64,'全唐诗/poet.song.8000.json','["澤國來遊豈厭重，羈孤懷感自無窮。", "雁聲不到歌樓上，秋色偏欺客路中。", "宿寺夢回蓮葉雨，渡江衣冷荻花風。", "誰憐未得青雲志，琴劍年年西復東。"]'),
('6e354759-0f12-4b32-8a9a-0e00b6aff9dc','綠蔭亭','王奇','宋','宋诗','song-poetry','','[]','創得幽亭近嶺梅，綠陰名好稱仙才。',32,'全唐诗/poet.song.8000.json','["創得幽亭近嶺梅，綠陰名好稱仙才。", "四圍山色檐頭出，一带泉聲竹裏來。"]'),
('87ab06d9-5f5f-48ef-bcea-e79d62805cac','句','王奇','宋','宋诗','song-poetry','','[]','不拜春官爲座主，親逢天子作門生。',16,'全唐诗/poet.song.8000.json','["不拜春官爲座主，親逢天子作門生。"]'),
('14e97a29-0036-4c3b-9488-2c119ae55bf3','廣勝寺','張傅','宋','宋诗','song-poetry','','[]','亭險高登畏力微，放懷堪此養天機。',64,'全唐诗/poet.song.8000.json','["亭險高登畏力微，放懷堪此養天機。", "下窺平野遙無際，仰視危簷勢欲飛。", "常日羣猿偎檻戲，有時晴靄拂窗歸。", "旌軒暫駐聊凝睇，應笑塵中萬事非。"]'),
('02d3f64f-f7c5-49ac-b650-ee26dbe4f5f6','句','朱頔','宋','宋诗','song-poetry','','[]','岳陽多丘山，城郭蜂房綴。',12,'全唐诗/poet.song.8000.json','["岳陽多丘山，城郭蜂房綴。"]'),
('87de2a1e-82e0-420b-b108-5c3cf4ef4c45','留題靈巖寺','杜堯臣','宋','宋诗','song-poetry','','[]','四好處精藍冠古今，千山影裏寺難尋。',33,'全唐诗/poet.song.8000.json','["四好處精藍冠古今，千山影裏寺難尋。", "年來蹤跡如萍梗，不得登臨恨更深。"]'),
('f36adaa4-86c4-4f09-925c-3ff27f41ff5b','句  其一','裴愈','宋','宋诗','song-poetry','','[]','東吳山色家家月，南楚江聲浦浦風。',16,'全唐诗/poet.song.8000.json','["東吳山色家家月，南楚江聲浦浦風。"]'),
('1b0191ca-3678-47ac-a414-538c7ad71657','句  其二','裴愈','宋','宋诗','song-poetry','','[]','楊柳影疏秋霽月，梧桐葉墜夕陽天。',16,'全唐诗/poet.song.8000.json','["楊柳影疏秋霽月，梧桐葉墜夕陽天。"]'),
('ed8c0aec-0ca8-4af8-8f72-fd244cfb5dc3','句','任布','宋','宋诗','song-poetry','','[]','田曹郎吏何多幸，親見池中墨水生。',16,'全唐诗/poet.song.8000.json','["田曹郎吏何多幸，親見池中墨水生。"]'),
('56c23852-65e7-4e33-8154-52829df938ff','句','朱巽','宋','宋诗','song-poetry','','[]','塞垣古木含秋色，祖帳行塵起夕陽。',16,'全唐诗/poet.song.8000.json','["塞垣古木含秋色，祖帳行塵起夕陽。"]'),
('c2b18f89-95c1-45b9-9b69-bcbbedf4f866','感懷','魏瓘','宋','宋诗','song-poetry','','[]','羸羸霜髪一衰翁，蹤跡年來類斷蓬。',64,'全唐诗/poet.song.8000.json','["羸羸霜髪一衰翁，蹤跡年來類斷蓬。", "萬里遠歸雙闕下，一身閑在衆人中。", "螭頭賜對恩雖厚，雉堞論功事已空。", "淮上有山歸未得，獨揮清涕灑春風。"]'),
('029730e7-4859-4a64-aa86-d979bdb06dfb','句  其一','魏瓘','宋','宋诗','song-poetry','','[]','誰言嶺外無霜雪，何事秋來亦滿頭。',16,'全唐诗/poet.song.8000.json','["誰言嶺外無霜雪，何事秋來亦滿頭。"]'),
('dc40282a-1871-47bc-b90c-1174cb00c90a','句  其二','魏瓘','宋','宋诗','song-poetry','','[]','鐵冠詩白簡，藩棘聚青蠅。',12,'全唐诗/poet.song.8000.json','["鐵冠詩白簡，藩棘聚青蠅。"]'),
('eb731b07-ac0a-4d1a-9c9d-d73a9e7c4f4e','送張無夢歸天台山  其一','初暐','宋','宋诗','song-poetry','','[]','閑倚天台看曙霞，自然龍漢度無涯。',64,'全唐诗/poet.song.8000.json','["閑倚天台看曙霞，自然龍漢度無涯。", "暫來演道明光殿，歸去乘蹻太上家。", "帝簡賜歌旌火棗，世人何處訪桃花。", "到山若赴崑崙會，還控青鸞白鳳車。"]'),
('d63c07d5-fd04-4710-8d5e-083c1dad6ad3','送張無夢歸天台山  其二','初暐','宋','宋诗','song-poetry','','[]','紫皇宮闕羅高清，花虯玉鳳圍墉城。',128,'全唐诗/poet.song.8000.json','["紫皇宮闕羅高清，花虯玉鳳圍墉城。", "長生曲奏昇天行，神仙縹緲喧相迎。", "棲真何必拋塵網，飇輪萬里時來往。", "張公結廬天台山，赤城霞起三千丈。", "天子好道思崆峒，欲使億兆歸庬鴻。", "鳳臺峨峨十二重，先生忽造明光宮。", "無爲清凈化可守，能助羲軒致仁壽。", "共羨乘蹻歸洞宮，他日騎龍卻來否。"]'),
('52bdd0dc-6ce3-4032-b51d-51ba4aa15982','送僧歸護國寺','趙況','宋','宋诗','song-poetry','','[]','振錫攜瓶謁未央，薜蘿衣濕惹天香。',64,'全唐诗/poet.song.8000.json','["振錫攜瓶謁未央，薜蘿衣濕惹天香。", "曉辭丹陛君恩重，笑指舊山歸路長。", "何處漱泉吟夜月，幾程聞雨宿雲房。", "他年松下敲門去，應許塵襟拂石牀。"]'),
('2266f61d-423e-4ec5-92fe-fb0a9ec10916','送僧歸護國寺','石羲叟','宋','宋诗','song-poetry','','[]','雲房春鎖赤城邊，榮著蘭芽謝勝緣。',64,'全唐诗/poet.song.8000.json','["雲房春鎖赤城邊，榮著蘭芽謝勝緣。", "鑾殿暫來趨玉陛，石橋重去埽金田。", "窗噴瀑布千巖雪，爐爇栴檀一炷煙。", "此處深居更誰見，臘高松偃舊峰前。"]'),
('c88c5a67-ba58-4f4b-9b98-53414d3f47e7','送張無夢歸天台','趙世長','宋','宋诗','song-poetry','','[]','瓊臺卜幽隱，金液鍊真精。',120,'全唐诗/poet.song.8000.json','["瓊臺卜幽隱，金液鍊真精。", "冰雪形容古，煙霞意思清。", "談玄通至道，養素達長生。", "被詔離仙窟，安居入帝京。", "唐虞迴聖眷，巢許讓高名。", "抗節辭丹陛，歸心戀赤城。", "再眠琪樹影，重聽瀑泉聲。", "朝客多攀餞，天章復贈行。", "令猷光史策，逸態傲公卿。", "珍重青雲外，逍遙樂太平。"]'),
('3dbfa019-54f4-4eb9-9183-d162cf242573','句  其一','趙世長','宋','宋诗','song-poetry','','[]','玉清仙子下雲逵。',8,'全唐诗/poet.song.8000.json','["玉清仙子下雲逵。"]'),
('9c9a6747-54f8-40c1-a335-63ea84e657c7','句  其二','趙世長','宋','宋诗','song-poetry','','[]','莫恨東風翦拂遲。',8,'全唐诗/poet.song.8000.json','["莫恨東風翦拂遲。"]'),
('b1766aa4-12ff-4800-9e43-101fa086bc92','鵝羊山','畢田','宋','宋诗','song-poetry','','[]','羽客何年此鍊丹，尚留空竈鎮孱顔。',64,'全唐诗/poet.song.8000.json','["羽客何年此鍊丹，尚留空竈鎮孱顔。", "雲中雞犬仙應遠，山下鵝羊石轉頑。", "湘渚幾因滄海變，遼城無復令威還。", "何年仙馭還來此，盡遣飛騰上九關。"]'),
('e1606655-459e-463c-a713-7550aea4e4c6','醉鄉','畢田','宋','宋诗','song-poetry','','[]','三宿酣神酎，鄉名因此呼。',24,'全唐诗/poet.song.8000.json','["三宿酣神酎，鄉名因此呼。", "山中千日者，自合是仙都。"]'),
('bb6583f4-7b00-4592-91a5-dc476a1ef502','朱陵洞水簾','畢田','宋','宋诗','song-poetry','','[]','洞門千尺掛飛流，玉碎珠聯冷噴秋。',32,'全唐诗/poet.song.8000.json','["洞門千尺掛飛流，玉碎珠聯冷噴秋。", "今古不知誰捲得，綠蘿爲带月爲鉤。"]'),
('ed2e5ff9-edd7-4ff2-87db-4cd7b625316e','凝碧亭','畢田','宋','宋诗','song-poetry','','[]','四面山屏疊萬重，古嵐濃翠鎖寒空。',32,'全唐诗/poet.song.8000.json','["四面山屏疊萬重，古嵐濃翠鎖寒空。", "清秋獨倚危闌立，身在琉璃世界中。"]'),
('5ac2580c-b2f0-4fdb-8bae-c82090babd03','擲鉢峰','畢田','宋','宋诗','song-poetry','','[]','應將鉢渡鬬神通，擲去乘將赴帝宮。',32,'全唐诗/poet.song.8000.json','["應將鉢渡鬬神通，擲去乘將赴帝宮。", "爭似嶺頭提不起，于今相續闡真風。"]'),
('7f2a6a9b-adf8-4dc8-ba62-e72baccb8a62','真霜寺','畢田','宋','宋诗','song-poetry','','[]','石上泉華噴猛霜，境奇因此闢禪坊。',32,'全唐诗/poet.song.8000.json','["石上泉華噴猛霜，境奇因此闢禪坊。", "使君環笏留何用，枯木千餘滿一堂。"]'),
('1c662293-26a6-43f2-ac86-c6ee2496dc5b','大哀洲','畢田','宋','宋诗','song-poetry','','[]','玉輦南巡去不還，翠娥望斷楚雲間。',64,'全唐诗/poet.song.8000.json','["玉輦南巡去不還，翠娥望斷楚雲間。", "波寒剩寫哀絃怨，露冷偏滋淚篠斑。", "一水盈盈傷遠目，九峰𡾼𡾼慘愁顔。", "荒洲千古凄涼地，半掩空祠向暮山。"]'),
('7562c64b-0ac6-44e4-9f7d-610c32d26d34','神鼎山','畢田','宋','宋诗','song-poetry','','[]','玉趾分明印絕巓，藥成仙去幾千年。',32,'全唐诗/poet.song.8000.json','["玉趾分明印絕巓，藥成仙去幾千年。", "深藏寶鼎今方出，合得丹經與世傳。"]'),
('edf0cc42-d6b5-49de-8ca7-7f1670fed296','香水','畢田','宋','宋诗','song-poetry','','[]','坎上浮圖已拂天，椒蘭遺馥尚依然。',32,'全唐诗/poet.song.8000.json','["坎上浮圖已拂天，椒蘭遺馥尚依然。", "九重無復脩常貢，空有香名與邑傳。"]'),
('9387aa23-d6cf-4a06-8ef6-b5e6b48a58b9','羅漢縧','畢田','宋','宋诗','song-poetry','','[]','五百酰栖絕洞深，空留轍跡杳難尋。',32,'全唐诗/poet.song.8000.json','["五百酰栖絕洞深，空留轍跡杳難尋。", "綠絲縧带何人施，長到春來掛滿林。"]'),
('10d3bdad-bccd-42b0-925a-b39cb5f051cc','送張無夢歸天台','王得益','宋','宋诗','song-poetry','','[]','獨上仙槎汴水湄，吟歸舊隱赤城西。',96,'全唐诗/poet.song.8000.json','["獨上仙槎汴水湄，吟歸舊隱赤城西。", "少微昨夜離丹闕，雙舄何時到會稽。", "策杖再三麋鹿逕，採芝重躡薜蘿梯。", "雲橫皓鶴翹松唳，月白孤猿倚樹啼。", "象帝真源通閫域，玄元幽趣達筌啼。", "玉皇歌賜恩殊厚，好把貞珉刻聖題。"]'),
('58a9a6f9-7575-45cf-b199-dbd454dd6d47','送梵才大師歸天台  其一','張友道','宋','宋诗','song-poetry','','[]','詩律密聞高九釋，倦遊歸老舊煙霞。',32,'全唐诗/poet.song.8000.json','["詩律密聞高九釋，倦遊歸老舊煙霞。", "朝中半是名臣友，時寄新吟壁罩紗。"]'),
('8651ec74-1da3-4b9d-805f-d46f6ad7c626','送梵才大師歸天台  其二','張友道','宋','宋诗','song-poetry','','[]','久陪譯館清流集，吟苦霜添相頷髭。',32,'全唐诗/poet.song.8000.json','["久陪譯館清流集，吟苦霜添相頷髭。", "厭駐王成思舊隱，年來卻赴白雲期。"]'),
('6c1e1158-9583-4f5c-a5d4-1dacffd49085','送張無夢歸天台','崔希範','宋','宋诗','song-poetry','','[]','孤雲須信少常期，未作禎祥又欲歸。',64,'全唐诗/poet.song.8000.json','["孤雲須信少常期，未作禎祥又欲歸。", "霖雨只宜滋大旱，山川終稱養沈機。", "夜寒放意文章險，春盡平心筍蕨肥。", "若是蒲輪重到日，讓辭牋長莫重飛。"]'),
('a44391a2-c789-415a-9a78-40223c848fa0','贈丁和','白侍郎','宋','宋诗','song-poetry','','[]','步入羅湖石徑斜，陰陰喬木鎖煙霞。',32,'全唐诗/poet.song.8000.json','["步入羅湖石徑斜，陰陰喬木鎖煙霞。", "小橋流水君須記，便是丁和處士家。"]'),
('333afd86-cc22-4c28-8f21-919f3a258b18','頌','釋修演','宋','宋诗','song-poetry','','[]','未悟之日要參禪，一見石門便坦然。',32,'全唐诗/poet.song.8000.json','["未悟之日要參禪，一見石門便坦然。", "蒙師指箇真消息，方知鹽鹹醋是酸。"]'),
('40846277-69da-450b-8588-06f6ddd45b0a','觀音詩  其一','釋契適','宋','宋诗','song-poetry','','[]','金沙池裊玉蓮馨，殿閣階墀盡水精。',64,'全唐诗/poet.song.8000.json','["金沙池裊玉蓮馨，殿閣階墀盡水精。", "雲化路歧通萬國，風飄舟楫濟羣生。", "座粧珪璧霜猶暗，衣綴珠璣月不明。", "若向險途逢八難，只勞心念諷持名。"]'),
('67047d12-7116-4c5b-ad0a-e193a9315cbf','觀音詩  其二','釋契適','宋','宋诗','song-poetry','','[]','淵智弘慈大辨才，端居波上絕纖埃。',64,'全唐诗/poet.song.8000.json','["淵智弘慈大辨才，端居波上絕纖埃。", "祥光射散千門病，甘露傾消萬國災。", "翠柳變成金世界，白蓮涌出玉樓臺。", "我今稽首焚香禮，願向人間應念來。"]'),
('05c561da-31c1-4610-a010-d3fe58ed4a89','觀音詩  其三','釋契適','宋','宋诗','song-poetry','','[]','慧炬慈航在世間，除昏濟險未嘗閑。',64,'全唐诗/poet.song.8000.json','["慧炬慈航在世間，除昏濟險未嘗閑。", "手擎一穗青絲柳，身倚千層碧玉山。", "聲滿諸天常諷誦，功圓十地絕躋攀。", "終求郢妙雕金相，時獻香花禮粹顔。"]'),
('d7763bd8-016d-41e4-9f91-2a0b2956d5b0','觀音詩  其四','釋契適','宋','宋诗','song-poetry','','[]','方珪座壓五雲端，修竹叢邊舞玉鸞。',64,'全唐诗/poet.song.8000.json','["方珪座壓五雲端，修竹叢邊舞玉鸞。", "施果狖離蒼岫晚，獻珠龍透碧波寒。", "琉璃瓶對珊瑚印，翡翠環搖玳瑁冠。", "百寶階前文石上，天人瞻禮爇旃檀。"]'),
('e5e0c962-067a-4941-9f74-9702056354f1','觀音詩  其五','釋契適','宋','宋诗','song-poetry','','[]','水面紅鮮恥絳唇，尋常侍從有天神。',64,'全唐诗/poet.song.8000.json','["水面紅鮮恥絳唇，尋常侍從有天神。", "整齊紺髪雲千縷，端麗慈容月一輪。", "素舸欲沉威濟物，霜刀曾斷福霑人。", "世間多少誠心者，智燭惟求照耀身。"]'),
('8df191df-cd86-48ad-a503-86cf1688c946','觀音詩  其六','釋契適','宋','宋诗','song-poetry','','[]','天花環繞瑞雲隨，整救湮淪萬類時。',64,'全唐诗/poet.song.8000.json','["天花環繞瑞雲隨，整救湮淪萬類時。", "貴賤若能勤行願，死生常得睹容儀。", "狻猊番擲瓊臺角，鸚鵡回翔寶樹枝。", "永劫只將權實化，有情皆使入無爲。"]'),
('27d75aa3-4e82-44f2-8485-ea45180ec2f2','觀音詩  其七','釋契適','宋','宋诗','song-poetry','','[]','水精盤躍錦鱗魚，閟宇淵沉海岸居。',64,'全唐诗/poet.song.8000.json','["水精盤躍錦鱗魚，閟宇淵沉海岸居。", "秀世竹鳴金鸑鷟，觀空波湧說蟾蜍。", "輕明纓絡垂身後，重疊芙蓉襯足初。", "曾向夢中潛祐我，爍人儀表降蓬廬。"]'),
('324bcd2e-d951-402c-8891-9d1781366c70','觀音詩  其八','釋契適','宋','宋诗','song-poetry','','[]','寂照慈威化不同，聞聲清凈得殊功。',64,'全唐诗/poet.song.8000.json','["寂照慈威化不同，聞聲清凈得殊功。", "指光遠射神龍燭，眉彩修彎帝釋弓。", "寶器曉凝蘭穗露，珠衣秋響桂枝風。", "信知萬里從人欲，何患周遊鬼國中。"]'),
('3572295a-6da9-42a1-a325-fd1e6badc5c3','觀音詩  其九','釋契適','宋','宋诗','song-poetry','','[]','宴坐瓊瑤曲密都，感通寧肯擇賢愚。',64,'全唐诗/poet.song.8000.json','["宴坐瓊瑤曲密都，感通寧肯擇賢愚。", "遍分智慧燈開暗，盡灑清涼雨發枯。", "荷擁夕池鮮五色，樹凝春砌瑩三珠。", "波神天女相初從，虛白光中美丈夫。"]'),
('5f2b62f0-a68c-43af-8e2f-b663df36fb81','觀音詩  其一○','釋契適','宋','宋诗','song-poetry','','[]','覺源非有等差心，物性陶溶逐淺深。',64,'全唐诗/poet.song.8000.json','["覺源非有等差心，物性陶溶逐淺深。", "昏惑道中瞻月角，辨才門裏聽潮音。", "彩雲輕罩山輝玉，花雨斜飛地湧金。", "終擬龍綃圖畫看，供承香火老東林。"]'),
('11d3a822-1175-4cfc-b20a-3f1f8f0c2851','句','趙慶','宋','宋诗','song-poetry','','[]','邁古文章金鸑鷟，出群行止玉麒麟。',16,'全唐诗/poet.song.8000.json','["邁古文章金鸑鷟，出群行止玉麒麟。"]'),
('9314e2d5-a578-43e6-95b6-7118d762aaaf','歌  其一','王寂','宋','宋诗','song-poetry','','[]','人間冉冉混塵埃，身後身前事莫猜。',32,'全唐诗/poet.song.8000.json','["人間冉冉混塵埃，身後身前事莫猜。", "早悟勞生皆是夢，當時悔向夢中來。"]'),
('83c5c151-e4ea-4e35-b9cf-50653efb6fa6','歌  其二','王寂','宋','宋诗','song-poetry','','[]','當年壯氣謾如虹，回首都歸含笑中。',32,'全唐诗/poet.song.8000.json','["當年壯氣謾如虹，回首都歸含笑中。", "羣玉峰前好歸路，可憐三十二秋風。"]'),
('59a8e31f-2e7d-4229-b299-ee7c1561a74f','遊黄山','石待問','宋','宋诗','song-poetry','','[]','軒皇曾把浮丘袂，駐蹕茲山遂得名。',64,'全唐诗/poet.song.8000.json','["軒皇曾把浮丘袂，駐蹕茲山遂得名。", "迤邐乍登隨步勝，巍峨一上覺身輕。", "煙雲日變百千態，猿鶴時聞三兩聲。", "截斷杳冥秋勢隔，數州各自見陰晴。"]'),
('dfcc45c4-b09e-421c-a260-b65f3fd59d55','詩一首','石待問','宋','宋诗','song-poetry','','[]','平生無女只生兒，三萬登科一子隨。',32,'全唐诗/poet.song.8000.json','["平生無女只生兒，三萬登科一子隨。", "家在白雲青嶂裏，不求閑散待何時。"]'),
('9ed5de16-2c84-4dd3-9eb6-18928f0f0abf','句','石待問','宋','宋诗','song-poetry','','[]','何常爲柱石，同立太平基。',12,'全唐诗/poet.song.8000.json','["何常爲柱石，同立太平基。"]'),
('5fc4b862-d45e-43b8-bb39-1e360bef01ca','答講僧','朱炎','宋','宋诗','song-poetry','','[]','四大不須先後覺，六根還向用時空。',32,'全唐诗/poet.song.8000.json','["四大不須先後覺，六根還向用時空。", "難將語默呈師也，只在尋常語默中。"]'),
('cae460c4-0fe9-4af8-9ecb-eed19866ba06','句','朱炎','宋','宋诗','song-poetry','','[]','古人不到處，吾子獨留心。',12,'全唐诗/poet.song.8000.json','["古人不到處，吾子獨留心。"]'),
('42bbe74e-9534-47e3-be32-648b606de3cd','過越','趙諮','宋','宋诗','song-poetry','','[]','地有千巖與萬津，霸圖無計老青春。',32,'全唐诗/poet.song.8000.json','["地有千巖與萬津，霸圖無計老青春。", "抱冰漫刷棲山恥，爭奈傾吳是歸人。"]'),
('fb8dac4b-a872-4f6e-898d-8c45f38fa36b','題黄敕背詩','陳彭年甥','宋','宋诗','song-poetry','','[]','彭年頭腦太冬烘，眼似朱砂鬢似蓬。',64,'全唐诗/poet.song.8000.json','["彭年頭腦太冬烘，眼似朱砂鬢似蓬。", "紕繆幸叨三字內，荒唐仍預四人中。", "放他權勢欺明主，落卻親情賣至公。", "千百孤寒齊灑淚，斯言無路入堯聰。"]'),
('eb837090-50ff-468a-a455-55f3a696be66','送張無夢歸天台','孫沖','宋','宋诗','song-poetry','','[]','天台山裏草堂低，一到都城識面稀。',64,'全唐诗/poet.song.8000.json','["天台山裏草堂低，一到都城識面稀。", "綺里冠裳遵漢命，許由風骨謝堯歸。", "去時暑氣蒸船滴，到日秋雲伴鶴飛。", "誰向薜蘿尋覓得，石橋侵漢見依微。"]'),
('4476165d-11c1-4002-8190-32b68da08712','過古夾寨城','孫沖','宋','宋诗','song-poetry','','[]','宋氏英聲振，並門意氣揚。',288,'全唐诗/poet.song.8000.json','["宋氏英聲振，並門意氣揚。", "兩雄爭裂土，百戰競圖王。", "揣敵惟虞晉，躭頤已噬唐。", "大河分背面，上黨扼咽吭。", "地利知爲勝，人心彼未遑。", "重圍誇壁立，夾寨逞虹張。", "埇道便輪饋，游兵勁絕糧。", "蒙衝窺女堞，鈎戟伺陑牆。", "踞峙培山峻，環圍列塹長。", "力攻須陷沒，堅拒倚金湯。", "墨带推才妙，班斤衒技良。", "萬夫橫劍刃，一噉墮夷傷。", "野草塗肝腦，貪心怒虎狼。", "嘶鳴宵遁馬，感慨守陴郎。", "戈甲從誰息，功名漫自狂。", "逡巡稱五代，合沓鬬干場。", "此後連吞併，於時旋覆亡。", "昔年勞戰陣，今日舊城隍。", "耕澀枯骸白，風腥鬼火光。", "營基繫井室，濠坎密榆桑。", "忍殺天還厭，陰謀嗣昔昌。", "驅除期出震，草昧在開皇。", "真主臨綿宇，華胥正樂康。", "廓然文軌至，海外截封疆。"]'),
('b171442b-3495-44c8-9b60-eb98bdde7e6a','題桑子鋪石壁','孫沖','宋','宋诗','song-poetry','','[]','峨峨溪畔石，迢迢石邊路。',24,'全唐诗/poet.song.8000.json','["峨峨溪畔石，迢迢石邊路。", "寄言名利徒，清閑誠足慕。"]'),
('b0f06800-35be-48b1-ac42-d5cbc6220640','長平懷古','孫沖','宋','宋诗','song-poetry','','[]','邯鄲無策信馮亭，上黨須貪澤起兵。',32,'全唐诗/poet.song.8000.json','["邯鄲無策信馮亭，上黨須貪澤起兵。", "趙括母言猶不聽，當時誰肯計長平。"]'),
('ab3c7ca0-ffab-4b94-838b-0acd1b921ec1','送別黄敬山','釋志宣','宋','宋诗','song-poetry','','[]','紫藤花發送君行，惜別龍谿暗悵神。',32,'全唐诗/poet.song.8000.json','["紫藤花發送君行，惜別龍谿暗悵神。", "目斷歸帆何太疾，風吹柳絮正愁人。"]'),
('2308d716-6d67-4bef-9d04-17d703729fe2','頌','釋守芝','宋','宋诗','song-poetry','','[]','北斗掛須彌，杖頭挑日月。',24,'全唐诗/poet.song.8000.json','["北斗掛須彌，杖頭挑日月。", "林泉好商量，夏一秋風切。"]'),
('25dc1830-9c33-4e3c-8175-93dde1ce11e8','偈  其一','釋守芝','宋','宋诗','song-poetry','','[]','一擊響玲瓏，喧轟宇宙通。',24,'全唐诗/poet.song.8000.json','["一擊響玲瓏，喧轟宇宙通。", "知音纔側耳，項羽過江東。"]'),
('9c3a900a-1b47-443f-bf98-864d11a2b962','偈  其二','釋守芝','宋','宋诗','song-poetry','','[]','大愚相接大雄孫，五湖雲水競頭奔。',68,'全唐诗/poet.song.8000.json','["大愚相接大雄孫，五湖雲水競頭奔。", "競頭奔，有何門，擊箭寧知枯木存。", "枯木存，一年還曾兩度春。", "兩度春，帳裏真珠撒與人。", "撒與人，思量也是慕西秦。"]'),
('26251cd6-d290-4d4c-8ae5-38ba325d62ed','偈  其三','釋守芝','宋','宋诗','song-poetry','','[]','翠巖路嶮巇，舉步涉千溪。',56,'全唐诗/poet.song.8000.json','["翠巖路嶮巇，舉步涉千溪。", "更有洪源水，滔滔在嶺西。", "沙裏無油事可哀，翠巖嚼飯餧嬰孩。", "他時好惡知端的，始覺從前滿面埃。"]'),
('8d0b0906-197f-4c50-aab3-273b90da9094','紀事夏事  其一','范雍','宋','宋诗','song-poetry','','[]','七百里山界，飛沙與亂雲。',48,'全唐诗/poet.song.8000.json','["七百里山界，飛沙與亂雲。", "虜騎擇虛至，戍兵常忌分。", "嘯聚類宿鳥，奔敗如驚麕。", "難稽守邊法，應敵若絲棼。"]'),
('d6e5342d-00c0-457c-9ddf-503c67df2130','紀事夏事  其二','范雍','宋','宋诗','song-poetry','','[]','承平廢邊事，備預久已亡。',48,'全唐诗/poet.song.8000.json','["承平廢邊事，備預久已亡。", "萬卒不知戰，兩城皆復隍。", "輕敵謂小醜，視地固大荒。", "願因狂狡叛，從此葺邊防。"]'),
('c4f4da2a-a2da-43ae-a6d6-5f4e44b1f609','紀事夏事  其三','范雍','宋','宋诗','song-poetry','','[]','劇賊稱中塞，驅馳甲鎧精。',48,'全唐诗/poet.song.8000.json','["劇賊稱中塞，驅馳甲鎧精。", "昔惟矜突騎，今亦教攻城。", "伏險多邀擊，驅羸每玩兵。", "拘俘詢虜事，肉盡一無聲。"]'),
('9bdf6684-27a1-4216-9672-2413b4c184d7','安陸','范雍','宋','宋诗','song-poetry','','[]','安陸號方鎮，江邊無事州。',24,'全唐诗/poet.song.8000.json','["安陸號方鎮，江邊無事州。", "民淳訟詞少，務簡官政優。"]'),
('9f8c4647-2ec8-4576-8e16-7ff51f5f35dc','白兆山','范雍','宋','宋诗','song-poetry','','[]','車蓋聊引步，浮雲鎮消憂。',36,'全唐诗/poet.song.8000.json','["車蓋聊引步，浮雲鎮消憂。", "鄖川夢澤地，古迹堪詢求。", "白兆桃花巖，翰林棲此邱。"]'),
('a485283d-01f9-4540-a619-6e2ca16f7f09','句  其一','范雍','宋','宋诗','song-poetry','','[]','五老峰排連戶色，萬山寒聳入雲株。',16,'全唐诗/poet.song.8000.json','["五老峰排連戶色，萬山寒聳入雲株。"]'),
('fbdf2f81-3eb8-470d-9a44-f8598a891f60','句  其二','范雍','宋','宋诗','song-poetry','','[]','清涼萬杉下，蒼翠五峰前。',12,'全唐诗/poet.song.8000.json','["清涼萬杉下，蒼翠五峰前。"]'),
('23e1db06-8880-4c7f-bbf4-bacecba425f2','句  其三','范雍','宋','宋诗','song-poetry','','[]','山奇號九嵕，名與雍州同。',12,'全唐诗/poet.song.8000.json','["山奇號九嵕，名與雍州同。"]'),
('793cdbae-4f37-42fd-9a97-9b1f0839d119','句  其四','范雍','宋','宋诗','song-poetry','','[]','日下溳川暮，煙橫夢澤秋。',12,'全唐诗/poet.song.8000.json','["日下溳川暮，煙橫夢澤秋。"]'),
('9c9effaa-f5a3-4363-96d3-e17c8d2e9aa2','呈法智大師','釋本如','宋','宋诗','song-poetry','','[]','處處逢頭路，頭頭是故鄉。',24,'全唐诗/poet.song.8000.json','["處處逢頭路，頭頭是故鄉。", "本來成現事，何必更思量。"]'),
('9355efaa-008d-4e09-afeb-e533ea78aebb','寓懷會稽吳道子遇因師','鮑當','宋','宋诗','song-poetry','','[]','隱淪與釋子，時予久往還。',48,'全唐诗/poet.song.8000.json','["隱淪與釋子，時予久往還。", "覽照不自認，況復思君顔。", "昨日山書至，乃夢雲蘿間。", "何必風韻息，始覺萬境閑。"]'),
('a2f46a31-d44a-43e3-ae71-fafe7bf85529','孤雁','鮑當','宋','宋诗','song-poetry','','[]','天寒稻粱少，萬里孤難進。',24,'全唐诗/poet.song.8000.json','["天寒稻粱少，萬里孤難進。", "不惜充君庖，爲這邊城信。"]'),
('26b6b694-9e33-4dae-935c-e2b3365d1578','松江夜泊','鮑當','宋','宋诗','song-poetry','','[]','舟閑人已息，林際月微明。',24,'全唐诗/poet.song.8000.json','["舟閑人已息，林際月微明。", "一片清江水，中涵萬古情。"]'),
('81a00d96-dd8b-45a1-b3d7-82f53561aac8','酬阮逸詩卷','鮑當','宋','宋诗','song-poetry','','[]','木有毫端水有源，漸成盤錯始潺湲。',32,'全唐诗/poet.song.8000.json','["木有毫端水有源，漸成盤錯始潺湲。", "右丞畫筆多平淺，平淺應知近自然。"]'),
('8c7a3c15-1454-4c25-9b71-79948373992b','寄西湖擇棲公','鮑當','宋','宋诗','song-poetry','','["\u897f\u6e56"]','兩信海潮喧曉夕，百年事過無遺迹。',32,'全唐诗/poet.song.8000.json','["兩信海潮喧曉夕，百年事過無遺迹。", "舊住招提有幾人，春風苔長湖邊石。"]'),
('0d6a777f-d0a2-40c5-ae0e-9acb11cb4dba','送人南歸','鮑當','宋','宋诗','song-poetry','','[]','凄凄楊柳暮，時復一蟬聲。',48,'全唐诗/poet.song.8000.json','["凄凄楊柳暮，時復一蟬聲。", "滄海不可極，風帆難計程。", "微煙生晚浦，斜日上孤城。", "欲寄相思札，誰傳萬里情。"]'),
('3f6cdb55-fff9-4655-9732-4b9b6eaf82d6','宿棲霞觀','鮑當','宋','宋诗','song-poetry','','[]','一宵會清境，不悟世間憂。',48,'全唐诗/poet.song.8000.json','["一宵會清境，不悟世間憂。", "天共白雲曉，水和明月流。", "碧煙生藻井，紅日映花樓。", "顧我無道氣，拂衣難少留。"]'),
('11252da5-c520-42d7-9330-c9cd11f70df1','送天台進長老','鮑當','宋','宋诗','song-poetry','','[]','嘗聞台嶺秀，積翠倚南天。',48,'全唐诗/poet.song.8000.json','["嘗聞台嶺秀，積翠倚南天。", "鹿下深溪飲，僧從絕嶺禪。", "浮塵滿浮世，流水逐流泉。", "人別歸心切，瓶盂上客船。"]'),
('66cad2b8-f241-4cfd-bfc8-59bb3d4f6bc0','送白上人歸天台','鮑當','宋','宋诗','song-poetry','','[]','梵譯千篇廣，歸心一念生。',48,'全唐诗/poet.song.8000.json','["梵譯千篇廣，歸心一念生。", "浮杯識海岸，持鉢去王城。", "雨彴春莓滑，香盆漏葉輕。", "遙知守庵虎，先辨錫環聲。"]'),
('aa1e7417-be1b-419b-a16e-b693a4e1f806','題和靖隱居','鮑當','宋','宋诗','song-poetry','','[]','湖水春來綠，山雲憂亦繁。',24,'全唐诗/poet.song.8000.json','["湖水春來綠，山雲憂亦繁。", "如何隱君子，長嘯掩柴門。"]'),
('ca52587c-7449-4c89-b7f0-6981b3bbcdcb','句','鮑當','宋','宋诗','song-poetry','','[]','更無聲接續，空有影相隨。',12,'全唐诗/poet.song.8000.json','["更無聲接續，空有影相隨。"]'),
('414f869d-b9e3-42d7-bda7-195a5acdb78c','遊虎丘','富嚴','宋','宋诗','song-poetry','','[]','繚繞禪關鎖翠微，遊人到此便忘歸。',32,'全唐诗/poet.song.8000.json','["繚繞禪關鎖翠微，遊人到此便忘歸。", "古今不盡春風恨，一劍清泉浸落暉。"]'),
('e86982e3-9a43-4ec1-bd5c-a8fc58f0d825','送僧歸護國寺','李諮','宋','宋诗','song-poetry','','[]','輦寺住對年，歸心起浩然。',48,'全唐诗/poet.song.8000.json','["輦寺住對年，歸心起浩然。", "傳衣因世出，揮麈自彌天。", "海客分朝供，江燈照夜禪。", "赤城重到日，八桂老巖煙。"]'),
('fcef1769-79f1-4083-8f07-ef96599aa81b','句','李諮','宋','宋诗','song-poetry','','[]','空令抱恨歸黄壤，不見崇山謫去時。',16,'全唐诗/poet.song.8000.json','["空令抱恨歸黄壤，不見崇山謫去時。"]'),
('59191b66-0e11-462e-922a-b1637aeafd46','句','柴宗慶','宋','宋诗','song-poetry','','[]','曾觀大海難爲水，除去梁園總是村。',16,'全唐诗/poet.song.8000.json','["曾觀大海難爲水，除去梁園總是村。"]'),
('34bf3656-6b35-46ba-aebb-6995c0d145a4','桐柏崇道觀','李仲偃','宋','宋诗','song-poetry','','[]','妙道心期赤水求，隙駒光景任川流。',64,'全唐诗/poet.song.8000.json','["妙道心期赤水求，隙駒光景任川流。", "朝真凈界瓊臺月，滌想鮮飈玉宇秋。", "芝茹薦盤香露散，茶腴烹鼎綠雲浮。", "勞生可念榮華束，食頃邯鄲枕上遊。"]'),
('cd281ff5-22b4-49ae-ab1d-e9861a452dcd','清隱巖','劉夔','宋','宋诗','song-poetry','','[]','地迥隔塵寰，石門雲閉關。',24,'全唐诗/poet.song.8000.json','["地迥隔塵寰，石門雲閉關。", "幽人澹無事，白鶴相往還。"]'),
('a1d88c5f-98c6-4ad6-80ee-af64eb1dbc6c','句  其一','劉夔','宋','宋诗','song-poetry','','[]','題詩人已貴，衮路冠三臺。',12,'全唐诗/poet.song.8000.json','["題詩人已貴，衮路冠三臺。"]'),
('8667102b-a441-41a8-8eed-f66de1c9d977','句  其二','劉夔','宋','宋诗','song-poetry','','[]','冷淡亭臺偏種竹，清虛軒砌不栽花。',16,'全唐诗/poet.song.8000.json','["冷淡亭臺偏種竹，清虛軒砌不栽花。"]'),
('28d6c058-9786-4fbd-8dda-e02d376e0ce7','如歸亭','章侁','宋','宋诗','song-poetry','','[]','倚岸凌虛若冠鰲，湖光山色兩相高。',64,'全唐诗/poet.song.8000.json','["倚岸凌虛若冠鰲，湖光山色兩相高。", "驚波雜沓聞千騎，遠樹微茫見一毫。", "娃館已空人世隔，帝鄉何許客心勞。", "吳門曳綵那曾睹，早覺霜華入髩毛。"]'),
('b9198e23-cb55-4dee-afca-809f6f98d112','句','章侁','宋','宋诗','song-poetry','','[]','官中逐月催租稅，不徵穀帛只徵銀。',16,'全唐诗/poet.song.8000.json','["官中逐月催租稅，不徵穀帛只徵銀。"]'),
