('8a9b85c2-f1fa-40e9-bca4-b76693b2a184','富池口','王周','宋','宋诗','song-poetry','','[]','扁舟閑引望，望極更盤桓。',48,'全唐诗/poet.song.8000.json','["扁舟閑引望，望極更盤桓。", "山密礙江曲，雨多饒地寒。", "短莎煙苒苒，驚浪雪漫漫。", "難寫愁何限，鄉關在一端。"]'),
('6c26f9e8-3eb7-4d74-9df2-9ef4e4da75a9','夔州病中','王周','宋','宋诗','song-poetry','','[]','隱几經旬疾未痊，孤燈孤驛若爲眠。',32,'全唐诗/poet.song.8000.json','["隱几經旬疾未痊，孤燈孤驛若爲眠。", "郡樓昨夜西風急，一一更籌到枕前。"]'),
('523d0e67-5c81-4d91-90e7-4cb8a87d7f83','題廳壁','王周','宋','宋诗','song-poetry','','[]','永日無他念，孤清吏隱心。',48,'全唐诗/poet.song.8000.json','["永日無他念，孤清吏隱心。", "竹聲并雪碎，溪色共煙深。", "數息閑凭几，緣情默寄琴。", "誰知同寂寞，相與結知音。"]'),
('1e63d8d2-66ef-4b98-aa27-4216a4bbec77','過武寧縣','王周','宋','宋诗','song-poetry','','[]','行過武寧縣，初晴物景和。',48,'全唐诗/poet.song.8000.json','["行過武寧縣，初晴物景和。", "岸回驚水急，山淺見天多。", "細草濃藍潑，輕煙疋練拖。", "晚来何處宿，一笛起漁歌。"]'),
('dce50196-b54f-42ef-87d3-34b0228e042b','路次覆盆驛','王周','宋','宋诗','song-poetry','','[]','曾上青泥蜀道難，架空成路入雲寒。',32,'全唐诗/poet.song.8000.json','["曾上青泥蜀道難，架空成路入雲寒。", "如何却向巴東去，三十六盤天外盤。"]'),
('19e0c53f-93b3-477b-8c7e-801ad6e4c3d5','藕池阻風寄同行撫牧裘駕','王周','宋','宋诗','song-poetry','','[]','船檣相望荆江中，岸蘆汀樹煙濛濛。',32,'全唐诗/poet.song.8000.json','["船檣相望荆江中，岸蘆汀樹煙濛濛。", "路間隄缺水如箭，未知何日生南風。"]'),
('0adfc2d6-85d5-43bb-b630-a1dc23fb86b3','無題  其一','王周','宋','宋诗','song-poetry','','[]','冰雪肌膚力不勝，落花飛絮遶風亭。',32,'全唐诗/poet.song.8000.json','["冰雪肌膚力不勝，落花飛絮遶風亭。", "不知何事鞦韆下，蹙破愁眉兩點青。"]'),
('785559a8-e38b-4ecc-86c2-ec2b6ff7163a','無題  其二','王周','宋','宋诗','song-poetry','','[]','梨花如雪已相迷，更被驚烏半夜啼。',32,'全唐诗/poet.song.8000.json','["梨花如雪已相迷，更被驚烏半夜啼。", "簾捲玉樓人寂寂，一鉤新月未沉西。"]'),
('f1c2dd7e-4160-4d44-a4c3-29c393508105','泊巴東','王周','宋','宋诗','song-poetry','','[]','偶泊巴東古縣前，宦情鄉思兩綿綿。',32,'全唐诗/poet.song.8000.json','["偶泊巴東古縣前，宦情鄉思兩綿綿。", "不堪蠟炬燒殘淚，雨打船窓半夜天。"]'),
('3581acde-d0ce-4bbf-aa6b-502e8f7e64a0','道中未開木杏花','王周','宋','宋诗','song-poetry','','[]','粉英香蕚一般般，無限行人立馬看。',32,'全唐诗/poet.song.8000.json','["粉英香蕚一般般，無限行人立馬看。", "村女浴蠶桑柘綠，枉將顔色忍春寒。"]'),
('8ebb4f8e-0bdc-42dd-adf1-c5d8c5675e83','西山晚景','王周','宋','宋诗','song-poetry','','[]','公局長清淡，池亭晚景中。',48,'全唐诗/poet.song.8000.json','["公局長清淡，池亭晚景中。", "蔗竿閑倚碧，蓮朵静淹紅。", "半引彎彎月，微生飋飋風。", "無思復無慮，此味幾人同。"]'),
('a1b30175-1cb3-4a3a-9035-031b028a386f','和','王周','宋','宋诗','song-poetry','','[]','一片殘陽景，朦朧淡月中。',48,'全唐诗/poet.song.8000.json','["一片殘陽景，朦朧淡月中。", "蘭芽紆嫩紫，梨頰抹生紅。", "琴阮資清格，冠簪養素風。", "煙霄半知己，吏隱少相同。"]'),
('a584df41-1b5d-4afb-9c99-50e87b2c4eeb','齒落詞','王周','宋','宋诗','song-poetry','','[]','己卯至庚辰，仲夏晦之暮。',144,'全唐诗/poet.song.8000.json','["己卯至庚辰，仲夏晦之暮。", "吾齒右排上，一齒脫而去。", "呼吸缺吾防，咀嚼欠吾助。", "年籥惜不返，日馭走爲蠧。", "脣亡得無寒，舌在從何訴。", "輔車宜長依，髮膚可增懼。", "不須考前古，聊且爲近喻。", "有如雲中雨，雨散絕回顧。", "有如枝上葉，葉脱難再附。", "白髮非獨愁，紅顔豈私駐。", "何必鬱九回，何必牽百慮。", "開尊復開懷，引筆作長句。"]'),
('10397780-21be-4d53-aaac-0ef655da246b','淘金磧','王周','宋','宋诗','song-poetry','','[]','畫船晚過淘金磧，不見黄金惟見石。',32,'全唐诗/poet.song.8000.json','["畫船晚過淘金磧，不見黄金惟見石。", "猶恐黄金價未高，見得錙銖幾多力。"]'),
('98921162-c96f-4c6d-be35-9731cdbbd79c','施南路偶書','王周','宋','宋诗','song-poetry','','[]','大石嶺頭梅欲發，南陵陂上雪初飛。',32,'全唐诗/poet.song.8000.json','["大石嶺頭梅欲發，南陵陂上雪初飛。", "苦無酒解愁成陣，又附蘭橈向秭歸。"]'),
('414b2e74-e754-44d7-8fe8-800cd50ff1ba','大石嶺驛梅花','王周','宋','宋诗','song-poetry','','[]','仙中姑射接瑤姬，成陣清香擁路岐。',32,'全唐诗/poet.song.8000.json','["仙中姑射接瑤姬，成陣清香擁路岐。", "半出驛牆誰畫得，雪英相倚两三枝。"]'),
('a9c2c8c5-7628-4bb3-a3d1-55723fafee7d','贈怤師','王周','宋','宋诗','song-poetry','','[]','水中有片月，照耀嬋娟姿。',108,'全唐诗/poet.song.8000.json','["水中有片月，照耀嬋娟姿。", "庭前有孤柏，竦秀歲寒期。", "堅然物莫遷，寂焉心爲師。", "聲發響必答，形存影即隨。", "雪花安結子，雪葉寧附枝。", "蘭死不改香，井寒豈生澌。", "晨鑪煙褭褭，病髮霜絲絲。", "丈室冰凛冽，一衲雲離披。", "顧此名利場，得不慚冠綏。"]'),
('5855fc63-491c-4d0a-9dcf-22614dfcecf9','遊仙都觀','王周','宋','宋诗','song-poetry','','[]','冷杉枯柏路盤空，毛髮生寒略略風。',32,'全唐诗/poet.song.8000.json','["冷杉枯柏路盤空，毛髮生寒略略風。", "兩漢真仙在何處，巡香行遶蕊珠宫。"]'),
('9b6d61c3-3f66-4886-848b-84cce0d2914e','誌峽船具詩 梢','王周','宋','宋诗','song-poetry','','[]','制之居首尾，俾之辨斜正。',108,'全唐诗/poet.song.8000.json','["制之居首尾，俾之辨斜正。", "首動尾聿随，斜取正爲定。", "有如提吏筆，有如執時柄。", "有如秉師律，有如宣命令。", "守彼方與直，得其剛且勁。", "既能濟險難，何畏涉遼夐。", "招招俾作主，汎汎實司命。", "風烏愧斟酌，畫鷁空輝映。", "古人存豐規，猗歟聊引證。"]'),
('ebc1f943-d52a-47d3-bdab-7523644e99b6','誌峽船具詩 櫓','王周','宋','宋诗','song-poetry','','[]','用之大曰櫓，冠乎小者楫。',60,'全唐诗/poet.song.8000.json','["用之大曰櫓，冠乎小者楫。", "通津既能濟，巨浸即横涉。", "身之使者頰，虎之拏者爪。", "魚之撥者鬛，弩之進者筴。", "此實爲相須，相須航一葉。"]'),
('b5e676a9-a411-4a3b-9a23-40bd31075dfe','誌峽船具詩 戙','王周','宋','宋诗','song-poetry','','[]','箭飛峡中水，鋸立峡中石。',132,'全唐诗/poet.song.8000.json','["箭飛峡中水，鋸立峡中石。", "峡與水爲隘，水與石相擊。", "濆爲生險艱，聲發甚霹靂。", "三老航一葉，百丈空千尺。", "蒼黄徒爾爲，倐忽何可測。", "篙之小難制，戙之獨有力。", "猗嗟戙之爲，彬彬堅且直。", "有如用武人，森森矗戈戟。", "有如敢言士，落落吐胸臆。", "拯危居坦夷，濟險免兢愓。", "誌彼哲匠心，俾其来者識。"]'),
('bae6c209-bcbf-45cd-82eb-cd5f0adc2d22','誌峽船具詩 百丈','王周','宋','宋诗','song-poetry','','[]','少嘗侍先君，餘閑誦白氏。',168,'全唐诗/poet.song.8000.json','["少嘗侍先君，餘閑誦白氏。", "始得入峡詩，深味作詩旨。", "云有萬仞山，云有千丈水。", "自念坎壈時，尤多兢慎理。", "山束峡如口，水潄石如齒。", "孤舟行其中，薄冰猶坦履。", "孱顔屹焉立，洶湧勃然起。", "百丈爲前牽，萬險即平砥。", "破之以篔簹，續之以麻枲。", "礪之堅以節，引之直如矢。", "杼軸連半空，長短隨兩涘。", "鐵鎖枉馳名，錦纜謾稱美。", "長繩豈能繫，朽索何足擬。", "苟非𦁤之爲，胡可力行此。"]'),
('1d773e51-8229-4c05-899d-f75e7d341f0e','早春西園','王周','宋','宋诗','song-poetry','','[]','引步攜筇竹，西園小徑通。',48,'全唐诗/poet.song.8000.json','["引步攜筇竹，西園小徑通。", "雪攲梅蔕綠，春入杏梢紅。", "静意崖穿溜，孤愁笛破空。", "如何將此景，收拾向圖中。"]'),
('a7e9f7be-c7fe-4a94-b494-8490fb0a56ec','金盤草','王周','宋','宋诗','song-poetry','','[]','今春從南陵，得草名金盤。',180,'全唐诗/poet.song.8000.json','["今春從南陵，得草名金盤。", "金盤有仁性，生在林一端。", "根節歲一節，食之甘而酸。", "風俗競採掇，俾人防急難。", "巴中虵虺毒，解之如走丸。", "巨葉展六出，軟幹分長竿。", "搖搖綠玉活，褭褭香荷寒。", "世云暑酷月，鬱有神物看。", "天之産於此，意欲生民安。", "今之爲政者，何不反此觀。", "知彼苛且猛，慎勿虐而殘。", "一物苟失所，萬金惟可歎。", "莫並蒿與莱，豈羡芝及蘭。", "勤渠護根本，栽植當庭欄。", "寄言好生者，休說神仙丹。"]'),
('798dca06-153a-4184-b24f-8a02dc348415','和程刑部三首 公會亭','王周','宋','宋诗','song-poetry','','[]','公事公言地，標名信必臧。',48,'全唐诗/poet.song.8000.json','["公事公言地，標名信必臧。", "江山如得助，談笑若爲妨。", "均賦鄉原肅，詳刑郡邑康。", "官箴居座右，夙夜算難忘。"]'),
('be7156b8-4c19-4e19-8ae1-242b8ea7d1b4','和程刑部三首 碧鮮亭','王周','宋','宋诗','song-poetry','','[]','飋飋籠清籟，蕭蕭鎖翠陰。',48,'全唐诗/poet.song.8000.json','["飋飋籠清籟，蕭蕭鎖翠陰。", "向高思盡節，從直羙虛心。", "迥砌滋蒼蘚，幽窓伴素琴。", "公餘時引步，一徑静中深。"]'),
('7167e7d5-94c4-4444-b927-ed2bca69f205','和程刑部三首 清漣閣','王周','宋','宋诗','song-poetry','','[]','照影翻窓綺，層紋滉額波。',48,'全唐诗/poet.song.8000.json','["照影翻窓綺，層紋滉額波。", "絲青迷岸柳，茸綠蘸汀莎。", "片雪翹饑鷺，孤香卷嫩荷。", "憑欄堪入畫，時聽竹枝歌。"]'),
('8e29104e-2819-4181-aa59-73b92d247824','自喻','王周','宋','宋诗','song-poetry','','[]','予念天之生，生本空疏器。',264,'全唐诗/poet.song.8000.json','["予念天之生，生本空疏器。", "五歲稟慈訓，憤悱讀書志。", "七歲辨聲律，勤苦會詩賦。", "九歲執公卷，倜儻干名意。", "乞薦鄉老書，幸會春官試。", "折桂愧巍峨，依蓮何氣味。", "性拙絕不佞，才短無餘地。", "前年會知己，薦章實非據。", "寧見民說平，空荷君恩寄。", "瞿塘抵巴渝，往来名攬轡。", "孤舟一水中，艱險實可畏。", "羣操百丈牽，臨難無苟避。", "濆向江底發，水在石中沸。", "槌鼓稱打寛，繫紉呼下緯。", "善惡胡可分，死生何足諱。", "騎衡與垂堂，非不知前喻。", "臨淵與履冰，非不知深慮。", "我今縻搢紳，善地誰人致。", "城狐與社鼠，巧佞誰從庇。", "奴顔與婢膝，醜直誰從媚。", "妻兒夐限越，容顔幾憔悴。", "致身霄漢人，呝嚱盡賢智。"]'),
('251ba973-dc72-4dab-bfc9-5e0ff0606b22','巫山廟','王周','宋','宋诗','song-poetry','','[]','廟前溪水流潺潺，廟中修竹聲珊珊。',32,'全唐诗/poet.song.8000.json','["廟前溪水流潺潺，廟中修竹聲珊珊。", "襄王一夢杳難問，晚晴天氣歸雲閑。"]'),
('b5606f3e-2cbf-4608-be7a-a6efda10a6a1','下瞿塘寄時同年','王周','宋','宋诗','song-poetry','','[]','春寒天氣下瞿塘，大壤溪前柳線長。',32,'全唐诗/poet.song.8000.json','["春寒天氣下瞿塘，大壤溪前柳線長。", "須信孤雲似孤宦，莫將鄉思附歸艎。"]'),
('45c148aa-aa25-4ed0-8f0e-50f48b4eb234','和杜運使巴峡地暖節物與中土異黯然有感詩三首  其一','王周','宋','宋诗','song-poetry','','[]','隨柳參差破綠芽，此中依約欲飛花。',32,'全唐诗/poet.song.8000.json','["隨柳參差破綠芽，此中依約欲飛花。", "春光是處傷離思，何況歸期未有涯。"]'),
('c79613c0-c33f-4434-b688-ebb62ee197d8','和杜運使巴峡地暖節物與中土異黯然有感詩三首  其二','王周','宋','宋诗','song-poetry','','[]','始看菊蘂開籬下，又見梅花寄嶺頭。',32,'全唐诗/poet.song.8000.json','["始看菊蘂開籬下，又見梅花寄嶺頭。", "攬轡巴西官局冷，幾憑春酒沃鄉愁。"]'),
('4df3429b-e47e-4917-aa4f-120cfd359d44','和杜運使巴峡地暖節物與中土異黯然有感詩三首  其三','王周','宋','宋诗','song-poetry','','[]','花品姚黄冠洛陽，巴中春早羡孤芳。',32,'全唐诗/poet.song.8000.json','["花品姚黄冠洛陽，巴中春早羡孤芳。", "不知别有栽培力，流詠新詩與激昂。"]'),
('2881337b-d067-466e-b4b3-1aa4dcef7091','施南太守以猿兒爲寄作詩答之','王周','宋','宋诗','song-poetry','','[]','虞人初獲酉江西，長臂難將意馬齊。',32,'全唐诗/poet.song.8000.json','["虞人初獲酉江西，長臂難將意馬齊。", "今日未啼頭已白，不堪深入白雲啼。"]'),
('5b67a5c2-6c03-43c5-913f-8b7c4e231aca','巫廟','王周','宋','宋诗','song-poetry','','[]','巴水走若箭，峡山開如屏。',180,'全唐诗/poet.song.8000.json','["巴水走若箭，峡山開如屏。", "洶湧匹練白，𡷾崒濃藍青。", "崖空蓄雲雨，灘惡驚雷霆。", "神仙宅幽邃，廟貌横杳冥。", "隱約可一夢，縹緲餘千齡。", "名利有所役，舟楫無暫停。", "悉窣垂肹蠁，祠禱希安寧。", "鵶鵶爾何物，飛飛来廟庭。", "紛紛颺寥泬，遠近随虚舲。", "鐵石礪觜爪，金碧輝光翎。", "翔集託陰險，鵮啄貪羶腥。", "日既恃威福，歲久爲精靈。", "依草與附木，誣詭殊不經。", "城狐與社鼠，瑣細何足聽。", "況乎人假人，心闊吞滄溟。"]'),
('7e1483f5-f954-4e94-a735-163ecd639358','赤壁','王周','宋','宋诗','song-poetry','','[]','帳前斵案決大議，赤壁火船燒戰旗。',32,'全唐诗/poet.song.8000.json','["帳前斵案決大議，赤壁火船燒戰旗。", "若使曹瞞忠漢室，周郎焉敢破王師。"]'),
('ec641678-a605-4786-a739-9e2973a0499e','奉和御製看毛詩詩三章二章十二句一章八句  其一','夏竦','宋','宋诗','song-poetry','','[]','周道洽平，聲動文成。',67,'全唐诗/poet.song.8000.json','["周道洽平，聲動文成。", "周王棄善，俗移風變。", "哀樂異心，治亂殊音。", "心發言從，影響攸同。", "政行音類，壎箎靡異。", "實教化之所由，故能經乎天而緯乎地。"]'),
('e1f71e59-da31-4626-bfe8-0f608e3b148a','奉和御製看毛詩詩三章二章十二句一章八句  其二','夏竦','宋','宋诗','song-poetry','','[]','生民尊祖，時邁告成。',68,'全唐诗/poet.song.8000.json','["生民尊祖，時邁告成。", "江漢撥亂，鳬鷖持盈。", "四詩之道，始于和平。", "五際之變，通于晦明。", "宣宥密之基命，敭遹駿之休聲。", "或箴規于闕政，或歎咏于芳馨。"]'),
('32578e6f-318f-4512-8a45-1b3b9b2f384e','奉和御製看毛詩詩三章二章十二句一章八句  其三','夏竦','宋','宋诗','song-poetry','','[]','温柔之教，政治之源。',54,'全唐诗/poet.song.8000.json','["温柔之教，政治之源。", "瞽能誦兮可以諫，士不學兮無以言。", "蓋盛衰之所繫，故諷諭之攸存。", "惟聖心兮垂思，永大庇兮元元。"]'),
('4ccaaafd-0408-45b3-af81-ab48d541bea7','奉和御製迎聖像中路獲金龍送還茅山','夏竦','宋','宋诗','song-poetry','','[]','巍巍真像範金成，瑞節棠舟遠導迎。',192,'全唐诗/poet.song.8000.json','["巍巍真像範金成，瑞節棠舟遠導迎。", "精衷勵翼符神貺，藻衛葳蕤率禮經。", "蘭隄曉景漣猗靜，神龍報降祥雲映。", "雙上瓊干采質明，旁臨旌栧靈輝盛。", "台臣祗肅薦華薌，承賀凝貞拜露章。", "羲氏官名高可擬，漢家年紀遠難方。", "鳯蓋分陰騰九色，蜿蜒共戯雲裳側。", "御天飛躍世空聞，瑞德縈盤今始識。", "騤騤矯首仰中宸，丹扆深嘉美應臻。", "紓禮既能疇聖日，爲霖當使福蒸人。", "華陽翠壑貞靈地，星使送還彰睿志。", "更播雲章入管絃，昭昭億載傳金匱。"]'),
('7ba39d75-b7d5-4493-aa44-5b460b666aa7','奉和御製崇政殿宴從臣','夏竦','宋','宋诗','song-poetry','','[]','青綺禁門符命錫，離珠御府天琛積。',164,'全唐诗/poet.song.8000.json','["青綺禁門符命錫，離珠御府天琛積。", "兩儀流慶會休期，二聖詒謀歸盛德。", "大禮修，真猷格，懿鑠昭昭兮靡極。", "阜民財，形物力，聖志乾乾兮夕惕。", "金扉玉宇麗皇居，鳯藻鸞蹤輝樂石。", "龜趺螭首建靈辰，鵲尾龍香奉至神。", "日轉翠華臨閣道，天旋丹仗復鈎陳。", "縉紳茂寵兮踰三接，羽衛鴻儀兮備九賓。", "瓊觴傳滿兮均堯酒，柏殿賡颺兮洽漢臣。", "奉若靈心彌翼翼，布昭醲化愈淳淳。"]'),
('d295deaf-099e-4929-9f2d-1e85b18ce066','奉和御製爲政歌','夏竦','宋','宋诗','song-poetry','','[]','黼帳夜分常監寐，鳯軒端委敷文治。',128,'全唐诗/poet.song.8000.json','["黼帳夜分常監寐，鳯軒端委敷文治。", "肇建元封陟介丘，寖尋毖祀臨汾水。", "茂烈馨香久際天，精心勵翼彌恭已。", "體道推仁洽惠和，斵凋歸厚蠲華侈。", "懷柔四貊盡來庭，邊圉無塵似平砥。", "堯德欽明惇茂族，漢條寛大措祥刑。", "永觀禹畫同文軫，更佇虞巡審量衡。", "睿政無爲猶日慎，布昭謨訓掩湯銘。"]'),
('2baeb1ad-e583-485c-9ae2-023014d04175','奉和御製奉先歌','夏竦','宋','宋诗','song-poetry','','[]','皇家兮仙祖，上世兮聖神。',379,'全唐诗/poet.song.8000.json','["皇家兮仙祖，上世兮聖神。", "承雲兮分治，駕羽兮臨民。", "誕昭兮馨烈，高陟兮元真。", "載乘土運臨三古，屬象羲農振遐武。", "爰炳明靈陟上蒼，綿綿聖緒慶悠長。", "既積仁兮累德，爰振耀兮流芳。", "罄二儀兮垂祐，彌萬祀兮開祥。", "巍巍烈祖兮膺宸歷，御瑤圖兮建鼇極。", "東征西怨兮振羣黎，下舞上歌兮康庶國。", "優游亮直顯敦仁，錫羡休嘉符拓迹。", "四貊名王尺組羈，九涯遠道安車適。", "聖功耆定實登三，方賮駿奔惟旅百。", "赫赫神宗廓帝紘，昭廣運兮洽和平。", "禮適素青兮沿夏子，化歸醲粹兮復胥庭。", "憲六學兮昭地緯，事七廟兮奉天經。", "震疊威霆兮踰朔幕，汪洋惠露兮浹編氓。", "偃節靈臺兮黜武，漏魚寛網兮蠲刑。", "三葉緝熙兮隆紹繼，皇穹右序兮隤繁祉。", "徘徊飇歘兮授元符，焜燿樵蒸兮修茂禮。", "思文成頌兮迪先謀，多黍申歌兮昭樂歲。", "參侔開闔已無爲，虔鞏盈成彌若厲。", "惟寤寐兮符通，實天人兮合契。", "降僊馭兮自三清，諭靈源兮踰百世。", "遐錫鴻休茂本枝，永符盛德昭明類。"]'),
('c283c275-2a0b-4d54-bedb-ba0b4374b49c','奉和御製筆歌','夏竦','宋','宋诗','song-poetry','','[]','制之精兮漢宫之雙管，鋒之妙兮趙國之修毫。',128,'全唐诗/poet.song.8000.json','["制之精兮漢宫之雙管，鋒之妙兮趙國之修毫。", "自承掌握濟羣用，觚與槧兮難施勞。", "古今罔不達，淑慝将何逃。", "深仰玉蟾均硯滴，詎慚金馬制書刀。", "頡皇觀迹蟲篆興，纖端積潤八體成。", "寫圖始告姬公瑞，錯寶終傳路扈名。", "上聖惟聰炳帝文，宸章奎畫冠生民。", "灑翰翠珉垂睿式，珥彤丹地寵儒臣。"]'),
('8c016149-6dbc-42de-9adc-b2ca9c0619d1','奉和御製硯歌','夏竦','宋','宋诗','song-poetry','','[]','南方潛璞出寒溪，沉沉紫蔚凝堅姿。',144,'全唐诗/poet.song.8000.json','["南方潛璞出寒溪，沉沉紫蔚凝堅姿。", "兩儀肖象磨礱異，三趾承隅琢餙奇。", "銀带参華貢雙闕，玉蟾分滴潤圓池。", "微波澄淡當晴景，旌旗半浸龍蛇影。", "輕浮春絮拂犀榦，微動日華明綺井。", "蘂簡交輝九禁深，玉枝斜照中宵永。", "列璇臺兮今得地，邇清光兮叶靈契。", "宣絲旨兮揚聖謨，贊雲章兮熙睿志。", "彌彰盛德冠生民，務以文明化兆人。"]'),
('71f6af33-65ba-4fee-b92f-ad0f19ff0f78','奉和御製墨歌','夏竦','宋','宋诗','song-poetry','','[]','昔造圖書兮紀方志，鉛黄丹漆兮初爲貴。',168,'全唐诗/poet.song.8000.json','["昔造圖書兮紀方志，鉛黄丹漆兮初爲貴。", "後世增華兮邁昔賢，松煙布色兮明且妍。", "一枝均賜官儀備，九子分形吉禮全。", "寫功詠德盈緗帙，體物緣情徧綺牋。", "陰山潛璞兮琢金池，相須藝圃兮事攸宜。", "湘川青管兮束圓鋒，並列璇臺兮用本同。", "垂大訓，述微言，孔墨之教兮長存。", "騰藻翰，贊儀形，淵雲之妙兮惟精。", "上聖敦仁崇儉約，厥篚珍奇詔皆却。", "唯許隃糜歲貢臻，式彰文德化生民。"]'),
('ae1bb9d9-a6a9-4cbe-b2e4-8b487b229b93','奉祀禮畢還京','夏竦','宋','宋诗','song-poetry','','[]','先天密命啟禎期，侯日靈文降紫闈。',374,'全唐诗/poet.song.8000.json','["先天密命啟禎期，侯日靈文降紫闈。", "恭館靖尊妙化，帝居齋祓擁純禧。", "勒鴻昭姓增梁甫，報本祈年款魏脽。", "真御下臨彰日監，嘉生誕降示天隨。", "丕承寶緒增寅畏，惠迪靈猷務肅祇。", "國陽郊報尊天位，欽奉后祇将合祭。", "仁里爰瞻嚴父祠，徐鑾式徇黎萌意。", "攸司經始兮載嚴，象物應斯兮紹至。", "熒煌先道兮珍符，煥衍参塗兮藻衛。", "真場合奏兮笙鏞，靈阯欽柴兮圭幣。", "三氣晬容兮仰覿，八景飛輿兮降格。", "青祺簡簡兮淵沖，瑞命禳禳兮山積。", "合飲譙城洽睿慈，仁風溥暢宣和懌。", "制畿睢水煥先謨，惠露汪洋敷潤澤。", "納賈陳詩兮總舊章，念功繼絕兮昭明德。", "近甸回衡景念新，太宫歸格物華春。", "太和充鬱層霄外，協氣周流率土濱。", "穆穆天章騰聖域，巍巍道蔭庇生民。", "體元化，叙彝倫，順則兮穹旻。", "觀秘奥，守精真，謹度兮聲身。", "四貉兮來同，千齡兮應會。", "甘實兮積中，英蕤兮發外。", "皇哉曼壽保丕基，青簡遐昭帝者儀。", "道冠周詩心翼翼，功踰夏載日孜孜。"]'),
('abf15881-8b1c-4f1c-906f-eb5b008b3b5f','奉和御製玉清昭應宫甘露歌','夏竦','宋','宋诗','song-poetry','','[]','祝聖清場初展禮，鴻都向曉彰繁祉。',130,'全唐诗/poet.song.8000.json','["祝聖清場初展禮，鴻都向曉彰繁祉。", "鬱鬱纖枝正後凋，瀼瀼瑞采俄雰委。", "吉雲五色比還疏，况是嚴冬歲律餘。", "承以玉杯甘若蜜，凝于翠幄皎如珠。", "薦宸居，稱壽酒，宣大慶兮仰歸元首。", "香馥馥，斾央央，建靈壇兮茂對多祥。", "天心信與人心會，誕節将臨遽霑霈。", "式昭真蔭祚君王，永錫遐齡齊覆載。"]'),
('dcd6bc8c-ca01-4ee9-ac06-e7e3db0ea6b1','奉和御製宣讀天書','夏竦','宋','宋诗','song-poetry','','[]','赫赫穹符迪慶基，巍巍真緒擁繁禧。',384,'全唐诗/poet.song.8000.json','["赫赫穹符迪慶基，巍巍真緒擁繁禧。", "控飈靈御傳天意，候日珍文告帝期。", "奉詣喬丘彰錫祉，胙壤瀨鄉修茂禮。", "宸闈薰祓款雲輿，戎候耕耘櫜象弭。", "紀號惟新歲歷呈，三元初吉協休辰。", "徽冊奉天熙事蕆，丕名尊祖皇儀展。", "太宫薦鬯孝思伸，陽位升煙鴻慶遠。", "瑞應紛綸百福同，寅威寶命務尊崇。", "布宣精意誠明顯，申飭攸司憲度隆。", "将披秘藴昭靈契，欲使萬方知帝意。", "肆眚端門詔畢旋，靈場預啟百枝燃。", "夙陳路寝敷瑤席，躬薦真香奏瑞煙。", "三辰淳耀居齋室，階滿祥蓂當望日。", "大裘陟降既登歌，羣后延登皆上笏。", "元輔披縢聖訓揚，樞臣援翰寶文彰。", "有虞出洛龜休躍，唐氏衘圖鳯罷翔。", "辭若洞章皆擿句，字如龍篆宛分行。", "森沉虎斾嚴真衛，肅穆珠旒增潔志。", "敬受丹書豈易侔，式旌玉刻誠難繼。", "修修羽帳降星辰，杳杳飈斿駐聖真。", "庭際煙霞輝曄曄，天中鸞鶴羽兟兟。", "微密妙言爰備舉，龐鴻盛則已宣臻。", "一一嘉猷保元后，諄諄深旨爲含生。", "寫成别笈緘藏密，薦獻禮周彌襲吉。"]'),
('bc5aaa7c-5458-4ce0-b655-bd87a2732e05','奉和御製幸金明池','夏竦','宋','宋诗','song-poetry','','[]','朱輅乘時兮出曉烟，飛梁承幸兮斗城邊。',104,'全唐诗/poet.song.8000.json','["朱輅乘時兮出曉烟，飛梁承幸兮斗城邊。", "幔省蔭堤兮楊葉闇，星旄藻岸兮物華妍。", "珠網金鋪兮豫章館，風檣桂楫兮木蘭船。", "象潢儀漢兮澄波遠，激水尋橦兮妙戯全。", "佇帝暉兮凝制蹕，人煥衍兮歡心逸。", "嘉流景兮延邇臣，樂清明兮麗新曲。"]'),
('b411a000-81b7-4ae2-8177-48ea03b51e43','奉和御製七夕','夏竦','宋','宋诗','song-poetry','','[]','紫皇宴服出瑤臺，仗下凉宵水殿開。',160,'全唐诗/poet.song.8000.json','["紫皇宴服出瑤臺，仗下凉宵水殿開。", "初月上絃光汎灔，横河案户勢徘徊。", "扇分蘭露侵衣滴，簾捲天香拂帳來。", "閣道森沉飛絳節，龍璈鳯吹凌霄發。", "琥車縹緲際煙潯，釦砌迢遙望雲闕。", "百子池深列宿分，九微燈淡纖塵絕。", "雲屏輕箑貫雙針，彩縷縈風勢不任。", "露挹瓊蘇敷碧席，明霞照地光無極。", "西漢元封五葉時，猗蘭雲輦會真期。", "何如法坐嘉蕃熟，高振薰絃播緝熙。"]'),
('650ab7a7-1282-44ec-a720-ce93b8e1eb50','黄鶴樓歌','夏竦','宋','宋诗','song-poetry','','[]','城上危樓高縹緲，城下澄江復相繞。',128,'全唐诗/poet.song.8000.json','["城上危樓高縹緲，城下澄江復相繞。", "有時漾影入中流，俯看魚游仰飛鳥。", "近樓多少未行舟，滿江落花灑汀洲。", "人同江狎不怕浪，登樓對酒弹箜篌。", "大别山頭白雲起，金口渡邊雨如洗。", "半鈎新月上孤城，還照高樓與江水。", "晴江依舊瀉潯陽，黄鶴無由歸故鄉。", "一聲玉笛起何處，燕撲闌干花影長。"]'),
('5c9b4b69-0a05-4b2e-9fbf-f5c6aed2b750','三月施州進金色小龜','夏竦','宋','宋诗','song-poetry','','[]','清江涵德澤，嘉瑞效靈龜。',48,'全唐诗/poet.song.8000.json','["清江涵德澤，嘉瑞效靈龜。", "巢葉形偏小，如金色最奇。", "玉靈慚異質，繹屬近幽姿。", "騎置遙承獻，觀圖仰帝祺。"]'),
('eb28e17e-b5eb-4298-b43e-4066b0cb4225','大中祥符七年七月錦州奏天慶觀修聖祖殿畢五色雲三朵各方丈餘見於殿上','夏竦','宋','宋诗','song-poetry','','[]','仙祠成秘殿，遠郡在盧陽。',48,'全唐诗/poet.song.8000.json','["仙祠成秘殿，遠郡在盧陽。", "旭日初流景，卿雲忽降祥。", "三枝分玉葉，五色照琳房。", "元后成真蔭，欽柴報上蒼。"]'),
('ddbf9115-787b-48b1-aa69-710307f7c213','八年正月天慶節上清宫行香錫慶院御筵日揚輝有非煙非霧之雲','夏竦','宋','宋诗','song-poetry','','[]','寶籙標嘉節，需雲錫惠筵。',48,'全唐诗/poet.song.8000.json','["寶籙標嘉節，需雲錫惠筵。", "烈暉騰愛景，瑞彩擬非煙。", "焜燿璿霄外，輪囷絳闕前。", "居歆方屢告，偉兆溢祥編。"]'),
('2fa45b25-f83d-44ea-8a99-3ca2f466d784','明州進芝草并圖','夏竦','宋','宋诗','song-poetry','','[]','四明開奥壤，三秀發靈芝。',48,'全唐诗/poet.song.8000.json','["四明開奥壤，三秀發靈芝。", "如蓋殊形聳，無根瑞氣滋。", "晨敷台嶺異，日茂下房奇。", "善氣方回復，充圖獻玉墀。"]'),
('a461d6fe-fcf8-4175-93ee-1e448a5b7f31','奉和御製讀史記詩  其一','夏竦','宋','宋诗','song-poetry','','[]','陶唐明歷象，茂氣與天通。',48,'全唐诗/poet.song.8000.json','["陶唐明歷象，茂氣與天通。", "舉正分星度，歸餘定歲功。", "孟陬名不殄，南正道彌隆。", "自此垂三代，循環協大中。"]'),
('0554fb55-afee-4da7-be9d-c242d56a1b8f','奉和御製讀史記詩  其二','夏竦','宋','宋诗','song-poetry','','[]','昭昭齊魯事，千載著良箴。',48,'全唐诗/poet.song.8000.json','["昭昭齊魯事，千載著良箴。", "欲辨爲邦體，先觀布政心。", "變民非遠略，從簡是徽音。", "北面無餘意，誠因惠物深。"]'),
('e896802a-89f8-4c76-ab04-5def6a17999f','奉和御製讀史記詩  其三','夏竦','宋','宋诗','song-poetry','','[]','漢武將從禪，須如亟釋兵。',48,'全唐诗/poet.song.8000.json','["漢武將從禪，須如亟釋兵。", "甘泉誠毖祀，喬嶽紀尊名。", "加禮崇休祉，修封蓋號榮。", "豈同承帝籙，肆覲正權衡。"]'),
('f6c13c9c-28b9-452b-b3ac-e59a8d993d36','奉和御製讀前漢書  其一','夏竦','宋','宋诗','song-poetry','','[]','酇侯依日月，天漢叙隆昌。',48,'全唐诗/poet.song.8000.json','["酇侯依日月，天漢叙隆昌。", "邁德居三傑，觀時定九章。", "過因王尉辯，功賴鄂君揚。", "終以同心美，清寧贊後王。"]'),
('2a81e243-9ddf-4f54-aa78-ff9a7ce7542f','奉和御製讀前漢書  其二','夏竦','宋','宋诗','song-poetry','','[]','子房天授漢，不戰道尤尊。',48,'全唐诗/poet.song.8000.json','["子房天授漢，不戰道尤尊。", "秘法盈編受，危機借箸論。", "避封昭止足，辟穀厭塵喧。", "莫訝蕭規茂，從容有緒言。"]'),
('9adc369d-a012-4880-a9f7-897f3c3265ca','奉和御製讀前漢書  其三','夏竦','宋','宋诗','song-poetry','','[]','高祖寛仁主，淮陰變詐才。',48,'全唐诗/poet.song.8000.json','["高祖寛仁主，淮陰變詐才。", "設壇誠有禮，推食本無猜。", "懷惠初顒若，夸功抑殆哉。", "何如中正者，千載仰高裁。"]'),
('9a3a1231-b2c0-4196-9348-6f4aaef3e62e','奉和御製讀後漢書詩  其一','夏竦','宋','宋诗','song-poetry','','[]','明帝章朝物，三雍復舊常。',48,'全唐诗/poet.song.8000.json','["明帝章朝物，三雍復舊常。", "籝金賞西域，雅樂奏南陽。", "拜老鴻徽茂，祈農盛典彰。", "珍符昭美應，獻壽表隆昌。"]'),
('bfea01d4-265a-4ca9-9d1f-af65a558091c','奉和御製讀後漢書詩  其二','夏竦','宋','宋诗','song-poetry','','[]','獨行懲澆俗，嘉名動遠荒。',48,'全唐诗/poet.song.8000.json','["獨行懲澆俗，嘉名動遠荒。", "至誠祈夏雨，嚴意勵冬霜。", "果行推陵險，豐規歎履方。", "孤高惟大遜，壽考茂祺祥。"]'),
('561c690a-7217-4657-87ad-73753becf8f6','奉和御製讀後漢書詩  其三','夏竦','宋','宋诗','song-poetry','','[]','昭公詳漢律，求比禮三千。',48,'全唐诗/poet.song.8000.json','["昭公詳漢律，求比禮三千。", "刻敝深文息，寛平治德全。", "芳猷宣輔弼，餘慶茂忠賢。", "方驗來嘉瑞，仁矜理最先。"]'),
('b2eac2ee-1678-4667-81aa-6d1d1d888eee','奉和御製讀三國志詩  其一','夏竦','宋','宋诗','song-poetry','','[]','白馬當塗兆，黄家得歲興。',48,'全唐诗/poet.song.8000.json','["白馬當塗兆，黄家得歲興。", "金符威既重，玉版事堪憑。", "漢火承前運，譙龍合舊徴。", "青雲開後葉，下武倍兢兢。"]'),
('e62d716b-13b9-4156-8a33-0e8e071f9497','奉和御製讀三國志詩  其二','夏竦','宋','宋诗','song-poetry','','[]','許昌功未逞，江表地初平。',48,'全唐诗/poet.song.8000.json','["許昌功未逞，江表地初平。", "漢帝居非遠，吳侯志欲迎。", "壯圖雖未遂，嘉慮實惟精。", "終闕尊崇禮，何關慎器名。"]'),
('90743242-9338-4b81-8f0a-09b20c398b78','奉和御製讀三國志詩  其三','夏竦','宋','宋诗','song-poetry','','[]','家乘桑蓋瑞，國富卧龍才。',48,'全唐诗/poet.song.8000.json','["家乘桑蓋瑞，國富卧龍才。", "漢水神暉徹，靈圖密命開。", "横天嘉氣應，繼日景雲來。", "儻乏英雄器，三分亦殆哉。"]'),
('ca13a259-fc4b-4a22-8981-d8e93abf8726','奉和御製讀晉書  其一','夏竦','宋','宋诗','song-poetry','','[]','安石陵霞致，清言振玉音。',48,'全唐诗/poet.song.8000.json','["安石陵霞致，清言振玉音。", "鴻勳濟世久，厚德感人深。", "朱組雖然襲，虛舟豈易沉。", "東山高志在，瀟灑謝塵襟。"]'),
('78b2cd84-c399-4cd4-8563-dd95e5028b5b','奉和御製讀晉書  其二','夏竦','宋','宋诗','song-poetry','','[]','李重推清雅，初傳友愛名。',48,'全唐诗/poet.song.8000.json','["李重推清雅，初傳友愛名。", "嘉言爲時發，大誼傅經明。", "崇德誠堪慕，修身豈易傾。", "留心衆才舉，千載仰銓衡。"]'),
('2a464bbe-f56b-4285-addf-594bcd9266f0','奉和御製讀晉書  其三','夏竦','宋','宋诗','song-poetry','','[]','士行勤武力，機鑒信良哉。',48,'全唐诗/poet.song.8000.json','["士行勤武力，機鑒信良哉。", "國賴桓文業，人推葛陸才。", "殊祥雙鶴至，吉夢八門開。", "終始全高節，誠因左翼推。"]'),
('95eb8bf4-58cb-4f18-9f37-3f99f5033372','奉和御製讀宋書  其一','夏竦','宋','宋诗','song-poetry','','[]','漢宗開聖緒，得歲與周同。',48,'全唐诗/poet.song.8000.json','["漢宗開聖緒，得歲與周同。", "金石終移律，山河始誓功。", "飛名傳秘記，嘉讖起游童。", "能使姦豪讋，誠爲一世雄。"]'),
('dba79810-97a5-4939-a849-43aec94d478e','奉和御製讀宋書  其二','夏竦','宋','宋诗','song-poetry','','[]','鎮惡才明舉，英雄想冠時。',48,'全唐诗/poet.song.8000.json','["鎮惡才明舉，英雄想冠時。", "推鋒平內侮，直指定西陲。", "向使鴻勳就，寧憂霸業衰。", "如何喪方召，遺烈漫傷咨。"]'),
('e909cd5c-0b55-4884-aa23-86d14ec714b1','奉和御製讀陳書  其一','夏竦','宋','宋诗','song-poetry','','[]','猛奴多勇槩，大矟事戎征。',48,'全唐诗/poet.song.8000.json','["猛奴多勇槩，大矟事戎征。", "新蔡兇圍陷，魚梁寇壘傾。", "遡風輕古法，間道貴奇兵。", "懋賞宜開府，番禺已盡平。"]'),
('cca53dab-2058-456d-8b95-1bac432d5639','奉和御製讀陳書  其二','夏竦','宋','宋诗','song-poetry','','[]','靈洗雖驍勇，忠規詎可輕。',48,'全唐诗/poet.song.8000.json','["靈洗雖驍勇，忠規詎可輕。", "石城嘗力戰，黟歙本連盟。", "京口殊勳茂，臨川叛寇驚。", "既能明號令，何惜務寛平。"]'),
('6e1017d8-30a0-45ef-84f3-8dfcdcb5d8f7','奉和御製讀後魏書  其一','夏竦','宋','宋诗','song-poetry','','[]','偉哉登國世，靈武定戎兵。',48,'全唐诗/poet.song.8000.json','["偉哉登國世，靈武定戎兵。", "拓土能圖大，求才實勵精。", "公侯新爵重，臺省舊風清。", "自匪謨長世，鴻圖豈易成。"]'),
('aef18859-bda7-48be-88c0-54523098e819','奉和御製讀後魏書  其二','夏竦','宋','宋诗','song-poetry','','[]','高祖寛仁主，哀矜信有餘。',48,'全唐诗/poet.song.8000.json','["高祖寛仁主，哀矜信有餘。", "嚴刑幾盡措，黎庶獲安居。", "舊法躬刊定，繁文再剗除。", "既平財謁路，清白勵簪裾。"]'),
('572ba2e0-e609-4c46-8f3f-e64c9828b9ec','奉和御製讀後魏書  其三','夏竦','宋','宋诗','song-poetry','','[]','真君昭密命，紀號表興隆。',48,'全唐诗/poet.song.8000.json','["真君昭密命，紀號表興隆。", "瑞著洪河外，文成翠石中。", "帝名傳祖禰，曆數感王公。", "三五方興運，明符事亦同。"]'),
('98495aa8-7607-4c1d-b069-bdc1d86d3941','奉和御製讀北齊書  其一','夏竦','宋','宋诗','song-poetry','','[]','段氏推忠武，論兵特造微。',48,'全唐诗/poet.song.8000.json','["段氏推忠武，論兵特造微。", "歷朝功並建，諸將令咸依。", "重位無矜色，高門有德輝。", "當時勳貴族，孰不仰家肥。"]'),
('cfdfa10e-f18f-4c59-95fe-dcaba205f1f8','奉和御製讀北齊書  其二','夏竦','宋','宋诗','song-poetry','','[]','咸陽誠赳赳，倚任極維師。',48,'全唐诗/poet.song.8000.json','["咸陽誠赳赳，倚任極維師。", "貴勢隆門緒，忠誠翼帝基。", "享年常戒滿，避寵或興咨。", "不學良無愧，嘉名已自垂。"]'),
('64fe659a-6abd-4076-ae65-d1aad3316989','奉和御製讀後周書  其一','夏竦','宋','宋诗','song-poetry','','[]','思道懷廉慎，童年類老成。',48,'全唐诗/poet.song.8000.json','["思道懷廉慎，童年類老成。", "郡豪嘗讋服，邊寇亦清平。", "臨難輸忠節，辭榮保令名。", "賢哉蹈仁義，舉世可爲程。"]'),
('6aaa0efb-c914-437d-a4b5-85a876126b89','奉和御製讀後周書  其二','夏竦','宋','宋诗','song-poetry','','[]','南荆推德厚，千里遠從師。',48,'全唐诗/poet.song.8000.json','["南荆推德厚，千里遠從師。", "奥識通三教，清聲冠一時。", "就招雖暫至，戀本固難移。", "故老稱前事，儒宗道益滋。"]'),
('575869a2-efef-4aa8-aa3c-4675169b1f67','奉和御製讀後周書  其三','夏竦','宋','宋诗','song-poetry','','[]','遷哲承華緒，深謀事戰征。',48,'全唐诗/poet.song.8000.json','["遷哲承華緒，深謀事戰征。", "艱危思大節，慷慨得羣情。", "惠愛均戎旅，威名震敵城。", "江陵摧寇勢，宵遁賴奇兵。"]'),
('684b2185-929a-4ffa-adb0-f896af484fb0','奉和御製讀隋書  其一','夏竦','宋','宋诗','song-poetry','','[]','里仁懷遠度，大雅擅嘉名。',48,'全唐诗/poet.song.8000.json','["里仁懷遠度，大雅擅嘉名。", "制禮通時變，求書贊治平。", "推心清選舉，從儉化黎氓。", "終始承恩遇，芳猷冠老成。"]'),
('0f8c79db-f4fa-472b-b247-b473530ac2b9','奉和御製讀隋書  其二','夏竦','宋','宋诗','song-poetry','','[]','榮定誠嘉器，攀鱗屬盛時。',48,'全唐诗/poet.song.8000.json','["榮定誠嘉器，攀鱗屬盛時。", "賞勞恩特異，知足志惟熙。", "壯節承昭感，崇基保燕詒。", "但能思衛霍，自可比蓍龜。"]'),
('14e1275c-0775-4463-ae9b-54ef01edb4f9','奉和御製讀隋書  其三','夏竦','宋','宋诗','song-poetry','','[]','子蓋懷英斷，南荒久駐留。',48,'全唐诗/poet.song.8000.json','["子蓋懷英斷，南荒久駐留。", "清通承眷奬，恭順望巡游。", "異寵榮鄉黨，丹誠破寇仇。", "邊民思舊愛，刻石在西州。"]'),
('f7f0bb50-42d2-4e0d-aff7-68fdd27b5cc9','奉和御製讀唐書  其一','夏竦','宋','宋诗','song-poetry','','[]','天祚文皇德，元成雅道施。',48,'全唐诗/poet.song.8000.json','["天祚文皇德，元成雅道施。", "納忠裨闕政，偃革致昌期。", "宴喜刀方解，人亡鑑遽隳。", "數行遺奏在，猶可動神祗。"]'),
('21dee3f2-8904-4deb-a116-e373b73b2c0c','奉和御製讀唐書  其二','夏竦','宋','宋诗','song-poetry','','[]','哲輔延清問，元和致治平。',48,'全唐诗/poet.song.8000.json','["哲輔延清問，元和致治平。", "從人成庶務，求瘼濟羣氓。", "務遠能無怠，求材可倚成。", "乃知虞舜德，恭已固難名。"]'),
('946c6f3f-78cd-445f-954e-c6a46cf44255','奉和御製讀唐書  其三','夏竦','宋','宋诗','song-poetry','','[]','賢哉段忠烈，振迹自邠寧。',48,'全唐诗/poet.song.8000.json','["賢哉段忠烈，振迹自邠寧。", "動必懷剛毅，何嘗廢典刑。", "英規方貫古，樂石諒難銘。", "密議初如用，艱危豈易形。"]'),
('bfd4241d-8d46-4858-b38f-67067a728e1d','奉和御製讀五代梁史  其一','夏竦','宋','宋诗','song-poetry','','[]','李唐危漢祚，巢寇盛黄巾。',48,'全唐诗/poet.song.8000.json','["李唐危漢祚，巢寇盛黄巾。", "嘉士逢多難，忠言變逆倫。", "决疑歸大順，定策戮姦臣。", "宜享崇高贈，千年道更新。"]'),
('4f85f7ad-5937-4844-8b86-7b83675f63cd','奉和御製讀五代梁史  其二','夏竦','宋','宋诗','song-poetry','','[]','贊貞懷武鷙，轉鬬曆炎凉。',48,'全唐诗/poet.song.8000.json','["贊貞懷武鷙，轉鬬曆炎凉。", "誠感泉源異，兵嚴士庶康。", "臨危見忠憤，對敵擅威強。", "終始心無改，遺言更可傷。"]'),
('b39878e2-4d03-4082-8fbe-dbae66a692e2','奉和御製讀五代史後唐史  其一','夏竦','宋','宋诗','song-poetry','','[]','燕趙生奇士，仇方决志平。',48,'全唐诗/poet.song.8000.json','["燕趙生奇士，仇方决志平。", "十年常竭節，一劍早知名。", "自取河南鎮，終辭霸府兵。", "飛鷹昭慶路，窮達有高情。"]'),
('b7b0580f-abfc-43d6-8bc6-1062147e1938','奉和御製讀五代史後唐史  其二','夏竦','宋','宋诗','song-poetry','','[]','長興秉鈞者，子晦道攸隆。',48,'全唐诗/poet.song.8000.json','["長興秉鈞者，子晦道攸隆。", "剛介昌言遠，忠清茂澤豐。", "懿文常體道，妙略早從戎。", "可惜虧同德，當年阻建功。"]'),
('6f2a55bb-2dcc-42ec-8ad0-d2c3d0383aa8','奉和御製讀五代晉史  其一','夏竦','宋','宋诗','song-poetry','','[]','子文懷妙識，奥學洞天常。',48,'全唐诗/poet.song.8000.json','["子文懷妙識，奥學洞天常。", "恬淡游蓮幕，謙虚踐玉堂。", "至仁周僕御，大雅變詞章。", "慎默誠無怠，危機可盡防。"]'),
('42d952a2-9a59-4f2c-8fd1-7be32ef65e6e','奉和御製讀五代晉史  其二','夏竦','宋','宋诗','song-poetry','','[]','大雅懷忠孝，當年效戰征。',48,'全唐诗/poet.song.8000.json','["大雅懷忠孝，當年效戰征。", "詢謀無敗事，臨敵有奇兵。", "安陸祅狂殄，宗城寇難平。", "察廉能惻下，何患政難成。"]'),
('a7993716-c7eb-4d83-be5e-38144b1acb50','奉和御製讀五代漢史  其一','夏竦','宋','宋诗','song-poetry','','[]','危邦有賢哲，力戰鎮州平。',48,'全唐诗/poet.song.8000.json','["危邦有賢哲，力戰鎮州平。", "革弊還疲庶，從寛悦衆情。", "愛人惟責已，徇節幾忘生。", "青史惟馨在，千年仰令名。"]'),
('3f8d094d-11d3-4944-b733-97f8d282b820','奉和御製讀五代漢史  其二','夏竦','宋','宋诗','song-poetry','','[]','求益誠賢牧，廉平致樂康。',48,'全唐诗/poet.song.8000.json','["求益誠賢牧，廉平致樂康。", "歡謠騰近輔，盛典茂徽章。", "舊相親褒記，黎民競感傷。", "豐碑應不朽，千載咏惟良。"]'),
('884b27ba-604e-4c93-8278-968b877598cb','奉和御製讀五代周史  其一','夏竦','宋','宋诗','song-poetry','','[]','文懿艱危際，虚心自晏寧。',48,'全唐诗/poet.song.8000.json','["文懿艱危際，虚心自晏寧。", "依違慚問戰，閑淡貴無刑。", "鎮俗懲浮躁，尊儒鏤典經。", "忠誠虧美謚，良足愧幽靈。"]'),
('68d4a5cd-45f6-4613-ab27-28905e5c4499','奉和御製讀五代周史  其二','夏竦','宋','宋诗','song-poetry','','[]','文伯懷明識，英規世所推。',48,'全唐诗/poet.song.8000.json','["文伯懷明識，英規世所推。", "濟時陳策畫，急用備論思。", "隘郭爰增廣，煩音亦改爲。", "温恭非不濟，感遇志如茲。"]'),
('aade062c-b409-4d82-9091-20d7e71a92ba','奉和御製中和節','夏竦','宋','宋诗','song-poetry','','[]','中春遘初吉，嘉節著芳名。',48,'全唐诗/poet.song.8000.json','["中春遘初吉，嘉節著芳名。", "習習微和扇，欣欣萬物榮。", "雲融纔化鶴，谷暖已遷鶯。", "朝野多歡日，風謠會頌聲。"]'),
('7c8d10c7-e8e0-4c13-ac29-e79f14f52047','奉和御製會慶殿宴','夏竦','宋','宋诗','song-poetry','','[]','禁門乘曉會，宴豆示慈伸。',48,'全唐诗/poet.song.8000.json','["禁門乘曉會，宴豆示慈伸。", "激水龍騰久，儀韶鳯降頻。", "雲章流漢筑，衢酒洽堯民。", "百辟皆星拱，兢兢奉北辰。"]'),
('ee53420b-060f-47ee-9b09-3a3196bce282','二月昭州奏正月一日設醮上玉皇表燒錢次有鶴一隻翺翔久之西北去','夏竦','宋','宋诗','song-poetry','','[]','平樂初正月，虛晨薦號時。',48,'全唐诗/poet.song.8000.json','["平樂初正月，虛晨薦號時。", "瑞場燔碧幣，僊驥駐霜儀。", "煙頂方遙辨，星精想下闚。", "天門俄翼去，杳靄瑞煙披。"]'),
('d9c58e87-e0a2-4f29-ba75-fd686111e48f','野步','夏竦','宋','宋诗','song-poetry','','[]','顧步方塘上，西郊日漸曛。',48,'全唐诗/poet.song.8000.json','["顧步方塘上，西郊日漸曛。", "歸心臨遠渡，晚色在閑雲。", "壠勢蜂腰接，谿流鷰尾分。", "田歌知有意，豐美謝明君。"]'),
('c6c613a4-3b5e-46ab-866c-b2fb29bfca29','秋曉','夏竦','宋','宋诗','song-poetry','','[]','半庭殘月在，江郡鼓聲初。',48,'全唐诗/poet.song.8000.json','["半庭殘月在，江郡鼓聲初。", "秋氣滿南國，曉雲高太虛。", "負霜鴻翼健，含霧橘花疏。", "此景無人共，朝陽入敝廬。"]'),
('1757d373-38c9-47ed-9e5a-3bc10ed07751','靈溪','夏竦','宋','宋诗','song-poetry','','[]','剡東溪溜合，一派貫天台。',48,'全唐诗/poet.song.8000.json','["剡東溪溜合，一派貫天台。", "白鳥蒙灘下，青山倚岸迴。", "波心晴景動，渡口晚煙開。", "咫尺通滄海，千帆自去來。"]'),
('da486cd0-b46d-4821-bc26-eb9526e24f27','馬跑泉','夏竦','宋','宋诗','song-poetry','','[]','天驥何年往，龍泓此地存。',48,'全唐诗/poet.song.8000.json','["天驥何年往，龍泓此地存。", "空餘曳練色，莫辨褭蹄痕。", "赴海妨苔甃，涵虚礙竹軒。", "會當逢禹鑿，始可見鴻源。"]'),
('6a035365-6086-4e35-a1b7-fd2cbb0a4402','天台道中','夏竦','宋','宋诗','song-poetry','','[]','驅馬天台路，悠悠漸向晨。',48,'全唐诗/poet.song.8000.json','["驅馬天台路，悠悠漸向晨。", "雲開忽見寺，山盡偶逢人。", "細雨疏篁長，微烟古木春。", "行行遙驛道，落吹起輕塵。"]'),
('13fc88dd-b808-438b-a540-a5e0af5f3f62','石梁','夏竦','宋','宋诗','song-poetry','','[]','斷澗横幽石，蒼苔古木陰。',48,'全唐诗/poet.song.8000.json','["斷澗横幽石，蒼苔古木陰。", "欹危接山腹，迢逓過雲心。", "峭壁峙千仞，飛流下萬尋。", "秦人若驅策，蓬島路非深。"]'),
('e2cd2404-95fb-4ec7-bf50-167245411854','晚望','夏竦','宋','宋诗','song-poetry','','[]','雨霽吳城晚，谿泉四散流。',48,'全唐诗/poet.song.8000.json','["雨霽吳城晚，谿泉四散流。", "禽歸半峰樹，人在夕陽樓。", "國望分江海，星躔次斗牛。", "堪嗟興廢地，千載有閑愁。"]'),
('f63b6dca-4890-4fc5-95dd-82c63da107fe','鑑湖晚望','夏竦','宋','宋诗','song-poetry','','[]','新霜脱衰葉，寒日下疏篷。',48,'全唐诗/poet.song.8000.json','["新霜脱衰葉，寒日下疏篷。", "岸細低疑盡，波平闊似空。", "橋通越谿水，帆带剡川風。", "何處鳴簫鼓，叢祠杳靄中。"]'),
('bf10d341-adae-431c-88d7-6c43ce1a7f44','舟行即事','夏竦','宋','宋诗','song-poetry','','[]','微陽下江樹，秋葉泛殘紅。',48,'全唐诗/poet.song.8000.json','["微陽下江樹，秋葉泛殘紅。", "鴈背寒塘雨，帆爭晚渡風。", "寺橋人倒影，漁徑菊分叢。", "正是承平日，輕艘萬派通。"]'),
('a889a61b-0d0f-43d1-9616-9f7415992e8c','吳中懷古','夏竦','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','覽古長江上，明時起嘆嗟。',48,'全唐诗/poet.song.8000.json','["覽古長江上，明時起嘆嗟。", "水流吳國苑，花入野人家。", "夜氣銷龍劍，秋星見客槎。", "凄凉館娃樹，西日映平沙。"]'),
('d24d577a-e6fb-488b-92cb-6f7b88411bd0','桐柏觀','夏竦','宋','宋诗','song-poetry','','[]','鳥道寒藤結，洞門蒼蘚深。',48,'全唐诗/poet.song.8000.json','["鳥道寒藤結，洞門蒼蘚深。", "樓臺在山畔，松檜出雲心。", "土暖春長在，峰高月易沉。", "羽衣祠太乙，香冷石壇陰。"]'),
('b3148527-31e5-41aa-a44e-e8dcb0d70590','喜种隱君授正言直館','夏竦','宋','宋诗','song-poetry','','[]','鶴版招幽士，龍墀襲茜袍。',48,'全唐诗/poet.song.8000.json','["鶴版招幽士，龍墀襲茜袍。", "道因閑上得，名向隱中高。", "密地棲芸閣，清塗歷諫曹。", "終南明月夜，松檜自蕭騷。"]'),
('d4a75a33-31e2-42c4-aaea-2576afc1c4e2','贈海州使君','夏竦','宋','宋诗','song-poetry','','[]','天衢未得便，假道海邊城。',48,'全唐诗/poet.song.8000.json','["天衢未得便，假道海邊城。", "任大纔勝器，官閑不稱名。", "勸農吟少暇，憂物睡常輕。", "見說行春處，和風滿斾旌。"]'),
('0ba28ff1-e874-4175-be4e-d13a60518a2f','贈縣宰','夏竦','宋','宋诗','song-poetry','','[]','俸輕官且冷，君喜在親民。',48,'全唐诗/poet.song.8000.json','["俸輕官且冷，君喜在親民。", "村路不聞犬，縣城長似春。", "架高書少蠧，廳靜隙無塵。", "考滿留碑去，清風勵後人。"]'),
('a6eda327-89ba-4a4f-ab1b-c1a4b5f04e1b','贈逸人','夏竦','宋','宋诗','song-poetry','','[]','鳯鳥來爲瑞，達人垂羽翰。',48,'全唐诗/poet.song.8000.json','["鳯鳥來爲瑞，達人垂羽翰。", "語因希聖古，詩爲惜名難。", "泰華僊標峻，江湖酒量寛。", "孤琴有舜曲，留我月中彈。"]'),
('15036d04-239c-4023-8fd2-6171d86e235b','送張學士赴闕','夏竦','宋','宋诗','song-poetry','','[]','東觀嘗聯袂，南州各退飛。',48,'全唐诗/poet.song.8000.json','["東觀嘗聯袂，南州各退飛。", "同傾就日戀，先喜賜環歸。", "舊業懷鉛筆，晨裝振綵衣。", "離絃有餘思，凄切寄南徽。"]'),
('51201c07-5130-4f6f-b422-43bd52cde318','送益州同理張殿丞','夏竦','宋','宋诗','song-poetry','','[]','遠指三川路，初辭六尚班。',48,'全唐诗/poet.song.8000.json','["遠指三川路，初辭六尚班。", "占星度危棧，叱馭下靈關。", "職亞銅符重，兵銷玉帳閑。", "漢臺誰視草，應待長卿還。"]'),
('929b3958-f41b-4058-ac54-3d8e582fb1c9','送人出牧','夏竦','宋','宋诗','song-poetry','','[]','聖主念元元，良臣選掖垣。',48,'全唐诗/poet.song.8000.json','["聖主念元元，良臣選掖垣。", "紫墀分使節，紅斾出都門。", "雪淺斜陽路，雲深晚燒村。", "期年如報政，應許賀新恩。"]'),
('484627f1-c589-4a56-a627-9034c9443e1c','秋日送人南遊','夏竦','宋','宋诗','song-poetry','','[]','幾驛蘇臺路，輕裝轉塞蓬。',48,'全唐诗/poet.song.8000.json','["幾驛蘇臺路，輕裝轉塞蓬。", "夜船千櫂月，寒酒一旗風。", "水闇菰蒲老，山明橘柚紅。", "算君回首處，曉色五湖東。"]'),
('66405277-eb38-4f67-82c9-4b22e1272a23','秋日送人西上','夏竦','宋','宋诗','song-poetry','','[]','旅程看驛道，西去興何如。',48,'全唐诗/poet.song.8000.json','["旅程看驛道，西去興何如。", "南國秋霖後，斜陽樹影疏。", "野光飛翠羽，溪艶照紅蕖。", "好去朝端客，人爭草薦書。"]'),
('76ee0b24-c138-423f-a19c-1c418215ed83','送人','夏竦','宋','宋诗','song-poetry','','[]','野色兼行色，長亭一送君。',48,'全唐诗/poet.song.8000.json','["野色兼行色，長亭一送君。", "束書登古路，重繭踏寒雲。", "山過天台小，溪臨婺女分。", "流光須強學，當宁正崇文。"]'),
('46234247-541c-48fd-99ba-bf580622e44c','留題友人郊居  其一','夏竦','宋','宋诗','song-poetry','','[]','羣書架寒壁，庶事得從容。',48,'全唐诗/poet.song.8000.json','["羣書架寒壁，庶事得從容。", "花木移諸寺，雲泉借數峰。", "積陰春作雨，瘦竹老成筇。", "應笑南陽士，明朝久卧龍。"]'),
('ee0fc640-2ca0-4c52-8866-7df31eed391d','留題友人郊居  其二','夏竦','宋','宋诗','song-poetry','','[]','卜築遠朝市，著書成歲功。',48,'全唐诗/poet.song.8000.json','["卜築遠朝市，著書成歲功。", "長雲覆孤木，古道滿清風。", "地勝花房異，山靈雨氣通。", "綸巾不可戀，鶴版下關東。"]'),
('91ba73d7-4269-4e3c-8be7-2dbaef7a2c53','代村叟','夏竦','宋','宋诗','song-poetry','','[]','安居近幽谷，井賦籍良田。',48,'全唐诗/poet.song.8000.json','["安居近幽谷，井賦籍良田。", "聖代無深隱，家山不直錢。", "候耕看土脉，祈穀賽豚肩。", "城市知何處，疏鐘隔暮煙。"]'),
('25671bf4-0fae-4b11-8549-f8d318768fa1','國清寺','夏竦','宋','宋诗','song-poetry','','[]','穿松渡雙澗，宫殿五峰圍。',48,'全唐诗/poet.song.8000.json','["穿松渡雙澗，宫殿五峰圍。", "小院分寒水，高樓半落暉。", "葉從金地下，雲向玉京飛。", "欲問西來意，誰傳智者衣。"]'),
('9f192188-b8f0-42af-828d-654ff668f6e6','善慧師禪齋','夏竦','宋','宋诗','song-poetry','','[]','是誰名作佛，何法謂之禪。',48,'全唐诗/poet.song.8000.json','["是誰名作佛，何法謂之禪。", "恍惚起無象，逍遙出自然。", "有修皆障礙，欲問即攀緣。", "寄語猊牀客，心心不易傳。"]'),
('33c4318c-d877-4639-bb46-4042fa36a76b','虎丘僧舍閑望','夏竦','宋','宋诗','song-poetry','','[]','勝地訪靈蹤，層樓四檻風。',48,'全唐诗/poet.song.8000.json','["勝地訪靈蹤，層樓四檻風。", "遠陰生曠野，午影轉疏桐。", "澗水霞凝紫，谿煙日襯紅。", "可憐秋思晚，相倚館娃宫。"]'),
('bc04f94f-f975-48c9-9c69-e299bbe1298d','奉和御製瑞雪','夏竦','宋','宋诗','song-poetry','','[]','朔吹凄寒序，繁英降美祥。',72,'全唐诗/poet.song.8000.json','["朔吹凄寒序，繁英降美祥。", "潤將膏露接，時契聖心彰。", "不夜蟾輝滿，先春柳絮揚。", "龍沙度北野，鷴素失南鄉。", "帝苑敷瓊蘂，神池瑩玉塘。", "薰絃俄發詠，風雅邁岐昌。"]'),
('d50282fb-7f0b-4298-a551-f59cea352920','宣賜翠芳亭雙頭並蒂牡丹仍令賦詩','夏竦','宋','宋诗','song-poetry','','[]','華景當凝煦，芳叢忽效奇。',72,'全唐诗/poet.song.8000.json','["華景當凝煦，芳叢忽效奇。", "紅房爭並萼，緗葉競駢枝。", "綵鳯雙飛稳，霞冠對舞欹。", "游蜂時共翥，零露或交垂。", "勝賞回金蹕，清香透黼帷。", "兩宫昭瑞德，天意豈難知。"]'),
('9b7aadca-e3e2-45cb-9e65-c15fd1d6700f','奉和御製玉清昭應宫天書閣瑞應','夏竦','宋','宋诗','song-poetry','','[]','盛德靈謀協，元符寶字披。',72,'全唐诗/poet.song.8000.json','["盛德靈謀協，元符寶字披。", "真宫肇高閣，精意感鴻禧。", "曉箭傳初刻，朝陽吐半規。", "祥煙五色麗，嘉氣九華滋。", "汎灔金光溢，扶疏玉葉垂。", "堯心膺眷佑，欽翼愈孜孜。"]'),
('95ebd31a-56df-418f-810b-7d47ec73530b','奉和御製滋福殿清醮聖祖天尊大帝尊像瑞應','夏竦','宋','宋诗','song-poetry','','[]','宸闈啓瑞場，祗畏感穹蒼。',72,'全唐诗/poet.song.8000.json','["宸闈啓瑞場，祗畏感穹蒼。", "紫幄威神格，清宵景曜彰。", "霓旌承宇列，僊驥度雲翔。", "肸蠁停霞轡，歆馨挹鳯觴。", "蘿圖千葉固，山壽萬齡昌。", "玉籥流宸唱，函蒙播美祥。"]'),
('eb3faa23-a15c-4722-b25c-f175e8d6d73c','奉和御製天書道場觀神雀','夏竦','宋','宋诗','song-poetry','','[]','齋明尊寶籙，祇肅建真場。',72,'全唐诗/poet.song.8000.json','["齋明尊寶籙，祇肅建真場。", "上帝靈心顯，中宵瑞羽彰。", "入豐慚美應，上雍喜嘉祥。", "彩仗留輕迹，彤霞混葆章。", "乍衝香馥郁，高映繚熒煌。", "雲漢敷宸唱，繁禧浹萬方。"]'),
('b20b38c7-21e9-4547-9d2a-9f536dfc7188','奉和御製册府元龜了畢','夏竦','宋','宋诗','song-poetry','','[]','文德洽隆平，蓬山蠧簡盈。',72,'全唐诗/poet.song.8000.json','["文德洽隆平，蓬山蠧簡盈。", "漢金方盡購，秦石諒難程。", "稽古承先志，宣猷聚世英。", "刊修百家備，紬繹十年成。", "休沐當冬日，多歡奉相衡。", "豈期頒睿藻，何以報兹榮。"]'),
('fdf50432-b45a-4ff4-a963-93c59623394d','奉和御製告玉清昭應宫太廟禮成','夏竦','宋','宋诗','song-poetry','','[]','時巡將順豫，吉禮協休成。',72,'全唐诗/poet.song.8000.json','["時巡將順豫，吉禮協休成。", "先道真文肅，徐鑾瑞氣平。", "密都嘉薦備，太室令芳呈。", "清越鏘金奏，齋莊儼翠纓。", "矞雲朝薈蔚，花雪夜縈盈。", "煥衍昭繁祉，千齡表盛明。"]'),
('7867552b-a4b2-483d-a248-f7c3e0a38af8','奉和御製真遊殿成詩','夏竦','宋','宋诗','song-poetry','','[]','宵晤靈猷顯，彤庭藻衛臻。',96,'全唐诗/poet.song.8000.json','["宵晤靈猷顯，彤庭藻衛臻。", "鳯輿回八景，龍斾駐三辰。", "太古仙儀接，虚皇密誨伸。", "天枝鴻緒遠，殿翼舊規新。", "寶勢承基壯，祥輝燭地頻。", "叢楹虹带繞，彩制玉霄鄰。", "致孝常尊祖，祈禠永庇民。", "巍巍扄禁內，億載奉元真。"]'),
('73f4b600-5621-4e4d-86d7-9f61ee30b04b','奉和御製大酺','夏竦','宋','宋诗','song-poetry','','[]','瘞玉祠真畤，還衡格閟宫。',72,'全唐诗/poet.song.8000.json','["瘞玉祠真畤，還衡格閟宫。", "策勳恩已盛，合醵慶彌隆。", "法坐臨雙起，清音奏六同。", "羽毛秋色麗，簪紱曉光融。", "寵宴均堯酒，宸章起漢風。", "羣生遂鳬藻，何以報層穹。"]'),
('62b3927f-deaa-4afe-84bf-e7dd043b38f1','賞花釣魚應制','夏竦','宋','宋诗','song-poetry','','[]','上苑乘春啓，奇花效祉新。',96,'全唐诗/poet.song.8000.json','["上苑乘春啓，奇花效祉新。", "連房紅萼並，合榦綠枝勻。", "翦獻尊長樂，分頒寵輔臣。", "從遊過水殿，凝蹕近龍津。", "黼座臨雕檻，文竿引翠綸。", "波香投桂餌，萍暖漾金鱗。", "湛露芳尊酒，鈞天廣樂陳。", "多歡千載遇，何以報嚴宸。"]'),
('bc23ee29-0554-49f1-b2de-6f547ec24998','延福宫雙頭牡丹','夏竦','宋','宋诗','song-poetry','','[]','禁籞陽和異，華叢造化殊。',72,'全唐诗/poet.song.8000.json','["禁籞陽和異，華叢造化殊。", "兩宫方共治，雙蘤故聯跗。", "嚮日檀心並，承煙翠榦孤。", "游蜂須並翼，凝露亦駢珠。", "曉檻香俱發，晴階影對鋪。", "君王重天貺，臨寫冠珍圖。"]'),
('8d3993bd-e45e-4562-8385-794d03cffc27','奉直園雙頭芍藥','夏竦','宋','宋诗','song-poetry','','[]','奉帝名園麗，翻階淑艶鮮。',72,'全唐诗/poet.song.8000.json','["奉帝名園麗，翻階淑艶鮮。", "一叢芳蘤綻，四朵綘跗聯。", "朱李應雙結，蘭釭忽並燃。", "異瓜緗蒂合，嘉木翠枝駢。", "映葉交霞袂，迎風疊綺錢。", "流祥在圖素，千載冠嘉蓮。"]'),
('7acdad76-15b7-4912-b9f6-3b8b519e36c1','講徹禮記崇政殿開宴應制','夏竦','宋','宋诗','song-poetry','','[]','幄坐尊儒術，華光御講筵。',72,'全唐诗/poet.song.8000.json','["幄坐尊儒術，華光御講筵。", "爰開柏梁宴，爲畢曲臺篇。", "法從飛緌接，藩房綺組聯。", "賜花均綵萼，陪鼎雜冬鮮。", "甘潤聲詩洽，芳蕤注籍傳。", "師臣咸拜手，歸道黼帷前。"]'),
('dc827b57-aef5-4e06-bdb4-7e4bf7535dc1','皇帝聽講尚書徹太清樓錫宴','夏竦','宋','宋诗','song-poetry','','[]','洛書初罷講，漢苑特開筵。',72,'全唐诗/poet.song.8000.json','["洛書初罷講，漢苑特開筵。", "將許陪旒扆，先容閱簡編。", "神宗遺札啓，真祖寶文宣。", "密坐瞻堯日，凝心聽舜絃。", "賜花緗葉綴，勸酒玉巵傳。", "恩重天難報，肌膚豈易鐫。"]'),
('6cd4b9c2-a1f3-404a-a4be-d43ce34c1afa','觀唐明皇山水字流杯石應制','夏竦','宋','宋诗','song-poetry','','[]','開元留翠刻，昭代奉宸游。',72,'全唐诗/poet.song.8000.json','["開元留翠刻，昭代奉宸游。", "綠酒聯杯汎，紅泉滿字流。", "澄清涵玉宇，瀲灔轉銀鈎。", "霄堮奎躔布，龜圖洛畫浮。", "偃波分密坐，垂露直前旒。", "若許銘天德，圜青豈易儔。"]'),
('20730c51-76a4-4c09-86ec-5f3d0e1b325a','元真殿燒香觀太宗真宗御書仁宗飛白書并瑞穀應制','夏竦','宋','宋诗','song-poetry','','[]','蘭炷薰琳殿，霓旄映綠莎。',72,'全唐诗/poet.song.8000.json','["蘭炷薰琳殿，霓旄映綠莎。", "九青真蔭遠，三母睿慈多。", "閣道陪鑾往，唐中奉詔過。", "熙陵遺札啓，禰廟寶文羅。", "繼志頒宸翰，飛毫動偃波。", "史臣書絕瑞，鈎盾對嘉禾。"]'),
('bd3c0824-c337-4530-a743-7e98da2665ba','奉觀御飛白書應制','夏竦','宋','宋诗','song-poetry','','[]','聖德天攸縱，慈闈寶訓崇。',72,'全唐诗/poet.song.8000.json','["聖德天攸縱，慈闈寶訓崇。", "飛毫邁古法，方丈奪神功。", "輕素飄驚吹，長煙疊遠空。", "點孤時戱蝶，波偃乍騰虹。", "洛畫誠難並，奎躔或可同。", "猥叨宸筆賜，羽翼誓輸忠。"]'),
('c786a28a-878c-44c9-9783-178aeba637fc','皇太后恭謝太廟','夏竦','宋','宋诗','song-poetry','','[]','法宫裁舊典，長樂奉春祠。',72,'全唐诗/poet.song.8000.json','["法宫裁舊典，長樂奉春祠。", "犧象華樽設，旂常大路移。", "屬車朱總備，亞祼翟章垂。", "瑤爵因周制，金根益漢儀。", "歆馨百禄委，齋祓六宫隨。", "往訓遵三母，何階擬聖時。"]'),
('2e82f934-8a2c-4331-ad2d-798606f90c43','躬耕耤田詩','夏竦','宋','宋诗','song-poetry','','[]','廣阼承嚴享，東廛錯上儀。',72,'全唐诗/poet.song.8000.json','["廣阼承嚴享，東廛錯上儀。", "纁裳拂黛耜，綵繅映紅縻。", "內宰登嘉種，餘夫列縹陂。", "游場玉趾遠，盡隴紺轅遲。", "藨蓘訓農穡，馨香供帝粢。", "匪今方介祉，敢續載芟詩。"]'),
('d5cfa583-a9a4-4c29-8988-b279f95168b5','晚晴','夏竦','宋','宋诗','song-poetry','','[]','萬家充積望，千里絕纖埃。',120,'全唐诗/poet.song.8000.json','["萬家充積望，千里絕纖埃。", "日輾雲頭上，風驅雨脚迴。", "亂帆爭古渡，疏葉下高臺。", "啓戶晴光入，卷簾秋氣來。", "山心餘靄散，地角亂煙堆。", "宿鳥幽叢閙，殘虹遠色開。", "脫簑人顧步，曬羽鶴徘徊。", "菌遶枯林下，萍翻曲岸隈。", "名園添舊笋，幽石長新苔。", "綺席誰相賀，繁絃拍屢催。"]'),
('25c97277-bef0-442c-b91a-66f2441b8880','和集賢相公攝事出郊','夏竦','宋','宋诗','song-poetry','','[]','台衮承嚴祀，傳呼出禁城。',144,'全唐诗/poet.song.8000.json','["台衮承嚴祀，傳呼出禁城。", "扢壇將錯事，總駟暫觀耕。", "盈止踰周頌，康哉叶舜賡。", "滿篝登大穟，首種達初萌。", "行饁家爲黍，要朋戶捧罌。", "川長應萬耦，樹密盡三荆。", "有相神休茂，多歡國譽榮。", "餘糧充近甸，遺秉富陪京。", "碓罷舂粱熟，機閑織素成。", "休牛鳴笛起，會績遠燈明。", "路有遺金在，村無吠犬驚。", "熙熙難徧紀，徒仰泰階平。"]'),
('3b6b1846-f3db-43f7-9075-461dad65b635','送吳興使君郎中分務歸姑蘇','夏竦','宋','宋诗','song-poetry','','[]','罷郡歸南國，分曹在别京。',96,'全唐诗/poet.song.8000.json','["罷郡歸南國，分曹在别京。", "江山適清尚，圭組謝浮名。", "桂楫鄉人送，雲漿舊吏迎。", "夕香薰徑遠，春溜斂池平。", "累去千憂盡，中恬四體輕。", "吟齋研賜墨，釣渚濯塵纓。", "玉樹時方盛，金鈎慶已成。", "何妨過轂下，萬壽集公卿。"]'),
('59871b19-62ae-4827-9bf6-d763f34b3954','送鳯茶與記室燕學士詩','夏竦','宋','宋诗','song-poetry','','[]','綠荈圜規異，紅縢篆印新。',72,'全唐诗/poet.song.8000.json','["綠荈圜規異，紅縢篆印新。", "爭先御府貢，初摘建溪春。", "膩滑重蒼璧，嬌黄聚麴塵。", "焙痕連井字，鳯刻疊龍鱗。", "玉座均芳旨，金華寵侍臣。", "齋心分一餅，持贈輞川人。"]'),
('f5b07905-6cd1-42fe-b8ab-9c04c37efef1','奉和御製千葉黄牡丹','夏竦','宋','宋诗','song-poetry','','[]','千葉繁英吐異芳，中央瑞色藹清香。',64,'全唐诗/poet.song.8000.json','["千葉繁英吐異芳，中央瑞色藹清香。", "密攅鶯羽參差折，細疊霓裳次第黄。", "霧鎖天衣臨翠幄，露傾金醆瀝霞漿。", "聖明盛事尊長樂，親灑宸毫奉美祥。"]'),
('06b99400-2fb7-4099-a3b3-fc9d4248f389','和御製賞花詩','夏竦','宋','宋诗','song-poetry','','[]','禁園清蹕賞春時，水殿晴陽照翠緌。',64,'全唐诗/poet.song.8000.json','["禁園清蹕賞春時，水殿晴陽照翠緌。", "步輦乍衝僊杏葉，御衣頻拂露桃枝。", "風搖蘂粉星星墜，日引芳陰寸寸移。", "帝所甚歡宫漏永，宴餘仍奉柏梁詩。"]'),
('8e372448-7ff5-477a-bff3-a5d89a941a39','奉和御製雪','夏竦','宋','宋诗','song-poetry','','[]','寒風夜傍梁園積，花雪晨臨宋殿飛。',64,'全唐诗/poet.song.8000.json','["寒風夜傍梁園積，花雪晨臨宋殿飛。", "歌儷陽春爭度曲，月承宵幌競通輝。", "五車洛邑延神御，八駿黄臺罷獵圍。", "今日雲章昭美應，眇觀千載事還稀。"]'),
('4c9805ea-6fa4-4f3b-bfc5-5206c517d331','奉和御製清心殿水清木再連理','夏竦','宋','宋诗','song-poetry','','[]','禁中遲日照南榮，瑞木聯祥耀國經。',64,'全唐诗/poet.song.8000.json','["禁中遲日照南榮，瑞木聯祥耀國經。", "合幹舊臨宫檻密，交柯重接帝梧青。", "華平對植行侵陛，若木相輝影滿亭。", "况是齋心延貺地，愈昭天意答惟馨。"]'),
('599d153c-de73-40de-ac9c-51052206ea15','奉和御製太清樓屏風柏連理','夏竦','宋','宋诗','song-poetry','','[]','禁園綺合羣芳茂，瑞柏屏開秀色呈。',64,'全唐诗/poet.song.8000.json','["禁園綺合羣芳茂，瑞柏屏開秀色呈。", "託植久依僊杏密，附枝俄接帝梧榮。", "非煙結翠和風細，滴露凝華曉日明。", "况是歲寒堅節異，亭亭千載表殊禎。"]'),
('48d2b915-25e4-4f1a-813a-6d1d5baba844','四月昌州奏聖祖殿下生芝草一本四莖及面有紅光如悦懌之狀','夏竦','宋','宋诗','song-poetry','','[]','昌元遠地凝和氣，真祖僊宫發帝祺。',64,'全唐诗/poet.song.8000.json','["昌元遠地凝和氣，真祖僊宫發帝祺。", "穆穆睟客分喜色，煌煌寶座秀靈芝。", "已彰日監靈心顯，更表晨敷協氣滋。", "元后欽崇膺瑞命，殊庭薦號答繁禧。"]'),
('37d1c4f5-3218-480d-b1c4-6864b86b743f','五月同州奏牡丹一枝開三花','夏竦','宋','宋诗','song-poetry','','[]','上聖德風馳率土，左馮嘉氣襲鴻英。',64,'全唐诗/poet.song.8000.json','["上聖德風馳率土，左馮嘉氣襲鴻英。", "疏叢一榦迎春茂，繁艶三房表瑞呈。", "承獻珍圖昭美應，考祥花品見維禎。", "帝宸欽翼崇昭報，薦玉燔柴極至誠。"]'),
('d774959e-350d-4a1f-a191-09da844bf686','閏六月眉州奏禾生九穗','夏竦','宋','宋诗','song-poetry','','[]','眉山遠地蜀川西，九穗嘉禾忽效祺。',64,'全唐诗/poet.song.8000.json','["眉山遠地蜀川西，九穗嘉禾忽效祺。", "東極龍枝人莫睹，環丘玉粒世空知。", "中和積粹名方異，繁蔚呈祥事更奇。", "自可增封齊北里，豈将同穎比繁禧。"]'),
('f8d539ca-28bb-4a1e-b756-988cd99c7b15','八月梓州奏廣化寺池蓮五莖各開二花','夏竦','宋','宋诗','song-poetry','','[]','梓潼名郡蜀川東，忽秀佳蓮紺宇中。',64,'全唐诗/poet.song.8000.json','["梓潼名郡蜀川東，忽秀佳蓮紺宇中。", "褭褭修莖孤引綠，盈盈雙蘂對分紅。", "絳跗相倚凝新露，紫菂交垂向晚風。", "爰考瑞圖觀美應，柳州嘉産實難同。"]'),
('ad425c8c-d442-4655-be1e-f3e7a88f67ce','奉和御製景靈宫迎牌','夏竦','宋','宋诗','song-poetry','','[]','紫館成功屬盛時，道迎金榜耀文思。',64,'全唐诗/poet.song.8000.json','["紫館成功屬盛時，道迎金榜耀文思。", "沉沉殿翼彌增麗，矗矗圭稜盡中規。", "祗薦寶香清吹褭，下觀飈御彩雲随。", "羣心仰止興謠誦，永見千齡播緝熙。"]'),
('42768923-1f26-4f1c-83fa-43108d8b8c3d','奉和御製兖州景靈宫太極觀牌登路','夏竦','宋','宋诗','song-poetry','','[]','崇丘紫館集繁禎，躬勒璿題耀筆精。',64,'全唐诗/poet.song.8000.json','["崇丘紫館集繁禎，躬勒璿題耀筆精。", "藻衛森沉登廣路，彩雲搖褭入層城。", "高侔曲密分都號，遠法陽寥紀殿名。", "真祖覽觀鴻慶茂，壽山從此倍崢嶸。"]'),
('ba51e2e4-5078-4350-bd9d-26f2f864094a','奉和御製甘雨應祈','夏竦','宋','宋诗','song-poetry','','[]','少皥九秋當季月，成湯六禱動靈心。',64,'全唐诗/poet.song.8000.json','["少皥九秋當季月，成湯六禱動靈心。", "中宵甘澍均豐浸，盡日層雲結遠陰。", "銷去驕陽爲瑞重，招来嘉應感人深。", "側身修道殊千古，仍叔焉能播德音。"]'),
('f80cc160-375e-4d50-845e-216310c12f3e','奉和御製喜春雨','夏竦','宋','宋诗','song-poetry','','[]','太液冰銷春水生，華林氣暖暮煙横。',64,'全唐诗/poet.song.8000.json','["太液冰銷春水生，華林氣暖暮煙横。", "忽聞甘澍中宵降，共慶豐年上瑞呈。", "拂地如絲籠北闕，映花疑霧靄南榮。", "原田脉起承甘潤，自此嘉生永順成。"]'),
('ac47397f-0dbf-41ef-bdc0-1151a9fe175f','上元應制','夏竦','宋','宋诗','song-poetry','','[]','魚龍曼衍六街呈，金鎻通宵啟玉京。',64,'全唐诗/poet.song.8000.json','["魚龍曼衍六街呈，金鎻通宵啟玉京。", "冉冉游塵生輦道，遲遲春箭入歌聲。", "寶坊月皎龍燈淡，紫館風微鶴燄平。", "宴罷南端天欲曉，迴瞻河漢尚盈盈。"]'),
('c7359a64-47e6-4338-86e7-b0e71ff2c91b','帝京春日','夏竦','宋','宋诗','song-poetry','','[]','景陽鐘盡唱鄰鷄，十二都門報啟扉。',64,'全唐诗/poet.song.8000.json','["景陽鐘盡唱鄰鷄，十二都門報啟扉。", "一带樓臺擎落月，萬家桃李待朝輝。", "宫槐煙暖鶯猶睡，僊掌雲寒露未晞。", "算是五侯偏稱意，遊春車馬早如飛。"]'),
('05e15473-e643-495e-888c-9672db8dab32','江南春日','夏竦','宋','宋诗','song-poetry','','[]','江北遊人春未迴，江南春色傍人来。',64,'全唐诗/poet.song.8000.json','["江北遊人春未迴，江南春色傍人来。", "茶經穀雨依稀綠，花接清明次第開。", "場上鬭鷄金作距，檻前粧鑑玉爲臺。", "六朝風物今何在，莫負流年酒百盃。"]'),
('45fb41b9-8a14-4b3b-bbad-ac55f6fa75d8','寒食','夏竦','宋','宋诗','song-poetry','','[]','夾城煙淡草霏霏，晉俗相傳禁火時。',64,'全唐诗/poet.song.8000.json','["夾城煙淡草霏霏，晉俗相傳禁火時。", "御苑梨繁花盛發，帝園桐嫩蘂初披。", "塵微蹴踘人将散，雨細鞦韆索半垂。", "遊騎尋芳還鬬酒，九門謠誦樂重熙。"]'),
('2b2cce6e-eeaf-482a-b12d-e97cb18bca63','春遊','夏竦','宋','宋诗','song-poetry','','[]','豔艶春風雨半收，少年疏誕稱春遊。',64,'全唐诗/poet.song.8000.json','["豔艶春風雨半收，少年疏誕稱春遊。", "将軍雪散橋邊市，騎省花開縣外樓。", "草嫩玉堤藏堕珥，酒濃金盞滑歌喉。", "誰能借取瑤池馬，亂踏紅塵四百州。"]'),
('3ec5f123-9616-43a6-9b78-88b6cdc8c318','初夏有作','夏竦','宋','宋诗','song-poetry','','[]','玉琯葭灰昨夜吹，日華光暖向陽枝。',64,'全唐诗/poet.song.8000.json','["玉琯葭灰昨夜吹，日華光暖向陽枝。", "東君亂點丹青筆，真宰忙揮造化椎。", "紅日暗長人不覺，好花偷發蝶先知。", "後園無限桃兼李，留待新恩得意時。"]'),
('ddff2c91-2bf3-4727-b5e2-52ffadb3f3bb','江城秋思','夏竦','宋','宋诗','song-poetry','','[]','澤國迢迢枕海涯，眼前歸思亂如麻。',64,'全唐诗/poet.song.8000.json','["澤國迢迢枕海涯，眼前歸思亂如麻。", "清秋泉石無多地，殘日樓臺有幾家。", "兩岸早霜紅橘柚，半汀殘雨老蒹葭。", "明時不見投簪客，落盡西風紫菊花。"]'),
('c14a1e9c-eb1e-4a9c-b2ee-f667c972a2e4','華山','夏竦','宋','宋诗','song-poetry','','[]','三峰森翠倚雲稜，凝睇煙蘿最上層。',64,'全唐诗/poet.song.8000.json','["三峰森翠倚雲稜，凝睇煙蘿最上層。", "八水亂分秦帝國，四關空鎖漢皇陵。", "僊羊未起眠春草，塞馬初歸放紫藤。", "堪惜聖朝無傲吏，夜来風月屬閑僧。"]'),
('48ef5658-a74c-4b04-ab04-d05ffbb36948','滕王閣','夏竦','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','面臨漳水勢凌霞，却倚重城十萬家。',64,'全唐诗/poet.song.8000.json','["面臨漳水勢凌霞，却倚重城十萬家。", "當檻曉雲生鶴嶺，拂階殘雨下龍沙。", "辭人高宴文皆在，帝子歡遊事未賖。", "好是良宵金鼓動，闌干牛斗逼簷斜。"]'),
('75a541a7-e0f2-460e-abdc-1a0f046440e1','江南懷古','夏竦','宋','宋诗','song-poetry','','[]','六朝雲物更風流，澹澹煙藏古寺樓。',64,'全唐诗/poet.song.8000.json','["六朝雲物更風流，澹澹煙藏古寺樓。", "敵國漫輕江似带，史臣能視橘爲侯。", "荒臺有鹿姑蘇晚，壞閣無香建業秋。", "到了賢明出中土，莫誇歌舞霸南州。"]'),
('11ad1339-5956-4241-ad35-e51aa3f54966','金陵','夏竦','宋','宋诗','song-poetry','','[]','虎踞龍盤委薜蘿，臺城春雨長寒莎。',64,'全唐诗/poet.song.8000.json','["虎踞龍盤委薜蘿，臺城春雨長寒莎。", "梁家不覺市朝改，蕭寺只聞鐘磬多。", "雲樹暮堤攅劍戟，風篁虚谷轉笙歌。", "須知王氣随明主，不據金陵又若何。"]'),
('25c8b82b-36c0-4591-8d56-760ba50058b5','狼山渡口有作','夏竦','宋','宋诗','song-poetry','','[]','渡口人疏黯翠煙，登臨猶喜夕陽天。',64,'全唐诗/poet.song.8000.json','["渡口人疏黯翠煙，登臨猶喜夕陽天。", "殘雲右倚江都樹，遠水南迴建業船。", "山引亂猿嘷古寺，電驅甘雨過閑田。", "季鷹死後無歸客，江上鱸魚不直錢。"]'),
('922becc3-2d13-449c-81ab-e3d3171f258f','感興','夏竦','宋','宋诗','song-poetry','','[]','流年難駐且從容，莫厭多情事萬重。',64,'全唐诗/poet.song.8000.json','["流年難駐且從容，莫厭多情事萬重。", "深院晚因留客鎖，小欄春爲惜花封。", "家山久駐偷歸夢，庭檜清含入夜鐘。", "更有薄遊長記得，翠鈿遺處綠陰濃。"]'),
('3a119cbc-496b-4ef7-adf4-6c6dac712ee6','洛中春旱禱龍門無畏塔得雨','夏竦','宋','宋诗','song-poetry','','[]','露盤金索出危岑，風卷驚塵撲翠林。',64,'全唐诗/poet.song.8000.json','["露盤金索出危岑，風卷驚塵撲翠林。", "五夜清場嚴佛事，一犁甘澍慰民心。", "聖君旰食憂應减，守吏齋誠禱更深。", "泛灔洛川皆帝力，好浮青鯉瑞煙尋。"]'),
('08e0884a-9818-47bd-8c60-e5e16fe30a25','本宫投龍簡中使','夏竦','宋','宋诗','song-poetry','','[]','醮罷層霄鶴吹分，夜壇香火鏤真文。',64,'全唐诗/poet.song.8000.json','["醮罷層霄鶴吹分，夜壇香火鏤真文。", "羽人月筆封瑤檢，使者星馳下絳雲。", "蘂簡薦誠川后聳，金龍傳信洞天聞。", "再三鵲尾添檀炷，爲祝虚心佑聖君。"]'),
('a75141de-6086-43d3-afc3-9dfc8b9d3171','僊姬怨','夏竦','宋','宋诗','song-poetry','','[]','洞口垂楊拂地垂，年来期約又依違。',64,'全唐诗/poet.song.8000.json','["洞口垂楊拂地垂，年来期約又依違。", "紅桃不解留人住，白鶴何曾覓信歸。", "雉扇對開春寂寂，繡衣雙卷雨霏霏。", "無言盡日雲邊立，不許霓裳按羽衣。"]'),
('f0dc21f7-acbf-4911-b250-1effd49dec6b','宫詞','夏竦','宋','宋诗','song-poetry','','[]','柳带分陰接殿基，笙歌還擁翠華歸。',64,'全唐诗/poet.song.8000.json','["柳带分陰接殿基，笙歌還擁翠華歸。", "前宫曉赭匀粧臉，别館春紅曬舞衣。", "槐影對籠苔點細，桐花西倚夕陽稀。", "夜来夢上檀香閣，猶映珠簾避貴妃。"]'),
('f3a0614b-5627-46e8-b48e-5baf34847b38','秋日江館喜彈琴羽人至','夏竦','宋','宋诗','song-poetry','','[]','水館凄清天一涯，喜逢僊蓋駐靈芝。',64,'全唐诗/poet.song.8000.json','["水館凄清天一涯，喜逢僊蓋駐靈芝。", "煙霞初散海中會，風雨忽来江上期。", "琴軫玉寒彈宿露，酒巵金暖對朝曦。", "圯橋書在如相授，不獨留侯是帝師。"]'),
('04970967-1351-42a6-8aa3-7b7f46c45d3b','喜馬少保致政','夏竦','宋','宋诗','song-poetry','','[]','世機無路惱天真，心地逍遙萬象新。',64,'全唐诗/poet.song.8000.json','["世機無路惱天真，心地逍遙萬象新。", "久戍金河歸塞客，却浮鯨海到家人。", "靜封藥竈移文火，閑看花陰上舞茵。", "應笑公侯方內熱，六街奔走利名塵。"]'),
('b7abbfd1-8cc3-4407-9110-b0f30130d87f','送江寜相公','夏竦','宋','宋诗','song-poetry','','[]','六朝臺榭好山川，丞相遙分造化權。',64,'全唐诗/poet.song.8000.json','["六朝臺榭好山川，丞相遙分造化權。", "兩府規模遵故事，二南風什聽新篇。", "平反庶獄棠廬外，約束諸侯玉帳前。", "莫訝依依戀行色，壽藩書命最多年。"]'),
('c64b9b1d-8513-423d-acf6-6cab4cf3f7a4','送太傅相公居留洛宅','夏竦','宋','宋诗','song-poetry','','[]','梓澤芝田尊帝里，玉符金鑰委台司。',64,'全唐诗/poet.song.8000.json','["梓澤芝田尊帝里，玉符金鑰委台司。", "家傳舊節居連帥，史作新書贊父師。", "留府櫜鞬分騎引，都門圭組鬬班辭。", "共驚河洛初開奥，一日龍光四海知。"]'),
('a115108d-5bf6-45d7-8e04-5b6054f01326','送濟南杜郎中','夏竦','宋','宋诗','song-poetry','','[]','秋樹參差堕葉紅，剖符還過故鄉東。',64,'全唐诗/poet.song.8000.json','["秋樹參差堕葉紅，剖符還過故鄉東。", "星分北陸龜蛇內，位應哀烏太紫中。", "亭傳宛如行部日，冠纓猶带觸邪風。", "寒泉豈是無人塞，應待君侯立事功。"]'),
('c5d43831-798c-45f6-b414-0757c0e0b820','送修撰楊學士留守南京','夏竦','宋','宋诗','song-poetry','','[]','畫船椎鼓忽東浮，留幕賓從候舳艫。',64,'全唐诗/poet.song.8000.json','["畫船椎鼓忽東浮，留幕賓從候舳艫。", "宫裏銅魚勘門鑰，府中銀兔合軍符。", "鳴騶苑路人千騎，送客河橋酒百壺。", "莫爲文章還自苦，騖池龍岫且遊娛。"]'),
('c2c54fae-45cb-4a04-8bc8-a6f7dc128a74','送王端公充荆湖北路轉運','夏竦','宋','宋诗','song-poetry','','[]','錦衣驄馬好還家，大别山邊漢水斜。',64,'全唐诗/poet.song.8000.json','["錦衣驄馬好還家，大别山邊漢水斜。", "霜簡位高增意氣，金章恩重有光華。", "幾程蠻徼雲藏驛，一棹荆江月照沙。", "多少朝簪鬢成雪，願君休訪楚山茶。"]'),
('0b5c13e5-7886-4c5a-b823-83c3391ed834','送李殿院知防州','夏竦','宋','宋诗','song-poetry','','[]','屈草聯芳映法冠，亭亭風度聳朝端。',64,'全唐诗/poet.song.8000.json','["屈草聯芳映法冠，亭亭風度聳朝端。", "一麾出守秦城近，千里班春漢詔寛。", "引道畫旗迎馬重，褰帷霜簡照人寒。", "都門迴首多離緒，寶瑟凄風别酒闌。"]'),
('42212e4b-f59d-4f42-9e95-53964183165e','送蘇臺守受代歸朝','夏竦','宋','宋诗','song-poetry','','[]','香案當衙拜鳳書，使君旌節下姑蘇。',64,'全唐诗/poet.song.8000.json','["香案當衙拜鳳書，使君旌節下姑蘇。", "賓朋唱和詩千首，耆幼扶攜酒百壺。", "野樹遮藏過建業，亂山迎送出江都。", "西風不得同歸去，紅藕花邊望舳艫。"]'),
('8cdc0b32-9f77-4fb4-b519-4d2ecb228f75','送新恩善濟處士歸玉笥','夏竦','宋','宋诗','song-poetry','','[]','蠲疴妙劑分黄閣，駐景僊山奉紫闈。',64,'全唐诗/poet.song.8000.json','["蠲疴妙劑分黄閣，駐景僊山奉紫闈。", "太秀山川須長價，少微星宿已增輝。", "幅巾不被塵纓縳，别笈唯封賜葯歸。", "唳鶴鳴猿好相候，利名無染世還稀。"]'),
('1d30a6da-ab70-464f-8d6d-a4fbe420c2cb','送人遊關右','夏竦','宋','宋诗','song-poetry','','[]','朝曦輕抺柳梢長，歌徹郵亭飭去裝。',64,'全唐诗/poet.song.8000.json','["朝曦輕抺柳梢長，歌徹郵亭飭去裝。", "鶉首右瞻秦分野，虎牢西入漢關防。", "温泉雨霽離宫碧，麟畤沙驚塞日黄。", "如訪平戎最長策，不徒鞭馬爲詩忙。"]'),
('fcbb6283-9518-4846-a6cd-1fffa774dff0','送人入越','夏竦','宋','宋诗','song-poetry','','[]','廣陵江口柳疏疏，自領笙歌上舳艫。',64,'全唐诗/poet.song.8000.json','["廣陵江口柳疏疏，自領笙歌上舳艫。", "一片曉山迎越絕，數程春水背姑蘇。", "蓮供晚果蜂房細，鱠市朝餐線縷麤。", "他日功成待相訪，謝家煙月借人無。"]'),
('46f426f5-8617-47f1-a330-bbb0cb99424a','送人之淮西','夏竦','宋','宋诗','song-poetry','','[]','五里亭前一送君，碧油紅斾駐清塵。',64,'全唐诗/poet.song.8000.json','["五里亭前一送君，碧油紅斾駐清塵。", "半軒晚日淮西路，數拍離歌江上春。", "杜宇有情移别樹，野花無主傍行人。", "男兒多少醻恩地，不欲東風淚滿巾。"]'),
('57f62a53-01fa-4e9e-8e7c-7ca3e3c8d454','寄張相公','夏竦','宋','宋诗','song-poetry','','[]','台司金印護諸侯，沖氣均和耐素秋。',64,'全唐诗/poet.song.8000.json','["台司金印護諸侯，沖氣均和耐素秋。", "户牖舊謀方倚重，莬裘前計合遲留。", "豈同少傅輕辭漢，况有維師永佐周。", "秉燭家園且行樂，即應重起濟川舟。"]'),
('6f6ad728-b591-40c7-8ae6-ded0c5e4b368','春日寄陳舍人','夏竦','宋','宋诗','song-poetry','','[]','濃淡晴霞泛夕陽，重重煙藹護流芳。',64,'全唐诗/poet.song.8000.json','["濃淡晴霞泛夕陽，重重煙藹護流芳。", "花殘遠渡曉風急，路入層雲春夢長。", "結蕙翠光留蝶舞，含桃紅實駐鶯嘗。", "可憐得意文章客，扈蹕西園月桂香。"]'),
('89568f48-9ad3-4b32-abeb-c7aafebf6c29','題東林寺','夏竦','宋','宋诗','song-poetry','','[]','昔帝先賢跡未消，森沉臺殿鎖嶕嶢。',64,'全唐诗/poet.song.8000.json','["昔帝先賢跡未消，森沉臺殿鎖嶕嶢。", "新蓮照水香空在，舊輦生塵翠已凋。", "夾道古藤看翳日，過谿蒼蘚半侵橋。", "遠公前意無人會，空對清風望寂寥。"]'),
('cc841345-bbc6-4cb7-af8f-eb2a17b85402','崇勝寺','夏竦','宋','宋诗','song-poetry','','[]','山當廬阜五峰邊，地占侯谿好習禪。',64,'全唐诗/poet.song.8000.json','["山當廬阜五峰邊，地占侯谿好習禪。", "杳藹峰巒雲蔽日，參差樓殿瓦生煙。", "僧房宿鳥棲簾外，客館鳴泉過枕前。", "但可登臨閑訪古，西来無法與人傳。"]'),
('ebd155f8-1f6f-4768-86c0-875a81ee31a9','觀夜醮','夏竦','宋','宋诗','song-poetry','','[]','萬條銀燭間靈旗，一片清香匝玉墀。',64,'全唐诗/poet.song.8000.json','["萬條銀燭間靈旗，一片清香匝玉墀。", "羽帳星辰来不覺，僊壇冠帔立多時。", "紅桃裛露風初細，白鶴迎雲月漸遲。", "試託東皇問蕭史，鳳簫應許借人吹。"]'),
('cdcbe8fe-7262-4022-95c8-fda68a7916b9','話道','夏竦','宋','宋诗','song-poetry','','[]','清净無營即自由，神僊何必待人求。',64,'全唐诗/poet.song.8000.json','["清净無營即自由，神僊何必待人求。", "秦皇多詐死猶諱，漢武窮兵老未休。", "巨費漫悲徐市藥，怪書空驗少翁牛。", "須知方寸真元意，不在層城十二樓。"]'),
('270c2534-4042-42ea-97a1-2c84fa1a23c9','赤城','夏竦','宋','宋诗','song-poetry','','[]','丹壁排空疊綵虹，上真應此駐靈蹤。',64,'全唐诗/poet.song.8000.json','["丹壁排空疊綵虹，上真應此駐靈蹤。", "烟沉曉日明孤頂，雲破餘霞出半峰。", "巖下法師曾伏虎，洞中僊客屢投龍。", "他年翠蓋東巡狩，玉牒終須受大封。"]'),
('45d1c074-bfa2-4bf7-9d11-fedf8590208f','奉和御製龍圖閣觀書','夏竦','宋','宋诗','song-poetry','','[]','切雲層閣倚龍城，霜素緹油聚壁經。',96,'全唐诗/poet.song.8000.json','["切雲層閣倚龍城，霜素緹油聚壁經。", "嚴召近臣容侍從，載賡宸唱樂清寜。", "神宗燕翼垂貽訓，地寶昭彰顯瑞形。", "芬馥芸香飄紫禁，熒煌金刻照彤庭。", "龜陳洛畫開瑤檢，絃泛薰風出黼扃。", "自慶孤生逢旦暮，愧無嘉頌贊明馨。"]'),
('995d931d-3d2b-4663-a555-b23f4e3dcc98','奉和御製奉祀禮成宴','夏竦','宋','宋诗','song-poetry','','[]','真場薦鬯方回蹕，泰畤欽柴既受禧。',96,'全唐诗/poet.song.8000.json','["真場薦鬯方回蹕，泰畤欽柴既受禧。", "璧散九行頒寵宴，翠緌三接慶昌期。", "露晞朝景彰慈渥，風扇微和表聖時。", "羽籥動容分廣砌，旍旂交影上丹墀。", "瓊跗拜賜承天意，綷羽來儀識鳳姿。", "向晚柏梁傳睿唱，帝臺春箭更遲遲。"]'),
('6853a10b-7e50-4583-877f-cad86da4c437','奉和御製內苑嘉穀','夏竦','宋','宋诗','song-poetry','','[]','淵聖欽明撫庶氓，齋居勵翼御彤庭。',96,'全唐诗/poet.song.8000.json','["淵聖欽明撫庶氓，齋居勵翼御彤庭。", "天田播種勤農事，雲稼流祥耀國經。", "瓊粒蕃滋爭結穟，龍枝屈曲競分形。", "搖風秀色交卿靄，垂穎餘光近帝星。", "茂遂豈同蕖葉異，殊尤全掩鳳冠靈。", "連莖五七踰成數，實表皇穹鑒德馨。"]'),
('ca9045cd-06a0-4118-96d1-89a780fcbcc6','奉和御製玉清昭應宫天書閣告成','夏竦','宋','宋诗','song-poetry','','[]','飈馭告期宵寤協，紫虚疇德秘符呈。',160,'全唐诗/poet.song.8000.json','["飈馭告期宵寤協，紫虚疇德秘符呈。", "誕膺顧諟營恭館，仰悟威神奉太清。", "密石礱磨鳩郢匠，非煙騰瑞集周禎。", "上侔帝闕規模麗，遠掩迎年憲度明。", "将閟玉文藏綠藴，載崇金閣對丹城。", "高陞彩制修梁直，永據柔靈寶勢貞。", "飛陛緣雲彌岌嶪，重欒倚漢益崢嶸。", "良辰涓選繁禧茂，嚴蹕臨觀懿禮成。", "慶賜春流均盛食，真香雲涌薦明誠。", "薰絃濬發斯干詠，丕顯鴻猷洽治平。"]'),
('120dc886-5102-48a1-b615-6f355659c557','奉和御製玉清昭應宫玉皇大殿告成','夏竦','宋','宋诗','song-poetry','','[]','三聖重熙鴻業茂，百靈申錫寶符彰。',160,'全唐诗/poet.song.8000.json','["三聖重熙鴻業茂，百靈申錫寶符彰。", "寅恭清凈函無象，顧諟高明順秉陽。", "法馭省巡修廢墜，真宫經始報祺祥。", "棟升文杏觚稜峻，殿啟真琳玉瑱方。", "九帳盛儀陳宴衎，六莖清奏助歡康。", "開軒瑞氣凝空碧，駐蹕晴輝艷赭黄。", "珠樹移陰從帝圃，霓旌分影自仙鄉。", "宸游悦豫同襄野，睿藻昭回邁柏梁。", "黎庶縱觀爭嘆詠，侍臣嘉頌極游揚。", "靈休錫羡淳風振，永播聲名浹四荒。"]'),
('201de0dc-b2a0-40cd-9827-078ccbafb1ed','奉和御製國學太宗皇帝御書閣告成','夏竦','宋','宋诗','song-poetry','','[]','神宗濬哲通三變，善繼文思洽萬方。',96,'全唐诗/poet.song.8000.json','["神宗濬哲通三變，善繼文思洽萬方。", "高倚叢楹藏鳯緼，密礱溫石鏤雲章。", "素風暢茂增鴻慶，景耀騰凌發美祥。", "迴據日畿分寶勢，遠承雲路抗飛梁。", "推恩宥幣班中帑，式宴朝纓集上庠。", "更仰紫宸敷睿唱，夏絃春誦永游揚。"]'),
('4809b67d-1ec4-47fb-bf92-28031f1c8a5e','奉和御製九天司命降臨','夏竦','宋','宋诗','song-poetry','','[]','緝熙綿宇肅邊疆，蕃祉紛綸顯阜昌。',160,'全唐诗/poet.song.8000.json','["緝熙綿宇肅邊疆，蕃祉紛綸顯阜昌。", "真馭告期通夢寐，嚴宸精意潔壇場。", "青煙漏上盈中禁，碧輦宵分下彼蒼。", "照地輝光蒙鶴燄，靄人嘉氣雜蕭薌。", "峒山順拜鴻儀展，太古靈源密命揚。", "載仰金姿唯睟穆，稍瞻雲躅更輝煌。", "曉霞微動觚稜峻，絃月斜明玉瑱方。", "丹鳳卷旗嚴藻衞，綠車旋軫向仙鄉。", "春褀渙汗均流慶，睿唱昭迴紀降祥。", "萬國頌聲皆載路，巍巍馨烈邁成康。"]'),
('97027b38-ee2e-4253-9db8-132cbbb257fe','奉賀御製靈應瑞石','夏竦','宋','宋诗','song-poetry','','[]','沉潛毓粹生嘉石，宥密開祥契上穹。',96,'全唐诗/poet.song.8000.json','["沉潛毓粹生嘉石，宥密開祥契上穹。", "降聖遠期真馭協，卜年遐祚寶符同。", "夐殊延喜靈珪上，詎比昭華瑞琯中。", "隱起玉文非篆隸，混成環狀豈磨礱。", "彌彰帝歷休祺茂，永叶仙源統緒隆。", "欽翼春懷敷睿藻，巍巍千祀仰惟聰。"]'),
('3076256a-d289-4748-b551-290c93c86add','奉和御製朝元殿朝謝玉皇大帝','夏竦','宋','宋诗','song-poetry','','[]','三清右序儲繁祉，萬乘欽明答上穹。',160,'全唐诗/poet.song.8000.json','["三清右序儲繁祉，萬乘欽明答上穹。", "聖化誕敷書軌混，僊游昭假地天通。", "靈輝熠煜充丹禁，瑞霧霏微翳碧空。", "積累有開鴻緒遠，顧懷無際慶基隆。", "精心展彩威顔肅，法曲迎真睿藻融。", "象舞在庭功夐異，寶符先道古難同。", "奉朝嘉服祇羣后，贊帝鴻儀儼上公。", "神爵乍臨香馥郁，矞雲低映樹青葱。", "潔粢禋薦升嚴陛，蒼璧高蟠照曉風。", "宣室受釐均大賚，洋洋春澤浹區中。"]'),
('686bb7ac-8e2d-4ecd-b230-4aea72491fab','奉和御製朝謝玉皇大帝致齋夜天書道場觀鶴下臨','夏竦','宋','宋诗','song-poetry','','[]','紫皇齋祓感青冥，仙驥徊翔瑞氣平。',96,'全唐诗/poet.song.8000.json','["紫皇齋祓感青冥，仙驥徊翔瑞氣平。", "百和真香凝玉羽，九枝芳燄動星精。", "遠辭金闕銜靈命，俯瞰瑤臺效帝禎。", "矯翼乍侵龍斾影，揚音微雜鳳簫聲。", "應須置祀昭神異，豈止登歌紀聖明。", "藻衞仰觀皆率舞，益知天意合三清。"]'),
('e6d4c161-3d25-4279-a0b2-41b8dc5665d9','奉和御製奉安聖像禮成','夏竦','宋','宋诗','song-poetry','','[]','琳宫胥宇象清都，金閣叢楹閟寶符。',128,'全唐诗/poet.song.8000.json','["琳宫胥宇象清都，金閣叢楹閟寶符。", "昭假僊游彰胄緒，範鎔真像極規模。", "精衷欽翼明威顯，近輔恭迎茂典敷。", "美應荐臻書不絕，靈期先定日無渝。", "徘徊瑞羽臨旌斾，夭矯飛龍上舳艫。", "齋幄接神珪璧異，景輿迎聖羽儀殊。", "熒煌寶座安三境，嫗煦鴻恩下九衢。", "深慶小臣叨奉蹕，翠緌華組耀微軀。"]'),
('5a5fdfd5-4598-418c-9ba7-202675f833a9','奉和御製先天節上清宫道場香合內獲金龍','夏竦','宋','宋诗','song-poetry','','[]','元真降治祐生民，紫館空歌協吉辰。',96,'全唐诗/poet.song.8000.json','["元真降治祐生民，紫館空歌協吉辰。", "芬馥鵲鑪蘭注褭，盤縈鈿合翠龍臻。", "陰凝珠樹飛鱗密，影拂霓旌瑞角新。", "月駟雲螭徒駿逸，碧鷄金馬謾璘彬。", "會驂虯輦昭靈異，終接飇輪奉聖神。", "願復水官修豢御，紀年何足播芳塵。"]'),
('8cffaacf-cc74-4532-a8c8-7f8dc2fc09cc','奉和御製恭謝天地禮成','夏竦','宋','宋诗','song-poetry','','[]','元真密誨惟疇德，耀魄靈猷務降衷。',128,'全唐诗/poet.song.8000.json','["元真密誨惟疇德，耀魄靈猷務降衷。", "僊里肇禋尊妙道，國陽嚴配報層穹。", "百神右序儲蕃祉，羣后寅威仰聖風。", "聲震山淵踰日際，澤流根葉徧區中。", "考熙茂範登虞舜，積累遙源屬帝鴻。", "柔遠九垠書軌混，凝休千載帝天通。", "賡歌紫禁唐文盛，苐頌青緗漢德融。", "盛業巍巍心翼翼，古今能事集皇躬。"]'),
('b82cea00-2cdb-485e-839e-574aafb955c7','奉和御製真游殿告成','夏竦','宋','宋诗','song-poetry','','[]','均和玉燭成冬夕，疇聖珍符紀瑞年。',160,'全唐诗/poet.song.8000.json','["均和玉燭成冬夕，疇聖珍符紀瑞年。", "八景鳳輿臨紫禁，九微龍檠照祥煙。", "森沉藻衞僊游接，睟穆真儀聖誨宣。", "濬發璿源開物始，密敷鴻蔭肇基先。", "良金肖像鎔三品，寶殿新規度九筵。", "綺棟虹陞初矯爾，丹楹叢倚倍森然。", "高侔帝所威神備，迥據坤靈勢勝全。", "雲雀嚮陽明翠羽，玉題承月燦珠躔。", "元龜協吉休符茂，盛藻迎祥睿志虔。", "璧散示慈恩正洽，斯千流詠降瓊牋。"]'),
('3dd66ace-9b24-442c-aa61-45d6fc408e26','奉和御製與天下臣庶恭上玉皇大帝天帝聖號','夏竦','宋','宋诗','song-poetry','','[]','皇皇至德召和平，茂烈馨香已告成。',160,'全唐诗/poet.song.8000.json','["皇皇至德召和平，茂烈馨香已告成。", "祇報元符營紫館，欽崇上帝薦鴻名。", "夤威潔志通三境，宥密真游降九清。", "淳耀先期觀道秘，休成協吉順天正。", "瓊干文彩雲幡列，金簡熒煌玉字呈。", "藻衞導迎揚盛則，靈場陟降極精誠。", "綿區率籲民胥悦，篆素鋪觀古未行。", "廣樂乍兼簫籟響，仙風微動珮環聲。", "颺煙層宙祥輝涌，稱慶齋闈瑞氣生。", "道蔭符通嘉應集，中宸繁貺永充盈。"]'),
('e78ae6ca-0569-442b-96d2-89f80c2b4b58','奉和御製五嶽觀告成','夏竦','宋','宋诗','song-poetry','','[]','嶽鎮明神屢降康，聖心尊奉禮文揚。',128,'全唐诗/poet.song.8000.json','["嶽鎮明神屢降康，聖心尊奉禮文揚。", "徽名祇薦昭殊典，秘宇欽崇報美祥。", "曲沼甘泉秋湛湛，浮榮嘉氣曉蒼蒼。", "金釭銜壁流繁影，雲雀踶甍耀采章。", "祇祓王靈涓吉日，密礱文杏架修梁。", "都人霧集鴻儀盛，帝御天臨絜志彰。", "宸唱茂宣昭峻極，春祺紛委顯蕃昌。", "升平更屬西成日，擊壤歡謠徧井疆。"]'),
('6bd96c04-1268-471d-ba0b-02ed2abd58fc','奉和御製玉清昭應宫成','夏竦','宋','宋诗','song-poetry','','[]','中宸夜駐飛廉轡，東闕朝迎綠錯篇。',160,'全唐诗/poet.song.8000.json','["中宸夜駐飛廉轡，東闕朝迎綠錯篇。", "祇建寶宫朝睟象，載崇金閣奉真銓。", "高侔紫極威神異，迥據柔靈勝勢宣。", "矗矗端平規景叶，煌煌豐麗聖功全。", "承隅陽馬層雲隔，鳴磬花臺曉色先。", "别笈籙緘龍印字，清壇香奏鵲鑪煙。", "流泉灌注通河漢，列館回環接洞天。", "玉籟琅璈鸞競舞，蘂書金簡鶴爭傳。", "采梁虹指祺祥集，銀榜星分慶賞延。", "永鎮帝居資曼壽，五城奚取漢迎年。"]'),
('a67a9233-d724-46b4-a6cf-b1604ff472db','奉和御製會靈觀甘露','夏竦','宋','宋诗','song-poetry','','[]','岳靈飛觀聳神州，上聖欽崇德日休。',96,'全唐诗/poet.song.8000.json','["岳靈飛觀聳神州，上聖欽崇德日休。", "嘉露霄零甘特異，貞條膏被勢何稠。", "崑山寶器今初貯，漢苑仙盤昔未浮。", "自可紀年昭瑞應，更殊添海助洪流。", "堇荼變味承餘潤，圖牒騰芳煥大猷。", "願采朝華和美玉，仰資宸筭倍千秋。"]'),
('c849815c-b85e-49e8-8630-de9c4322928d','奉和御製冬至','夏竦','宋','宋诗','song-poetry','','[]','漢門候景嘉辰啟，魯觀書雲協氣升。',96,'全唐诗/poet.song.8000.json','["漢門候景嘉辰啟，魯觀書雲協氣升。", "玉琯飛灰新節應，璿霄合璧瑞華凝。", "陽芸初動猶兼雪，柔茘將芳尚隔冰。", "繁祉建元名已肇，殊庭備物禮将登。", "黄龍甘露誠難擬，泰畤甘泉豈足稱。", "共慶帝辰延百福，巍巍千載庇黎蒸。"]'),
('08a653fd-6c46-400b-8896-7c6843175698','奉和御製恭謝南郊','夏竦','宋','宋诗','song-poetry','','[]','高真降佑開鴻業，哲后祈禠福下民。',128,'全唐诗/poet.song.8000.json','["高真降佑開鴻業，哲后祈禠福下民。", "靖館齋心成鉅典，嘉壇報貺奉嚴禋。", "時遵夏曆春當孟，禮憲周郊日在辛。", "圖籙先登符命顯，祖宗昭配孝思伸。", "侍祠卿士衣纓列，隨兆星辰爼豆陳。", "穆穆蒼靈潛扈蹕，寥寥風伯豫清塵。", "再登午陛虔誠達，三燭奔精美應臻。", "萬壽無疆增介祉，永蠲牲玉事神明。"]'),
('a2258956-7c1d-456b-966a-41a34284717b','奉和御製慶先后升祔禮成','夏竦','宋','宋诗','song-poetry','','[]','事地有嚴彰至德，顯親爲重化含生。',96,'全唐诗/poet.song.8000.json','["事地有嚴彰至德，顯親爲重化含生。", "永懷慈景心追孝，載舉鴻儀月就盈。", "徽冊欽崇昭懿鑠，太宫祇祔極誠明。", "黄彝進裸精衷達，小吕登歌茂禮成。", "式宴外庭均大慶，受釐恭館洽維禎。", "薫絃遠播思齊頌，億載垂鴻廓帝紘。"]'),
('e562fdaf-06f3-4e79-b214-f394582f835d','奉和御製藉田詩','夏竦','宋','宋诗','song-poetry','','[]','紹休文祖盛儀陳，載耜東耕恊仲春。',32,'全唐诗/poet.song.8000.json','["紹休文祖盛儀陳，載耜東耕恊仲春。", "冕服遠推踰古制，須知明主爲生民。"]'),
('268bc24e-7fd6-4e4d-aa6a-0a8ae63da4a7','奉和御製皇太后恭謝太廟','夏竦','宋','宋诗','song-poetry','','[]','聖哲因心邁古先，親裁禮樂定犧牷。',32,'全唐诗/poet.song.8000.json','["聖哲因心邁古先，親裁禮樂定犧牷。", "祼成文母膺鴻祐，永指南山比壽年。"]'),
('870febdb-bb46-4bf6-bcff-360d9dcfa277','奉和御製幸金明池','夏竦','宋','宋诗','song-poetry','','[]','睿藻昭回侔列緯，時龍順豫體蒼旻。',32,'全唐诗/poet.song.8000.json','["睿藻昭回侔列緯，時龍順豫體蒼旻。", "豈同周穆臨瑤水，凱樂雍容浹庶民。"]'),
('945263c7-e60c-41aa-a838-674adcaa3f02','御閣春帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','金盤曉日融春露，黼帳鮮雲蔭瑞香。',32,'全唐诗/poet.song.8000.json','["金盤曉日融春露，黼帳鮮雲蔭瑞香。", "聖壽永同天地久，南山何足比延長。"]'),
('6feeeb89-771e-4f4c-a5e1-81aa76754890','御閣春帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','冰消太液生春水，日上披香積瑞煙。',32,'全唐诗/poet.song.8000.json','["冰消太液生春水，日上披香積瑞煙。", "喬嶽告成鴻慶遠，垂衣無事永千年。"]'),
('fb320bbb-8105-48cb-86d1-cd86e2810ca6','御閣春帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','天人道洽真游降，禪祀功高帝業昌。',32,'全唐诗/poet.song.8000.json','["天人道洽真游降，禪祀功高帝業昌。", "迎氣東郊風乍暖，受釐中禁日初長。"]'),
('82fed737-8378-4686-9bd2-d25f3ba3d60f','御閣春帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','九門和氣衝魚鑰，層宙祥飇起鶴雲。',32,'全唐诗/poet.song.8000.json','["九門和氣衝魚鑰，層宙祥飇起鶴雲。", "王澤下流慈煦遠，萬方歌舞戴明君。"]'),
('44e9520a-dcdc-4064-bde0-ca6b93089908','御閣春帖子  其五','夏竦','宋','宋诗','song-poetry','','[]','青逵布序韶暉盛，紫禁乘春樂事多。',32,'全唐诗/poet.song.8000.json','["青逵布序韶暉盛，紫禁乘春樂事多。", "海域晏清無夕慮，齋居宣室順天和。"]'),
('b0252e68-6596-4129-ac3f-413473e28001','御閣春帖子  其六','夏竦','宋','宋诗','song-poetry','','[]','寒梅吐艷風初應，步輦宣游日漸遲。',32,'全唐诗/poet.song.8000.json','["寒梅吐艷風初應，步輦宣游日漸遲。", "道蔭無涯真緒遠，永康寰海茂春祺。"]'),
('f0859e87-77d8-4400-9f0d-09a97ba31a94','內閣春帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','青逵布序和風扇，紫禁延禧瑞日長。',32,'全唐诗/poet.song.8000.json','["青逵布序和風扇，紫禁延禧瑞日長。", "佇看親蠶臨繭館，永觀彤管播聲芳。"]'),
('46f6f1aa-8fa0-48f8-b726-7fdc3729a439','內閣春帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','椒花獻歲良時啟，彩鷰迎春淑氣來。',32,'全唐诗/poet.song.8000.json','["椒花獻歲良時啟，彩鷰迎春淑氣來。", "仰奉帝慈方秀出，吹簫看築鳳凰臺。"]'),
('4967d5dd-5dda-487d-abd3-c1f53c346eeb','內閣春帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','東郊候氣迴青輅，北闕迎祥闢紫闈。',32,'全唐诗/poet.song.8000.json','["東郊候氣迴青輅，北闕迎祥闢紫闈。", "大庇羣生承寶緒，永敷春澤播鴻徽。"]'),
('633398c2-1130-44ad-abe7-5d1b414a7400','內閣春帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','銀箭初傳暖律延，微和漸扇物華姸。',32,'全唐诗/poet.song.8000.json','["銀箭初傳暖律延，微和漸扇物華姸。", "彩幡紅鏤宜春字，永奉宸慈億萬年。"]'),
('aefd2db0-8674-477e-b429-00c776e4a9ed','內閣春帖子  其五','夏竦','宋','宋诗','song-poetry','','[]','青陽乍整蒼龍駕，紫宙初凝白鶴雲。',32,'全唐诗/poet.song.8000.json','["青陽乍整蒼龍駕，紫宙初凝白鶴雲。", "曼壽無疆真蔭遠，九重嘉氣日氤氲。"]'),
('a9daca49-2e4f-45b2-8615-7460ff4870ec','內閣春帖子  其六','夏竦','宋','宋诗','song-poetry','','[]','緹室葭灰飛候管，彤闈天路起和風。',32,'全唐诗/poet.song.8000.json','["緹室葭灰飛候管，彤闈天路起和風。", "六宫永被河洲化，穆穆芳猷佐聖功。"]'),
('2abcdc58-1024-4ecb-a4a6-8e16dce10602','內閣春帖子  其七','夏竦','宋','宋诗','song-poetry','','[]','三星分曜輝宸漢，九禁迎春啟令辰。',32,'全唐诗/poet.song.8000.json','["三星分曜輝宸漢，九禁迎春啟令辰。", "仰奉椒闈宣內治，湛恩鴻慶永如春。"]'),
('137f2b7f-20ba-4101-9022-9ff00f23bfd2','壽春郡王閣春帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','穆穆韶華生紫禁，遲遲春箭下青宫。',32,'全唐诗/poet.song.8000.json','["穆穆韶華生紫禁，遲遲春箭下青宫。", "良辰已慶加元服，大國爰聞拜景風。"]'),
('cdda3f99-34ef-4d20-aac1-6a742719014f','壽春郡王閣春帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','緹室葭灰飛律管，鳳闈春色動年芳。',32,'全唐诗/poet.song.8000.json','["緹室葭灰飛律管，鳳闈春色動年芳。", "仙源積慶誠無際，永戴宸慈襲美祥。"]'),
('b7a81f75-a034-4a4c-9742-8690be195f03','壽春郡王閣春帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','日上苑梅凝素艷，雪晴宫柳弄青條。',32,'全唐诗/poet.song.8000.json','["日上苑梅凝素艷，雪晴宫柳弄青條。", "已觀壽土封東國，即看懷金奉內朝。"]'),
('802d91b5-3e67-4ef2-ba8c-f95e0d4d7ff5','壽春郡王閣春帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','異表英奇非世出，惠心通敏盡生知。',32,'全唐诗/poet.song.8000.json','["異表英奇非世出，惠心通敏盡生知。", "更當淑景承慈煦，永奉嘉祥茂本枝。"]'),
('3c3f0c73-a45f-457b-a5c2-3eff5d913569','御閣端午帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','續命彩絲登繭館，長生金籙獻琳宫。',32,'全唐诗/poet.song.8000.json','["續命彩絲登繭館，長生金籙獻琳宫。", "百靈拱衛天居峻，萬國歡康帝業隆。"]'),
('b293ad2f-d499-4183-b7af-d3cbc73eb59e','御閣端午帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','金縷開辰分五色，長絲獻壽祝千年。',32,'全唐诗/poet.song.8000.json','["金縷開辰分五色，長絲獻壽祝千年。", "垂衣日月承嘉慶，真祖飇游正在天。"]'),
('3e8fba27-48c7-4f4a-b22d-ccadbca8e2f3','御閣端午帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','僊園采藥回彫輦，禁殿迎祥啟鳳闈。',32,'全唐诗/poet.song.8000.json','["僊園采藥回彫輦，禁殿迎祥啟鳳闈。", "四海樂康民富壽，穆清無事永垂衣。"]'),
('1c239284-cffa-40af-a17f-3a98fe20f5bc','御閣端午帖子  其四','夏竦','宋','宋诗','song-poetry','','[]','彩絲祝壽芳辰啟，紫禁凝旒瑞日長。',32,'全唐诗/poet.song.8000.json','["彩絲祝壽芳辰啟，紫禁凝旒瑞日長。", "億兆歸仁天祐德，綿綿真蔭永無疆。"]'),
('f9dbd8be-c408-4ed2-9585-ec688d4c652c','御閣端午帖子  其五','夏竦','宋','宋诗','song-poetry','','[]','絳臺丹筆書金籙，紫殿瑤箱獻巧衣。',32,'全唐诗/poet.song.8000.json','["絳臺丹筆書金籙，紫殿瑤箱獻巧衣。", "億載延鴻資睿算，百祥重沓擁宸闈。"]'),
('4cb48e21-0075-4ada-8d0e-57af331f1082','御閣端午帖子  其六','夏竦','宋','宋诗','song-poetry','','[]','太官角黍迎嘉節，上聖齋居襲美祥。',32,'全唐诗/poet.song.8000.json','["太官角黍迎嘉節，上聖齋居襲美祥。", "金闕鑒觀真緒遠，永延鴻慶庇多方。"]'),
('1a8f0889-9f21-45f6-ad82-e7891381d977','御閣端午帖子  其七','夏竦','宋','宋诗','song-poetry','','[]','尚方綬带迎嘉節，中禁彤闈納美祥。',32,'全唐诗/poet.song.8000.json','["尚方綬带迎嘉節，中禁彤闈納美祥。", "疇德珍符方瑞聖，後天宸壽永無疆。"]'),
('8233d3b2-2172-4cc4-bf41-f4828415750e','御閣端午帖子  其八','夏竦','宋','宋诗','song-poetry','','[]','太官角黍初晨啟，法坐垂衣介福隆。',32,'全唐诗/poet.song.8000.json','["太官角黍初晨啟，法坐垂衣介福隆。", "億載昌期方赫奕，九天真蔭永延鴻。"]'),
('43f49d67-185c-459c-8c60-f32f5bc69f80','御閣端午帖子  其九','夏竦','宋','宋诗','song-poetry','','[]','賜羮佳事傳青簡，續壽長絲獻紫宸。',32,'全唐诗/poet.song.8000.json','["賜羮佳事傳青簡，續壽長絲獻紫宸。", "帝祉薦彰符盛德，聖心勤恤爲生民。"]'),
('6d71cddd-448d-4c1e-acf7-ff31c64a34b7','御閣端午帖子  其一○','夏竦','宋','宋诗','song-poetry','','[]','五色綵絲初獻壽，九重嘉氣頌長生。',32,'全唐诗/poet.song.8000.json','["五色綵絲初獻壽，九重嘉氣頌長生。", "庇民精意方虔鞏，垂拱仁風更穆清。"]'),
('8b648566-d40b-4bcc-b103-c473cb193f97','御閣端午帖子  其一一','夏竦','宋','宋诗','song-poetry','','[]','浴蘭襲祉良辰啟，握紀無爲聖道尊。',32,'全唐诗/poet.song.8000.json','["浴蘭襲祉良辰啟，握紀無爲聖道尊。", "舄奕嘉祥充九禁，冲融和氣徧干門。"]'),
('11e4f85a-fdba-4fee-8a2d-0ef70d208857','御閣端午帖子  其一二','夏竦','宋','宋诗','song-poetry','','[]','八龍焜燿長生籙，五采葳蕤續命絲。',32,'全唐诗/poet.song.8000.json','["八龍焜燿長生籙，五采葳蕤續命絲。", "億載延長資睿算，萬區康樂遇昌期。"]'),
('18ef0d82-1ca3-4d47-9519-3a0f635c1dff','皇后閣端午帖子  其一','夏竦','宋','宋诗','song-poetry','','[]','迎祥競獻雙條達，續壽初纒五色絲。',32,'全唐诗/poet.song.8000.json','["迎祥競獻雙條達，續壽初纒五色絲。", "共仰齋莊隆內訓，永觀蕃衍茂仙枝。"]'),
('ffdc9f3d-b8ef-412e-b33c-3161f4603813','皇后閣端午帖子  其二','夏竦','宋','宋诗','song-poetry','','[]','璧沼水嬉飛隼渡，瑤箱命縷彩絲新。',32,'全唐诗/poet.song.8000.json','["璧沼水嬉飛隼渡，瑤箱命縷彩絲新。", "親蠶禮畢無餘事，夙佩珩璜奉紫宸。"]'),
('0c2b85f4-c422-434b-b2bb-227c09ba7558','皇后閣端午帖子  其三','夏竦','宋','宋诗','song-poetry','','[]','千門朱索迎嘉祉，九禁椒塗納美祥。',32,'全唐诗/poet.song.8000.json','["千門朱索迎嘉祉，九禁椒塗納美祥。", "虔奉黼帷承渥惠，慶隆禖石美祥新。"]');
